-- Poems batch 210
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('68a875c8-24d1-4032-bb69-df38714be992','和趙使君喜雨','陽枋','宋','宋诗','song-poetry','','[]','舉頭日日雲如血，遍走羣祠腰漫折。',128,'全唐诗/poet.song.197000.json','["舉頭日日雲如血，遍走羣祠腰漫折。", "惻隠存君一念間，造物於人豈終絕。", "天眼豁隨公道開，宵人於此何有哉。", "煩歊陡逐苛條去，甘澤端從德意來。", "公心與天同一宇，那是經生分別處。", "佳句催成頭上雲，仁言散作空中雨。", "開軒對雨卜香秔，鈴閣無風還自凉。", "新詩寫出天人際，賡歌細與問蒼蒼。"]'),
('3b837129-be4a-4898-bd01-985c30730f30','黄池舟中和全父弟韻','陽枋','宋','宋诗','song-poetry','','[]','江上平隄隄上路，隻輪來往舟沿泝。',96,'全唐诗/poet.song.197000.json','["江上平隄隄上路，隻輪來往舟沿泝。", "林疎風葉墜輕黄，征雁聲中秋暗度。", "來踏東風歸歲暮，佳山好水無重數。", "揩摩老眼待冬深，更看霜林排雪樹。", "岸木稠邊屋作鄰，港魚多處鷗成聚。", "竿蓑擬欲箇中留，却恨冬風催我去。"]'),
('8c00c656-1340-4445-b81d-5061047aa2b8','和存子姪上風嘆','陽枋','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','家在岷峨峰六六，文章李杜追芳躅。',64,'全唐诗/poet.song.197000.json','["家在岷峨峰六六，文章李杜追芳躅。", "有詩吟破雪飛花，無酒斟來體生粟。", "觀光上國肩共摩，舟下長江尾相觸。", "行行得意買湖天，携手風凉曾點浴。"]'),
('f77a8b2f-7ca1-46a6-b571-0f5ca4ae00c0','雲山避地','陽枋','宋','宋诗','song-poetry','','[]','依山茅屋兩三間，與世相遺盡日閒。',160,'全唐诗/poet.song.197000.json','["依山茅屋兩三間，與世相遺盡日閒。", "背擁藍屏半天碧，面對參差橫架山。", "徑草蒙頭雲覆屋，泉甘土肥似盤谷。", "劍峰林密杳無邊，綿峽潭深幽莫燭。", "有鮮可食美可茹，康樂和平長自飫。", "有時拂石弄泉聲，有時策杖登山去。", "山中日沈山月出，巖暝林晦總佳適。", "平石如臺倚山隈，準擬結茅閒讀易。", "尚論古人得我心，商傅周姜漢子陵。", "好共栽桃艷長春，却恐漁父來相尋。"]'),
('e40fd417-94ba-45cf-b599-f695d593cc78','壽程彥彪簽判乃翁','陽枋','宋','宋诗','song-poetry','','[]','黄鐘宮動夏秋分，夜來一雨如傾盆。',212,'全唐诗/poet.song.197000.json','["黄鐘宮動夏秋分，夜來一雨如傾盆。", "炎雲洗盡金天渾，老人星見程家門。", "老人降生敘南村，昔日聞名今共論。", "耆英侍坐聆嘉言，八窗玲瓏笑語溫。", "千載一朝逢漆園，夾拶小澗開窗軒。", "雲雞月犬聞朝昏，衰情晚態常相存。", "翠竹紫鳳高騰騫，梧枝裊娜棲雛鵷。", "琴彈碧玉箜篌蕃，爐養白砂賢弟昆。", "胎仙三疊舞翩翻，玉液九轉朝崑崙。", "沆瀣爲飲霞爲餐，菊酒酌客香盈樽。", "欲隨枕石漱潺湲，只恐鼎養歸天閽。", "九老圖中姓字尊，月倦指點詩輕捫。", "莫學劉阮窮溪源，儘教親見眼前七世森仍孫。"]'),
('63d1ab15-f193-4932-a853-b62e6cd55825','回程宣義賀生日詩','陽枋','宋','宋诗','song-poetry','','[]','錦章卷遺書八分，獨繭抽緒浮金盆。',212,'全唐诗/poet.song.197000.json','["錦章卷遺書八分，獨繭抽緒浮金盆。", "太羹玄酒淳風渾，秋草得暖生華門。", "隔溪來往如幽村，百年時敘從君論。", "直誼高情無綺言，寒陬冷宇回春溫。", "鄭公耆英思陶園，顧我芒屐羞高軒。", "感君昭昭排昏昏，心期好語饒溫存。", "惠然長風來孤騫，九苞後乘彤庭鵷。", "肯令穉榻依陳蕃，相對怡愉諧弟昆。", "跋紅坐久金爐翻，天雞不覺鳴崑崙。", "清蕭滿腹烟霞餐，歸來捧枵哦空樽。", "新題壯筆流飛湲，欲持此詩排帝閽。", "祈我友君同壽尊，座間談笑舌莫捫。", "伊洛派脈探其源，與世無窮振振繩繩之子孫。"]'),
('baf09ed0-b0eb-4629-95a5-0b6833e61bae','送文大監赴召','陽枋','宋','宋诗','song-poetry','','[]','雲門大卷聲鏗鏘，不比寒谷號蛩螿。',232,'全唐诗/poet.song.197000.json','["雲門大卷聲鏗鏘，不比寒谷號蛩螿。", "長笑歸來書滿床，著眼不用垂簪裳。", "夤緣仕版亦逢場，一鼎熱處元清凉。", "年來道心包乾剛，鑑凈水止無迎將。", "付物大公齊混茫，玲瓏窗牖開八荒。", "霽月海東懸秋霜，照破蒙昧橫津梁。", "不才賦資如點狂，柱倚寶瑟心陶唐。", "冰輪玉井情徜徉，祥雲麗日希餘光。", "布帛菽粟味尤長，尋繹此樂徒激昂。", "頎然美人天西方，許我立雪來其旁。", "欲坐春風吸餘芳，聽說夜話攄中膓。", "又聞催歸侍玉皇，挈提北斗斟天漿。", "凈洗世表塵昏黄，席此廣宇歸康莊。", "起舞掉頭帆飛揚，誓鳴急槳隨烏檣，參同希傳魏伯陽。"]'),
('8780d7d8-0c3b-4ef0-baca-7f54ce7f77d4','送雲山文先生吏部赴召','陽枋','宋','宋诗','song-poetry','','[]','雲山至寶非和璧，光耀燭天難毖密。',384,'全唐诗/poet.song.197000.json','["雲山至寶非和璧，光耀燭天難毖密。", "一朝天子闡坤珍，此寶肯爲蜀人出。", "寶生蜀東六十年，蜀勢關吳妙陳述。", "蜀爲頭目吳腹心，頭目清明腹心佚。", "蜀爲藩籬吳奧堂，藩籬堅固奧堂實。", "蜀若顛危憂在吳，夔峽豈能遏迸溢。", "自從蜀口棄三關，托裏金城更崷崒。", "戎馬衝奔二十年，此城處處皆屹立。", "虔劉俘掠技已窮，羣聚寶峰頻出入。", "抵礙堅城不得戰，轉攻雲詔謀虛襲。", "欲踐辰沅闖廣南，後顧有蜀還恧尼。", "留屯漢中綴祕師，計俟萬全無一失。", "我向嘉渝增重屯，大理垂軍須縮絰。", "夷陵近聞列守戍，似謂蜀險爲難必。", "或言東晉不用蜀，是時南北只守一。", "如今敵人斡腹來，不思保蜀更何術。", "莫虞海道要先防，雲濤湧沸蛟黿慄。", "臣寶一戰振天威，至今敵膽猶惕怵。", "莫憂淮堧近建康，萬柁舟師人素習。", "踏車橫江臣世忠，北人言之魂凜凓。", "荆南雖云瞰大江，曹瞞百萬幾禽執。", "趙公堰匱孟公湖，有如弱水蓬萊岌。", "當今重勢在蜀川，蜀事艱難今轉急。", "井絡丘墟烟火空，荆棘漫彌虎窟室。"]'),
('cfab253c-f5aa-407c-aaab-e9e8b8aedea7','和存子姪長吟酆都韻','陽枋','宋','宋诗','song-poetry','','[]','江肥石沒浪壯激，水瘦石露灘無聲。',96,'全唐诗/poet.song.197000.json','["江肥石沒浪壯激，水瘦石露灘無聲。", "叢深鹿來平都重，林槁鹿去平都輕。", "消息盛衰有如此，是理見處須分明。", "孟叟晚年盡心作，孔聖垂老春秋成。", "當知血氣命於志，不同萬物殊枯榮。", "好向先生問心極，萬里浮舟入帝城。"]'),
('910e46e9-1e66-4418-8ce2-305ea1f35cab','長風峽避風和全父弟韻','陽枋','宋','宋诗','song-poetry','','[]','慘舒異氣無異機，交朋論心不論迹。',128,'全唐诗/poet.song.197000.json','["慘舒異氣無異機，交朋論心不論迹。", "詩書一酌飲芝蘭，風雨連宵聽蕭瑟。", "旋調詩律破愁城，閒弄局棊消短日。", "酒來思逸吟轉高，笑罷江橫顔自懌。", "坐久那知風袂寒，眠酣未問霜衾濕。", "四時翻轉無停機，一理渾融何所適。", "佳山好水看已多，江鄉誰作蓴鱸憶。", "天人之際妙復微，莫事空言須踐實。"]'),
('24caaf14-6e7c-4eed-9cd4-8b9de915fb99','讀易書懷','陽枋','宋','宋诗','song-poetry','','[]','家家住坐長安道，日問長安何草草。',64,'全唐诗/poet.song.197000.json','["家家住坐長安道，日問長安何草草。", "春到驪山渭水深，拂石臨流苦不早。", "萬戶千門鎮日開，無邊風月隨人好。", "滿城花柳斷鶑腸，芳菲易歇天難老。"]'),
('d90051e3-171c-4c4f-a6ac-434ca5ef888b','賦趙守接竹引巖泉','陽枋','宋','宋诗','song-poetry','','[]','冰絲寶瑟無膠柱，事省庭空引泉注。',256,'全唐诗/poet.song.197000.json','["冰絲寶瑟無膠柱，事省庭空引泉注。", "爲愛心隨水色清，從教竹傍山腰去。", "循除㶁㶁聽潺湲，華襟湛徹生靈根。", "縱使波深池自滿，尚嫌鯉躍圓荷翻。", "破除崖岸非落泊，虛室融融自出白。", "通塞默知箇裏心，媸妍各付水中色。", "自來道體如泉流，晝夜不舍無春秋。", "希音解入幽人聽，世間俗耳徒箜篌。", "沈沈夜永寒聲出，宮商寡和鳴琮璧。", "山高月冷天地空，寸地希夷無畛域。", "架竹主人還記年，山下出泉常不乾。", "凡物有本自無息，對泉玩理高懷寬。", "先生仁念泉初達，蒼生鎮爾銅烏渴。", "太空一滴著人清，生意汪洋湖海闊。", "野人不作名利貪，飲水曲肱心自甘。", "時乞一甌空煮茗，快讀羲經井九三。"]'),
('f36b3951-f7a9-4b2f-b7f6-1c599782dd63','少年看花行寄示誼儒姪','陽枋','宋','宋诗','song-poetry','','[]','少年看花日千遭，黄金買笑俠氣豪。',170,'全唐诗/poet.song.197000.json','["少年看花日千遭，黄金買笑俠氣豪。", "醆斟西凉綠蒲萄，燕歌趙舞紛綺羅。", "插花上馬玉顔酡，鞭馬如風花底過。", "九天閶闔手可摩，揚眉不怕金吾訶。", "杜鵑一聲啼山阿，門掩綠苔愁秦娥。", "春樹紅顔能幾何，萬里封侯成蹉跎。", "河南布衣正婆娑，却笑因風想玉珂。", "未肯巖前捫翠蘿，商丘不唱採芝歌。", "獨深於易如鄒軻，紫陽真人聲相和。", "蓮蕩歸來揚其波，我傍梅花讀遺書，不知紛紛坐久落花多。"]'),
('c4d650dc-b2c0-4c6f-8f19-917c120a1f68','丙寅八月旦晨興尚早坐而假寐夢與客誦詩云藜羹藿啜蔬園芳黄花晚節凌秋霜因增成十韻寄壬兒','陽枋','宋','宋诗','song-poetry','','[]','僂指寅年已半强，煩歊能幾還凄凉。',80,'全唐诗/poet.song.197000.json','["僂指寅年已半强，煩歊能幾還凄凉。", "風葉有聲宵鳴廊，試擁衾紬眠藤床。", "曉鉦錚錚樓點長，清夢了了哦詩章。", "藜羹藿啜蔬園芳，黄花晚節凌秋霜。", "起挑木火然心香，晴雲收雨烟黄江。"]'),
('556f707e-b2d7-4a27-b579-c80022078370','謝涪陵劉君舉使君見委北巖堂長詩','陽枋','宋','宋诗','song-poetry','','[]','雪片冬深玩易編，正公和氣理尤渾。',194,'全唐诗/poet.song.197000.json','["雪片冬深玩易編，正公和氣理尤渾。", "八分寫就龍蛇走，巖藤澗樹常蜒蜿。", "蓮蕩飄裾紫陽學，歸來拂拭莓苔痕。", "巖前世事幾興廢，道無今古終長存。", "新來五馬栽桃李，生平伊洛期窮源。", "下車一笑撫江閣，片心飛度蒼崖根。", "生香動蕩滿幽谷，秋叢濯雨抽蘭蓀。", "露華滴晴舞夜鶴，雲葉卷霽吟朝猿。", "衰翁白首野人服，不愛市井憐山村。", "太守招來說好語，翠蘿有路猶堪捫。", "聽終不敢謝疲苶，瘦筇强拄巖檐門。", "遺書欲傍梅花讀，祇恐使人昭昭己昏昏。"]'),
('c1c0ac56-1f46-4302-ad66-06a267e06fb7','和夔州李約齋燈宵','陽枋','宋','宋诗','song-poetry','','[]','蠶叢今歲看燈宵，可人只有峽中州。',307,'全唐诗/poet.song.197000.json','["蠶叢今歲看燈宵，可人只有峽中州。", "白帝綸巾隠敵國，勝勢蜀尾連吳頭。", "竹枝歌舞喧城市，春聲泛鷗臈浮蟻。", "府主山村耕稼心，挈客銜盃聊爾爾。", "咿啞蠻唱雜𪔳鼕，老者前導幼者從。", "不貪嬉惰樂遊冶，只記時序還桑農。", "村村蓑笠兒童隊，桑上鷄聲花底吠。", "春歸野燒雪初融，日上高峰寒早退。", "生意著人人莫知，但見綠草生清淒。", "雪戍坐斂荆江北，月華靜照峨眉西。", "此意洪濛不可道，張皇恐被春風惱。", "酒澆象澦石無言，春不生榮冬不槁。", "穿花燕曲弄繁絃，來尋故壘畫堂前。", "呢喃似與遊人語，今宵行樂寧徒然。", "得賢千里只須一，大公方寸無他術。", "厚地不填無底谷，萬流豈漲滄溟溢。", "我談此語費形容，有似樵聲箇箇同。", "野蠶作繭自纏縛，拈弄輕絲大巧中。", "君不見隣女效顰人愛少，萬目睽睽分醜好。"]'),
('a3e8e816-c22a-4939-89ee-46e09c83894a','寶祐三年上巳風雨連日成短歌寄誼儒姪','陽枋','宋','宋诗','song-poetry','','[]','風雨飄摇三月三，綺羅罷遊客停驂。',140,'全唐诗/poet.song.197000.json','["風雨飄摇三月三，綺羅罷遊客停驂。", "滿城春樹烟䰐鬖，朱戶綠窗愁不堪。", "香芹刺泥燕爭銜，杜鵑欲啼情正含。", "舞雩兒童笑鴒䳺，堯舜氣象此中涵。", "鼓瑟高人手可探，淡音非雅亦非南。", "太守風期神與參，我解此意誰爲談，但覺滿懷春酣酣。", "花柳蒙迷不可貪，芳菲易歇隨浮嵐。", "閒閉閣門何所耽，惟見千山萬山秀色郁如藍。"]'),
('eb445544-74b9-4bd0-8ca8-bbdff3083942','壽制置夏節使','陽枋','宋','宋诗','song-poetry','','[]','丙申蚩尤臨蜀口，三十年餘遭踐蹂。',176,'全唐诗/poet.song.197000.json','["丙申蚩尤臨蜀口，三十年餘遭踐蹂。", "當時五十四郡全，兵與民財堪著手。", "鋒旗戊午肆長驅，江北江南分戰守。", "彫瘵僅存六七州，鴻鴈飛鳴狐夜吼。", "先生受任勢凌兢，倉扁視證亦驚走。", "無麫餺飥難支撐，將勇兵强民力阜。", "前賢用蜀當優游，先生端力排紛糾。", "農炊豈暇勸加餐，春風未始一盃酒。", "公心只有天地知，雖處艱關安且久。", "事不辭難功不矜，節度樞垣亦廉取。", "天下都統捧霞觴，先生一人更誰有。"]'),
('ce38beaa-199e-49cc-860b-23296ecb439c','壽李使君宣義父子同日','陽枋','宋','宋诗','song-poetry','','[]','黄梅雨陣歇窗紗，庚夢醒來槐月斜。',246,'全唐诗/poet.song.197000.json','["黄梅雨陣歇窗紗，庚夢醒來槐月斜。", "拜後拜前懽陸續，老君謫仙同一家。", "蟬冠醉倒金貂客，異香飄隨青犢車。", "旋呼五馬博一笑，酒酣逸氣凌蒼霞。", "培椿植桂弄梧碧，生香不斷樹交花。", "清凈何須餐沆瀣，抱素肯養瓊田鴉。", "伯陽參同竊造化，高風海客空乘槎。", "武陵溪深自流水，天台雲渺維胡麻。", "神遊八極亦汗漫，大鵬希有爭雄誇。", "藤床經卷得真諦，五鼎三釜輕豪奢。", "靜桃宿火熏百和，閒引山泉烹粟芽。", "自行自坐脚力輕，瘦筇擲棄龍槎枒。", "從來參苓不到口，雙瞳鏡碧顔春華。", "我向關頭伴尹喜，共乞刀圭期修遐。", "阿誰疑年問甲子，純乾一氣健而無息孰測其津涯。"]'),
('cc4e93a2-ba8d-4ea3-82d2-733459fad52a','和王季行制幹昌溪即事  其一','陽枋','宋','宋诗','song-poetry','','[]','異境破清愁，狂吟日點頭。',48,'全唐诗/poet.song.197000.json','["異境破清愁，狂吟日點頭。", "前峰方極目，遠嶺又迎眸。", "石亂屢支舫，灘高常負舟。", "心亨行有尚，習坎自安流。"]'),
('0f04ae17-a142-4271-954d-ded661dcec9d','和王季行制幹昌溪即事  其二','陽枋','宋','宋诗','song-poetry','','[]','鹽米溪中艇，桑麻雲外村。',48,'全唐诗/poet.song.197000.json','["鹽米溪中艇，桑麻雲外村。", "巖重稀鳥道，石勁少篙痕。", "赤甲此微峽，溫泉茲小軒。", "絕憐鷄唱罷，近午日方暾。"]'),
('acd77cfe-3fcc-460e-b3c9-c525a89b04d3','過下沱','陽枋','宋','宋诗','song-poetry','','[]','迤衍魚鹽地，清明花柳天。',48,'全唐诗/poet.song.197000.json','["迤衍魚鹽地，清明花柳天。", "江平拖霧縠，山遠带霜鉛。", "景好輒作畫，心閒連得篇。", "汎舟隨暮靄，明月冷浮川。"]'),
('3a78dcd8-91c3-44f3-a039-d722577bdae9','瞿唐峽','陽枋','宋','宋诗','song-poetry','','[]','壁絕晝昏明，猿高髣髴音。',48,'全唐诗/poet.song.197000.json','["壁絕晝昏明，猿高髣髴音。", "不關天宇窄，自是峽流深。", "既曉遲朝日，未西還夕陰。", "扁舟平涉險，憑取有孚心。"]'),
('45af1057-584d-401b-a0d2-7565d63bec07','和全父弟立秋喜雨','陽枋','宋','宋诗','song-poetry','','[]','造化仁民意，瀟瀟夜雨聲。',48,'全唐诗/poet.song.197000.json','["造化仁民意，瀟瀟夜雨聲。", "焦原欣得潤，枯黍喜更生。", "染出林陰密，濯餘天氣清。", "秋河從此挽，盡洗北來兵。"]'),
('b42c7902-b8f9-48bd-8ab7-47a85efb7d4d','茅屋','陽枋','宋','宋诗','song-poetry','','[]','情契居連屋，炊齋霤合烟。',48,'全唐诗/poet.song.197000.json','["情契居連屋，炊齋霤合烟。", "放懷行共出，得語坐相傳。", "竹戶雲深入，蘆窗月半穿。", "桃源今得趣，堪賦擬前賢。"]'),
('9ac133f5-ae4a-4081-9969-8f078bf56cff','和黄循齋送景正輔戶曹之夔三首  其一','陽枋','宋','宋诗','song-poetry','','[]','要路倦登臨，淵明徑好尋。',48,'全唐诗/poet.song.197000.json','["要路倦登臨，淵明徑好尋。", "卷收名利幟，揭示聖賢心。", "月使千家滿，霜從兩鬢侵。", "逃空三峽客，屬耳聽蛩音。"]'),
('2a81bfa9-22fe-4931-93a0-d690033dbedc','和黄循齋送景正輔戶曹之夔三首  其二','陽枋','宋','宋诗','song-poetry','','[]','自脫樊籠役，潛心克己私。',48,'全唐诗/poet.song.197000.json','["自脫樊籠役，潛心克己私。", "是求從此日，非莫問前時。", "郡改山元在，江流石不移。", "人心日瀾倒，先覺仰扶持。"]'),
('e8d0f576-1f8c-48cc-a807-76c1648bfad1','和黄循齋送景正輔戶曹之夔三首  其三','陽枋','宋','宋诗','song-poetry','','[]','淺見論成敗，先幾燭是非。',48,'全唐诗/poet.song.197000.json','["淺見論成敗，先幾燭是非。", "端倪還眇眇，勳績自巍巍。", "學僻門常掩，詩枯毫懶揮。", "何時住巖下，質問此心微。"]'),
('f29dde6f-85cf-4658-8817-67375a9eb8c8','輓黄循齋  其一','陽枋','宋','宋诗','song-poetry','','[]','桂賸爐峰月，香飄字水春。',48,'全唐诗/poet.song.197000.json','["桂賸爐峰月，香飄字水春。", "姓名天下客，抱負洛中人。", "膴仕方三紀，徂年未六旬。", "循齋餘售用，何必歎窮民。"]'),
('8741fcfd-c9bc-422d-b571-6927210de999','輓黄循齋  其二','陽枋','宋','宋诗','song-poetry','','[]','憶昔論文友，如今舐鼎仙。',48,'全唐诗/poet.song.197000.json','["憶昔論文友，如今舐鼎仙。", "周經談正印，易學話真傳。", "一樂堂中語，三生石上緣。", "蓮峰望崑嶽，惆悵白雲連。"]'),
('de1c7527-626b-4007-9e21-2771bb1ea709','挽故人  其一','陽枋','宋','宋诗','song-poetry','','[]','公生百載下，學契五峰心。',48,'全唐诗/poet.song.197000.json','["公生百載下，學契五峰心。", "崇鼎屹重器，洪鐘希太音。", "詞源擅翻海，句律善舂金。", "材古誰人識，清歌和慘吟。"]'),
('65cea7a5-7eac-4845-aeed-333c0174242c','挽故人  其二','陽枋','宋','宋诗','song-poetry','','[]','卓世輕財易，懸知種德難。',48,'全唐诗/poet.song.197000.json','["卓世輕財易，懸知種德難。", "有貧皆粟帛，無骼不衾棺。", "紅樹悲春早，孤松忍歲寒。", "輕颸生宰木，多少鼻成酸。"]'),
('ee0c5604-ce9f-4825-8601-c5aa84cb72fe','挽鄭廣安','陽枋','宋','宋诗','song-poetry','','[]','壯節從丁卯，奇功歲轉新。',48,'全唐诗/poet.song.197000.json','["壯節從丁卯，奇功歲轉新。", "有征皆鼓勇，無戰不鏖塵。", "棠國香凝月，榆關夢熟春。", "吁嗟河北地，今日尚終臣。"]'),
('74b68d73-1e55-46e5-9f0b-169b86d65714','挽武龍蹇巡檢  其一','陽枋','宋','宋诗','song-poetry','','[]','仁者壽宜得，王臣忠可嘉。',48,'全唐诗/poet.song.197000.json','["仁者壽宜得，王臣忠可嘉。", "功名雖有約，雲月自爲家。", "義粟饑中糶，慈梁雨後斜。", "百年回首處，溪冷欲梅花。"]'),
('92a2cadf-57b7-4a82-a181-5d1b7568b812','挽武龍蹇巡檢  其二','陽枋','宋','宋诗','song-poetry','','[]','叩戶憶曾識，升堂期再尋。',48,'全唐诗/poet.song.197000.json','["叩戶憶曾識，升堂期再尋。", "仙遊誠絕往，俗慮苦盈襟。", "菡萏晚猶好，荼䕷霜不侵。", "思君望阡隴，遠樹白雲深。"]'),
('b67acc43-302f-428a-a605-3335a3ce4daf','挽伏德華主簿  其一','陽枋','宋','宋诗','song-poetry','','[]','黌堂深惜昔，六典共尋源。',48,'全唐诗/poet.song.197000.json','["黌堂深惜昔，六典共尋源。", "合遂齊飛鶚，嘉逾競化鵾。", "紅顔君早去，白髮我空存。", "方寸千年事，悽然誰與論。"]'),
('a65e6c2b-12ad-4b58-b77b-6ff09333288e','挽伏德華主簿  其二','陽枋','宋','宋诗','song-poetry','','[]','豁達千人傑，巍峨七尺軀。',48,'全唐诗/poet.song.197000.json','["豁達千人傑，巍峨七尺軀。", "天邊期闊武，意外失華途。", "墮淚一人足，傷心二女孤。", "西溪橋畔塚，多少爲嗟呼。"]'),
('897e78b6-a83f-4a83-988c-5a7237f42069','和前人韻賦昌溪洞口','陽枋','宋','宋诗','song-poetry','','[]','洞口天容黯，靈宮暫潔齋。',144,'全唐诗/poet.song.197000.json','["洞口天容黯，靈宮暫潔齋。", "中宵輕霢霂，向晚捲雲霾。", "巖削蒼璆璧，峰攢碧玉釵。", "水花紛迸峽，石乳溜垂崖。", "噴浪遲歸舫，穿濤急去𥱼。", "布飛千丈直，屏立半空排。", "木任巖藤束，花從澗草埋。", "高猿枝裊裊，幽鳥韻喈喈。", "亭午烟光冷，深春風色飁。", "便疑塵世隔，直與洞仙偕。", "意得詩偏好，情閒樂可涯。", "寄言軒冕客，名利莫裝懷。"]'),
('624c41ad-4ac2-490a-9f88-c40cb018ff20','椶花','陽枋','宋','宋诗','song-poetry','','[]','滿株擐甲詫椶櫚，葉展蒲葵冬不枯。',64,'全唐诗/poet.song.197000.json','["滿株擐甲詫椶櫚，葉展蒲葵冬不枯。", "鬼髮擘開纖玉掌，蚌胎剖破細瓊珠。", "熟煨爐火香于笋，白飣盤銀美似酥。", "珍膳莫充禪客供，恐猜魚子放江湖。"]'),
('b83f0a47-2823-4d36-85df-da9a549983fa','別宇文丈','陽枋','宋','宋诗','song-poetry','','[]','滿耳聲稱驀浣沙，萍根雲葉際天涯。',64,'全唐诗/poet.song.197000.json','["滿耳聲稱驀浣沙，萍根雲葉際天涯。", "襟扃噴撲芝蘭氣，韻味清修詩禮家。", "賸把香編消歲月，點無浮葉靚春華。", "西歸人問簪朋得，將作東南第一誇。"]'),
('88075693-cc3c-48d7-9104-d541671e95fd','壽韓司理','陽枋','宋','宋诗','song-poetry','','[]','不因春酒駐紅顔，都是心清事弗關。',64,'全唐诗/poet.song.197000.json','["不因春酒駐紅顔，都是心清事弗關。", "草爲囹空隨意綠，花緣客少笑人閒。", "幽情倚棹暫隨水，爽氣拄頤常看山。", "共指武陵槃澗地，桃花深處屋三間。"]'),
('54f05b73-6d84-476f-9e8e-bb8031f5c06d','壽紹慶金守','陽枋','宋','宋诗','song-poetry','','[]','神光高射斗牛墟，知是龍泉瑞氣舒。',64,'全唐诗/poet.song.197000.json','["神光高射斗牛墟，知是龍泉瑞氣舒。", "彩映北堂霜後檜，輝連東館月中書。", "江流麗水描來似，峽束棠溪畫得如。", "爲報鯨鯢休陸走，劍芒元是發硎初。"]'),
('d5cb1f2f-3d14-441a-8135-7fe4921eb966','庚子叨第贄合州甘守  其一','陽枋','宋','宋诗','song-poetry','','[]','吳門扞蔽重夔渝，兩地藩籬屬釣魚。',64,'全唐诗/poet.song.197000.json','["吳門扞蔽重夔渝，兩地藩籬屬釣魚。", "自昔無城當蜀屏，從今有柱壯坤輿。", "軍心鐵石高深裏，敵膽灰塵築鑿餘。", "看偃天戈閒夜月，朗聲讀破磨崖書。"]'),
('2643a7bc-00e4-46ac-b3ce-5c2399f826dd','庚子叨第贄合州甘守  其二','陽枋','宋','宋诗','song-poetry','','[]','欲陳禮樂字三千，起趁東風萬里船。',64,'全唐诗/poet.song.197000.json','["欲陳禮樂字三千，起趁東風萬里船。", "戎馬不禁文未喪，石魚間出瑞開先。", "人知制梃摧堅甲，政比黄鐘緩急絃。", "願借風雲乘快便，一聲雷爆九重天。"]'),
('4d1d0b26-f73e-4f1e-9082-b808c6f35538','賀李萬州守夔  其一','陽枋','宋','宋诗','song-poetry','','[]','騎鯨汁漫謫仙臞，一世龍門只漢儒。',64,'全唐诗/poet.song.197000.json','["騎鯨汁漫謫仙臞，一世龍門只漢儒。", "天下文章從古有，人間勳業即今無。", "鶴山往事心存蜀，象澦新功力蔽吳。", "留取道宗遼外策，共爲炎宋鞏皇圖。"]'),
('8f09ea91-55b0-4874-be3f-2bdab70d1c5a','賀李萬州守夔  其二','陽枋','宋','宋诗','song-poetry','','[]','淵淵聖道浩津涯，萬里尋師暮景斜。',64,'全唐诗/poet.song.197000.json','["淵淵聖道浩津涯，萬里尋師暮景斜。", "濫吹叢中情懶散，彈冠鏡裏髮爬髿。", "蒼龜已卜林間屋，青犢還逢關上車。", "未得乞符求換骨，借閒讀易傍梅花。"]'),
('308e5355-150d-49a9-bb9f-65294d31fe80','壽蹇從叔制幹','陽枋','宋','宋诗','song-poetry','','[]','黄鐘大呂播年華，簪盍城南捧九霞。',64,'全唐诗/poet.song.197000.json','["黄鐘大呂播年華，簪盍城南捧九霞。", "共說賢寮心似鏡，何妨幕府事如麻。", "紛紛吏坌空迷目，蹇蹇王臣豈計家。", "共約歲寒松竹友，好携周易傍梅花。"]'),
('481aa609-1b1c-4a42-bd6d-4af042bf2392','壽蹇用叔姻翁總幹','陽枋','宋','宋诗','song-poetry','','[]','明知少府是神仙，金水何須掛彩鞭。',64,'全唐诗/poet.song.197000.json','["明知少府是神仙，金水何須掛彩鞭。", "喜喜歡歡遊兩幕，平平穩穩過三年。", "紅蓮照水香仍舊，緋棗團秋味正圓。", "蘭玉已堪華晚節，更尋小圃菊花天。"]'),
('cba47d2f-7910-4461-85b9-dae0dcd3aef7','壽狄知錄','陽枋','宋','宋诗','song-poetry','','[]','熟讀周官知幾冬，染人袍就彩絲縫。',64,'全唐诗/poet.song.197000.json','["熟讀周官知幾冬，染人袍就彩絲縫。", "生當永日三三夏，數應西岷六六峰。", "囚放盡言公活汝，民期無復鼠穿墉。", "籠中上藥芝苓富，却笑頻看鏡裏容。"]'),
('150b57bc-9107-4906-ac6c-90dae446b20b','賀田都統再帥夔  其一','陽枋','宋','宋诗','song-poetry','','[]','十乘由夔入釣魚，飲江無馬鴈安居。',64,'全唐诗/poet.song.197000.json','["十乘由夔入釣魚，飲江無馬鴈安居。", "瞿唐催要金城壁，即墨爭迎鐵裹車。", "八陣旌旗蛇勢整，九關風月虎符虛。", "白鹽萬丈齊天石，揭日奇功大字書。"]'),
('f2d3efc6-09fe-4386-a278-629109761702','賀田都統再帥夔  其二','陽枋','宋','宋诗','song-poetry','','[]','桃李三生黄口兒，春回桑梓放塤吹。',64,'全唐诗/poet.song.197000.json','["桃李三生黄口兒，春回桑梓放塤吹。", "燕依舊主今還再，兔守空株懶未移。", "暫對少陵堂下瀼，遠懷靖節菊邊籬。", "好風借與一帆飽，歸趁江空水落時。"]'),
('d7a44ea3-d29a-4ca5-aa64-75d762fc4333','謁夔門桂帥  其一','陽枋','宋','宋诗','song-poetry','','[]','閫歌整暇化清夷，笑把宗師正印提。',64,'全唐诗/poet.song.197000.json','["閫歌整暇化清夷，笑把宗師正印提。", "繡腑文章開賸馥，錦江桃李爛成蹊。", "旌摇蜀水春浮峽，柝靜蠻天月滿溪。", "衣衮歸歟近宸極，殊勳嘉歎殿頭西。"]'),
('5164463d-3ae3-49d4-b0d2-fc88a376edd1','謁夔門桂帥  其二','陽枋','宋','宋诗','song-poetry','','[]','志欲商伊學欲顔，尋師夢遶五湖間。',64,'全唐诗/poet.song.197000.json','["志欲商伊學欲顔，尋師夢遶五湖間。", "不違誓至仁三月，親炙寧辭雪萬山。", "流海浪浮蝸戰角，排雲應許豹窺斑。", "還丹知換塵凡骨，趁得先生未出關。"]'),
('f7f55a46-9945-415b-ac39-f7ce5ebdf810','贄鄂帥張仁簡  其一','陽枋','宋','宋诗','song-poetry','','[]','八牖玲瓏義理天，復齋心印妙親傳。',64,'全唐诗/poet.song.197000.json','["八牖玲瓏義理天，復齋心印妙親傳。", "化爐點處金非鐵，吏坌清餘否亦賢。", "吠息蒹蘆湖外月，炊生榆柳竈中烟。", "水浮鄂渚連牛渚，公子行行天上僊。"]'),
('f04281ad-b889-4c4c-a595-d2385b26c361','贄鄂帥張仁簡  其二','陽枋','宋','宋诗','song-poetry','','[]','不爲名韁浪出山，朱門桃李恐闌珊。',64,'全唐诗/poet.song.197000.json','["不爲名韁浪出山，朱門桃李恐闌珊。", "師尋湖海胸懷闊，道滿乾坤耳目寬。", "水驛已終三楚尾，天閽猶向五雲端。", "登樓便欲騎黄鶴，乞與書生換骨丹。"]'),
('06d45a10-ee10-4031-8a2d-22d85f263d52','赴大寧司理贄俞帥  其一','陽枋','宋','宋诗','song-poetry','','[]','見說三關息虎貔，風高白帝卷旌旗。',64,'全唐诗/poet.song.197000.json','["見說三關息虎貔，風高白帝卷旌旗。", "擎天砥柱瞿唐險，保蜀規模陣石奇。", "誓出祁山禽仲達，肯屯漢口學姜維。", "枕戈心事聞鷄起，未必閒眠聽竹枝。"]'),
('a676aed4-ccfb-4b3f-809e-be0290686793','赴大寧司理贄俞帥  其二','陽枋','宋','宋诗','song-poetry','','[]','入手青衫愧壯顔，悠悠底事白雲閒。',64,'全唐诗/poet.song.197000.json','["入手青衫愧壯顔，悠悠底事白雲閒。", "有心文字幾千卷，適意茅茨三兩間。", "可奈紅塵飛白羽，不容黄叟卧青山。", "欲從寧水成仙骨，趁得先生未出關。"]'),
('b3b61430-9d6b-4c53-87f8-1d1ec49f842a','壽紹慶王守謹禮','陽枋','宋','宋诗','song-poetry','','[]','燕寢凝香事自無，祝釐何用飲酴酥。',64,'全唐诗/poet.song.197000.json','["燕寢凝香事自無，祝釐何用飲酴酥。", "袴歌雪外暖傳曲，社酒人間春滿壺。", "客到競誇逢子晉，我來甚喜見夷吾。", "摩圍山下閒摩詰，他日添歸九老圖。"]'),
('f5399855-56cb-4831-b01a-f40419aa4f0d','壽劉節判','陽枋','宋','宋诗','song-poetry','','[]','昨夜天香兩袖中，轉頭人日又桑蓬。',64,'全唐诗/poet.song.197000.json','["昨夜天香兩袖中，轉頭人日又桑蓬。", "雲龍風虎千年遇，聖主賢臣此際同。", "翠竹西來方嫩綠，夭桃栽後未繁紅。", "人間正喜洪鈞轉，莫問天台有路通。"]'),
('d1f6aa01-fe24-4bdd-98ef-de619cd6a208','壽涪州李漢輔使君','陽枋','宋','宋诗','song-poetry','','[]','見得州如斗大輕，閒將五馬繫榕陰。',64,'全唐诗/poet.song.197000.json','["見得州如斗大輕，閒將五馬繫榕陰。", "兩江波上千家月，萬卷堂中一片心。", "尚笑龔黄爲計淺，更尋伊洛問鈎深。", "莫慳仙李盤根實，可與輕紅種作林。"]'),
('42086d16-ca0b-4586-acbf-90beafdac122','乙丑除夕衍少陵韻成七言寄示任兒於珍南','陽枋','宋','宋诗','song-poetry','','[]','邊隅守歲莫思家，有酒盈樽即頌花。',64,'全唐诗/poet.song.197000.json','["邊隅守歲莫思家，有酒盈樽即頌花。", "愛爾和鳴同野鶴，起予返哺學林鴉。", "生香不斷爐烟裊，絳蠟長明跋暈斜。", "時序推遷休問當，何思何慮樂無涯。"]'),
('529dca88-0d32-4dd7-b601-e9be0a544977','丙辰病起示兒','陽枋','宋','宋诗','song-poetry','','[]','採薪背夏見書雲，世我相遺思轉清。',64,'全唐诗/poet.song.197000.json','["採薪背夏見書雲，世我相遺思轉清。", "識箇凝陰消又長，喜些真火熄還生。", "百年好夢黄粱短，一片閒心白鶴輕。", "獨擁寒衾長不寐，聽吹梅角動江城。"]'),
('ad0c4ae4-6364-4598-920a-96d66f269f0c','舟過三遊洞知遂脫兵火矣喜賦','陽枋','宋','宋诗','song-poetry','','[]','萬里扁舟歸自東，干戈滿地路難通。',64,'全唐诗/poet.song.197000.json','["萬里扁舟歸自東，干戈滿地路難通。", "弟兄一榻聊相對，叔姪雙頭未許同。", "峽入三遊千丈險，水連西蜀百憂空。", "家山桃李期堪數，共約花間酌晚風。"]'),
('c397e160-589e-4716-b5fa-9461b3cb051b','泊舟洞庭雲薄天空湖光可愛恨未登岳陽樓耳','陽枋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','昨日蘭橈逐順流，今朝湖口泊歸舟。',64,'全唐诗/poet.song.197000.json','["昨日蘭橈逐順流，今朝湖口泊歸舟。", "千山日暖雪花散，萬里風高雲葉收。", "江影曲通西蜀遠，湖光橫與北溟浮。", "岳陽奇眺嗟猶欠，付與他年穩上樓。"]'),
('05543a3b-3fc8-4909-adab-5afd2edef6f5','壽鄧子西提幹與乃堂相距八日','陽枋','宋','宋诗','song-poetry','','[]','碧梧清夢繞紅萱，袖橘歸來人倚門。',64,'全唐诗/poet.song.197000.json','["碧梧清夢繞紅萱，袖橘歸來人倚門。", "七日喜稱王母壽，經旬還捧謫仙尊。", "松知得算霜中樹，梅報和羹雪外村。", "拄杖金魚消息好，慇懃拜舞勸加飱。"]'),
('4ea3368a-36c3-43db-8284-4f2709566f03','遣季子壽黄循齋二首  其一','陽枋','宋','宋诗','song-poetry','','[]','五峰高處五雲新，黄石先生非避秦。',64,'全唐诗/poet.song.197000.json','["五峰高處五雲新，黄石先生非避秦。", "圯上未容書出袖，巖前元自易無塵。", "烟霞窟冷苦留客，雲霧窗虛亦可人。", "好爲蒼生徹蒸暑，天邊散與一襟春。"]'),
('817b7e7c-3144-4d4e-8183-ebc2b47d7c83','遣季子壽黄循齋二首  其二','陽枋','宋','宋诗','song-poetry','','[]','自得遺書學子房，擬來辟穀並山陽。',64,'全唐诗/poet.song.197000.json','["自得遺書學子房，擬來辟穀並山陽。", "仙鄉不秘眼前道，俗相慚無肘後方。", "經葉再傳新雨露，桃花重發舊門牆。", "呼兒莫怕蓬萊遠，勤爇南豐不盡香。"]'),
('09f233de-9b5e-4ad2-b293-4f21d89d6f81','謁同年許使君德開  其一','陽枋','宋','宋诗','song-poetry','','[]','人人屬目快星凰，倚棹溪頭起漫郎。',64,'全唐诗/poet.song.197000.json','["人人屬目快星凰，倚棹溪頭起漫郎。", "强仕慣聞紆郡紱，綴班希有擅文場。", "賸栽棠蔭兩江綠，重著藍袍再世光。", "人物西清自華選，未應琴鶴久松崗。"]'),
('e4c8720e-9652-4d22-8e61-1e9f66386e26','謁同年許使君德開  其二','陽枋','宋','宋诗','song-poetry','','[]','欲造詩壇奪錦標，幾回躡足愧還休。',64,'全唐诗/poet.song.197000.json','["欲造詩壇奪錦標，幾回躡足愧還休。", "君提妙律都先手，我漫家吟浪出頭。", "濟世自憐無絕力，叩閽剛道有嘉猷。", "先生若動出關興，便爾挑包逐去舟。"]'),
('8bc212f8-69d3-4d89-80fb-643a8bb80d9c','謁九江周元公祠嗣性善度先生韻','陽枋','宋','宋诗','song-poetry','','[]','聖賢隨遇即成都，仰止宗師謁故居。',64,'全唐诗/poet.song.197000.json','["聖賢隨遇即成都，仰止宗師謁故居。", "面揖光風江渚遠，心涵霽月海天舒。", "圖由自得前無畫，道未嘗亡今有書。", "共立斜陽歸去晚，當年與點意何如。"]'),
('6a991dbb-de30-4c84-8172-922a9fb59e7d','挽樂應乃堂','陽枋','宋','宋诗','song-poetry','','[]','高堂憶昨燕春風，雙老怡愉桂棹東。',64,'全唐诗/poet.song.197000.json','["高堂憶昨燕春風，雙老怡愉桂棹東。", "藍袖歸時饒榜綠，橘香懷處少萱紅。", "悲纏忍見舟藏壑，德感還知月在空。", "有子天教優好善，五花不日賁泉宮。"]'),
('d0035dea-43d0-4609-9830-98b2e567eebe','挽南平趙化卿','陽枋','宋','宋诗','song-poetry','','[]','昔遊曾到萬山峰，趙氏樓臺紫翠中。',64,'全唐诗/poet.song.197000.json','["昔遊曾到萬山峰，趙氏樓臺紫翠中。", "六藝近誇三世學，四賢爭顯一家風。", "不堪顧影憐孤鴈，恰喜摩天有阿鴻。", "好是生香元不斷，靈椿雖老桂成叢。"]'),
('d8787920-d299-4d42-8989-0944986a1c9f','挽何深甫','陽枋','宋','宋诗','song-poetry','','[]','羨君底事過時人，一點閒愁不到心。',64,'全唐诗/poet.song.197000.json','["羨君底事過時人，一點閒愁不到心。", "笑語屢陪桃李酒，詩書曾對竹松林。", "已驚別鶴江天遠，何事騎鯨歲月侵。", "五桂聯芳知有日，去尋蕭侶碧雲深。"]'),
('de22cd62-8a92-4935-90d4-524080281c45','挽趙飛卿','陽枋','宋','宋诗','song-poetry','','[]','萬翠亭邊山鬰葱，書聲散出五雲重。',64,'全唐诗/poet.song.197000.json','["萬翠亭邊山鬰葱，書聲散出五雲重。", "紅萱色改宦情薄，綠酒盃深客話濃。", "鴈起秋空從整整，鷗閒野水自溶溶。", "誰人爲作坡仙傳，弟似潁濱文似邕。"]'),
('e63a2f28-7f01-4a7d-b140-1096d8007ca4','壽張方叔表弟','陽枋','宋','宋诗','song-poetry','','[]','聞說書臺百世張，燕山來數竇家郎。',64,'全唐诗/poet.song.197000.json','["聞說書臺百世張，燕山來數竇家郎。", "含容寸念侔焚券，正直生平等發藏。", "丹桂香浮森駟馬，碧梧翠織引雙凰。", "松蘿歲晚陪真喜，染得卿雲爛有光。"]'),
('146e4fc4-4c48-43d9-b03b-f0e8c9c04a70','和楊提刑喜雨  其一','陽枋','宋','宋诗','song-poetry','','[]','螻蟻何能格上穹，况於三伏藴隆中。',64,'全唐诗/poet.song.197000.json','["螻蟻何能格上穹，况於三伏藴隆中。", "瓣香載走神龍廟，法象俱來大梵宮。", "出岫金身能普濟，臨池玉醮可幽通。", "尚憑使者疎寃獄，歌舞豐年與衆同。"]'),
('b66fa6ee-d932-4d29-a361-06bb099152e2','和楊提刑喜雨  其二','陽枋','宋','宋诗','song-poetry','','[]','詔許歸耕荷聖王，又扶衰病過南方。',64,'全唐诗/poet.song.197000.json','["詔許歸耕荷聖王，又扶衰病過南方。", "幸親博洽前無輩，每歎平反後必昌。", "請雨頼公誠獨至，回天愧我德多凉。", "作詩志喜親銜袖，玩把渾如七寶裝。"]'),
('82452fca-d82a-4857-bae8-2742aaa60667','和蘇提舉喜雨  其一','陽枋','宋','宋诗','song-poetry','','[]','瞻仰雖勤隔壤穹，此誠何自達天中。',64,'全唐诗/poet.song.197000.json','["瞻仰雖勤隔壤穹，此誠何自達天中。", "幸憑今日皇華使，不假當年帝釋宮。", "人道蘇天真廣大，歲逢商旱得流通。", "欲知八郡生靈喜，七月興歌我稼同。"]'),
('7e7c47e2-181e-4410-a8b1-be409da75fe2','和蘇提舉喜雨  其二','陽枋','宋','宋诗','song-poetry','','[]','皇上焦勞冠百王，精求膚使惠南方。',64,'全唐诗/poet.song.197000.json','["皇上焦勞冠百王，精求膚使惠南方。", "驅馳靡憚周原隰，斂散尤高漢壽昌。", "屬邑近方憂水澇，單車不復待秋凉。", "公餘更有驚人句，爲解塵懷倥傯裝。"]'),
('a2fa7f7f-0b3c-471c-abc7-a1da772bc981','和知宗喜雨  其一','陽枋','宋','宋诗','song-poetry','','[]','災祥何必問圓穹，自是承流得失中。',64,'全唐诗/poet.song.197000.json','["災祥何必問圓穹，自是承流得失中。", "旱魃憑誰投遠裔，靈科聊復啟仙宮。", "天憐南國人民困，雨走西郊畎澮通。", "多謝宗英相慰勞，也應休戚略相同。"]'),
('d7baf882-c559-43d8-8a53-40ac6111e577','和知宗喜雨  其二','陽枋','宋','宋诗','song-poetry','','[]','赫赫炎官未退藏，祈禳已盡別無方。',64,'全唐诗/poet.song.197000.json','["赫赫炎官未退藏，祈禳已盡別無方。", "忽施潤澤環千里，再使榮華及百昌。", "未問民天無欠闕，且欣心地得清凉。", "一杯預作秋成慶，草草盤飱不用裝。"]'),
('96e50897-7e9a-47d0-976d-a59ea9cb3750','再和知宗喜雨','陽枋','宋','宋诗','song-poetry','','[]','旱魃爲災百念關，瓢中一滴奈天慳。',64,'全唐诗/poet.song.197000.json','["旱魃爲災百念關，瓢中一滴奈天慳。", "講求碧玉仙科秘，叱起蒼龍洞府間。", "神賜甘霖三日往，人欣和氣一朝還。", "憑公大手爲民賀，五色牋中蜀錦斑。"]'),
('bbd68461-3ddc-4e7e-9458-e5a709309f6b','三和知宗喜雨  其一','陽枋','宋','宋诗','song-poetry','','[]','藴隆尤更覺天穹，誰道滂沱正伏中。',64,'全唐诗/poet.song.197000.json','["藴隆尤更覺天穹，誰道滂沱正伏中。", "風捲海潮雷助勢，夜占星畢月移宮。", "黄雲轇轕村村喜，碧玉淙琤處處通。", "前日勤民均此念，尊前一笑大家同。"]'),
('d16e15c3-1610-41e6-8ca3-84ceb935d8a1','三和知宗喜雨  其二','陽枋','宋','宋诗','song-poetry','','[]','江海人推百谷王，可無膏澤惠炎方。',64,'全唐诗/poet.song.197000.json','["江海人推百谷王，可無膏澤惠炎方。", "五龍行水蘇將槁，萬頃秧田喜寖昌。", "不用飲冰祛內熱，急須沽酒做新凉。", "却愁好雨催詩句，愧乏良材取次裝。"]'),
('089a5ec5-df75-4849-9b39-2e69a708b078','和陳提舉喜雨  其一','陽枋','宋','宋诗','song-poetry','','[]','愁歎何繇達灝穹，秋成恐墮渺茫中。',64,'全唐诗/poet.song.197000.json','["愁歎何繇達灝穹，秋成恐墮渺茫中。", "五龍偃蹇藏深廟，六佛慈悲會一宮。", "帝勅名山諸洞閉，醮開太乙獨函通。", "應憐赤子車中鮒，爲激西江遍處同。"]'),
('f125db16-71be-4718-b514-a3c6d11e334d','和陳提舉喜雨  其二','陽枋','宋','宋诗','song-poetry','','[]','周家重穀業陳王，天亦哀民救此方。',64,'全唐诗/poet.song.197000.json','["周家重穀業陳王，天亦哀民救此方。", "一雨如傾過衆望，三登可卜見時昌。", "固知福地長無歉，尤喜炎天預借凉。", "耆老首爲鄉曲賀，唾成珠玉巧於裝。"]'),
('c49b6d4a-b2d7-4cf8-a8ce-dc7113df59e5','再和陳提舉喜雨  其一','陽枋','宋','宋诗','song-poetry','','[]','了無和氣格清穹，天意難回執熱中。',64,'全唐诗/poet.song.197000.json','["了無和氣格清穹，天意難回執熱中。", "驟雨起從南海廟，雄風到自楚王宮。", "却愁水府丹瓢注，解使銀河赤岸通。", "急趁好晴催刈穀，坻京相慶萬家同。"]'),
('2c6317f3-e311-4019-af9e-1fb452c75674','再和陳提舉喜雨  其二','陽枋','宋','宋诗','song-poetry','','[]','十萬農租要納王，望霓雖切雨何方。',64,'全唐诗/poet.song.197000.json','["十萬農租要納王，望霓雖切雨何方。", "桑林敬體皇心禱，雲漢終歌國祚昌。", "坐使里閭消歎息，幻成境界得清凉。", "欲知千里人情共，盈袖新詩已可裝。"]'),
('c9d24425-5856-4622-8649-c3204a094e3f','贄袁茶使','陽枋','宋','宋诗','song-poetry','','[]','天隅把袖立春風，井絡民情許上通。',64,'全唐诗/poet.song.197000.json','["天隅把袖立春風，井絡民情許上通。", "煖到夜郎安靜裏，寒消白帝撫摩中。", "摘山豈必溪芽盡，市駿何須冀種空。", "月渚扁舟書好讀，琅琅聲與大江東。"]'),
('82c4c7a0-a109-4899-b19e-e9b51e95850c','買舟過太湖口入小港','陽枋','宋','宋诗','song-poetry','','["\u592a\u6e56"]','連天白水渺無涯，短涉湖灣五里賒。',64,'全唐诗/poet.song.197000.json','["連天白水渺無涯，短涉湖灣五里賒。", "箇樣船腰穿浪急，片來帆腹飽風斜。", "日隨飛鷺幾程水，心逐浮鷗何處家。", "日落荒溪無繫纜，荻叢深處傍漁槎。"]'),
('85b13ca2-4c9d-49e7-8924-12796ee546b1','詠黄池詩','陽枋','宋','宋诗','song-poetry','','[]','姑蘇平野入黄池，烟樹重重綠漲迷。',64,'全唐诗/poet.song.197000.json','["姑蘇平野入黄池，烟樹重重綠漲迷。", "肆列門前喧坌俗，稻臨屋背儘幽棲。", "路長車馬南還北，水遠帆檣東復西。", "小寺江心閒繫纜，周迴看盡柳盈堤。"]'),
('b32178b2-2d8d-4c05-8010-b8be4eeba4fb','中秋黄池舟中獨酌五首  其一','陽枋','宋','宋诗','song-poetry','','[]','秋深客棹倚吳頭，喜見江鄉素月浮。',64,'全唐诗/poet.song.197000.json','["秋深客棹倚吳頭，喜見江鄉素月浮。", "水墨畫成洲渚遠，神仙宅盡水雲幽。", "心閒最與趣相會，句拙常憐景莫收。", "多少樓臺羅綺席，未知真是賞中秋。"]'),
('a5df6177-13e1-43c9-a899-f8dc3b9920bd','中秋黄池舟中獨酌五首  其二','陽枋','宋','宋诗','song-poetry','','[]','畫橋楊柳繫船兒，蟾魄飛來光滿溪。',64,'全唐诗/poet.song.197000.json','["畫橋楊柳繫船兒，蟾魄飛來光滿溪。", "有水連雲疑地闊，無山礙月覺天低。", "魚堪寄信應時見，鴈欲橫霜猶未齊。", "白酒堪沽雞中割，呼樽獨酌畫橋西。"]'),
('f1a472f2-40d9-4229-a648-8ea387bebde9','中秋黄池舟中獨酌五首  其三','陽枋','宋','宋诗','song-poetry','','[]','賞月東西兩地遥，一輪千里共今宵。',64,'全唐诗/poet.song.197000.json','["賞月東西兩地遥，一輪千里共今宵。", "心中至樂成真得，分外閒愁不復摇。", "江寺饒吾觀白水，郡亭喜弟看洪潮。", "世間歡賞由人爾，天地何曾有寂寥。"]'),
('c5d752c1-3c4b-4fe7-8ae0-dd1919392e8b','中秋黄池舟中獨酌五首  其四','陽枋','宋','宋诗','song-poetry','','[]','居家賞月天常雨，遠客逢秋月倍明。',64,'全唐诗/poet.song.197000.json','["居家賞月天常雨，遠客逢秋月倍明。", "世事美時難兩得，化工好處少雙成。", "詩如遇興須重賦，酒若逢辰且再傾。", "不是衰遲廢拘檢，良心隨寓自忘情。"]'),
('e4e75e12-6130-48f6-aa26-309927f65c75','中秋黄池舟中獨酌五首  其五','陽枋','宋','宋诗','song-poetry','','[]','一年十二月華圓，何事今宵到處看。',64,'全唐诗/poet.song.197000.json','["一年十二月華圓，何事今宵到處看。", "春夏暖時無底白，雪霜凝處不勝寒。", "酒腸緩放金罇倒，詩興何妨玉漏殘。", "莫學時人貪酩酊，清光未澈已闌單。"]'),
('e5cef843-b94b-458e-b1c3-48a9bcb16416','久留黄池待弟姪不至九日獨酌','陽枋','宋','宋诗','song-poetry','','[]','將道花黄醉彭澤，又還茱紫酌平湖。',64,'全唐诗/poet.song.197000.json','["將道花黄醉彭澤，又還茱紫酌平湖。", "詩因得意時時賦，酒爲無賓淺淺沽。", "藍色已殘千岸柳，霜花催滿萬汀蘆。", "閒行閒坐雲和水，不識天工怪我無。"]'),
('1a397294-086a-4c9f-b33a-61aab576517a','喜雨賀黄叔厚判縣','陽枋','宋','宋诗','song-poetry','','[]','去年精禱雨隨至，今日熏香雨便來。',64,'全唐诗/poet.song.197000.json','["去年精禱雨隨至，今日熏香雨便來。", "人事只從無僞見，天心端可至誠回。", "溜匙即此知翻雪，枵腹何由更隠雷。", "若使邊臣充此意，凶殘到處豈難摧。"]'),
('69e748ea-2b79-447f-bf24-3643a9c8f6ec','贄何總領','陽枋','宋','宋诗','song-poetry','','[]','中興賦用倚江淮，兼裕良籌仰雋才。',64,'全唐诗/poet.song.197000.json','["中興賦用倚江淮，兼裕良籌仰雋才。", "民社有歌耕足雨，伍符無腹隠枵雷。", "塞邊粟積漢而上，地上錢流唐以來。", "相業理財餘事耳，安能鬰鬰此居哉。"]'),
('cf65e725-3421-4a33-969e-d18ac114bd76','別黔中趙尉','陽枋','宋','宋诗','song-poetry','','[]','好風吹雪點征衣，認得東君巧轉機。',64,'全唐诗/poet.song.197000.json','["好風吹雪點征衣，認得東君巧轉機。", "北渚燕鴻從背立，前灘鸂鶒喜雙飛。", "梅中有味不妨隠，蓮本無心何待依。", "到處江山生意滿，呼尊判倒是和非。"]'),
('21014d28-133b-4e5b-a0e3-ed8a176f149f','寄桃源尉趙謙之','陽枋','宋','宋诗','song-poetry','','[]','桃源洞口送春歸，欲換漁蓑傍釣磯。',64,'全唐诗/poet.song.197000.json','["桃源洞口送春歸，欲換漁蓑傍釣磯。", "火着高林鴉又散，弦鳴中澤鴈還飛。", "蕭蕭空雨晨光潤，耿耿籠燈夜色微。", "休對癡人獃說夢，野花啼鳥恁天機。"]'),
('d54043db-d7bc-4664-94d6-5a78c0c65960','江干覽鏡','陽枋','宋','宋诗','song-poetry','','[]','千重灘淺身曾過，萬頃湖深也去來。',64,'全唐诗/poet.song.197000.json','["千重灘淺身曾過，萬頃湖深也去來。", "平地雪中蕭店宿，掀天浪裏片帆開。", "干戈鼎沸舟還失，炎暑甑蒸師正灾。", "小艇隨人偷入峽，笑開菱匣亦頑哉。"]'),
('3b6a2ac3-61c1-47d2-bce4-93a079939cb1','壽鄧提幹母  其一','陽枋','宋','宋诗','song-poetry','','[]','爭似瑶仙捧玉觴，一堂四世聚簪裳。',64,'全唐诗/poet.song.197000.json','["爭似瑶仙捧玉觴，一堂四世聚簪裳。", "閒中尊俎江山久，靜裏襟懷日月長。", "蓂紫爛連庭桂紫，橘香濃引誥花香。", "陵溪種得桃無限，乞與漁郎半核嘗。"]'),
('18cfd9d0-92aa-44a0-af99-eeda14f16dd6','壽鄧提幹母  其二','陽枋','宋','宋诗','song-poetry','','[]','嘗桃不祇似東方，三度濃熏竹院香。',64,'全唐诗/poet.song.197000.json','["嘗桃不祇似東方，三度濃熏竹院香。", "眼底兒孫青瑣客，鏡中顔色碧琳房。", "山屏繡出方壺穩，峽線拖餘翠水長。", "醉問羣仙休拍手，誰人翻得九霞觴。"]'),
('fcea1df1-9a8a-4822-a99f-121503bf25c1','贄趙廣安','陽枋','宋','宋诗','song-poetry','','[]','先生早矣袖薰弦，趁取南風入皛然。',64,'全唐诗/poet.song.197000.json','["先生早矣袖薰弦，趁取南風入皛然。", "燕穩不妨辭閫幕，魚枯應喜活民編。", "萬家吟賞知微月，千里依棲刺史天。", "河漢定應思黼黻，大宗寧許久藩宣。"]'),
('1a786e63-dc71-43f9-a035-dba1760d374d','中秋微月和彭水趙文卿韻','陽枋','宋','宋诗','song-poetry','','[]','剩雨頑雲乍解圍，清光此夜擬依稀。',64,'全唐诗/poet.song.197000.json','["剩雨頑雲乍解圍，清光此夜擬依稀。", "天工不許厭厭飲，月姊終慳皎皎輝。", "離合隨緣都是樂，陰晴任理兩忘機。", "謝君好語無貂續，題拙慙隨趙璧歸。"]'),
('66d7a324-8592-4770-9151-80198a6dc4f2','曹都統詩','陽枋','宋','宋诗','song-poetry','','[]','胸中陳法久堂堂，卯歲邊戎真漫狂。',64,'全唐诗/poet.song.197000.json','["胸中陳法久堂堂，卯歲邊戎真漫狂。", "佇看勝齊歸一鼓，未饒破魏說三當。", "弓刀早落風雲會，衮繡行依日月光。", "已撰磨崖碑萬字，爲君題破碧苔蒼。"]'),
('03a94c4e-9445-47df-bf65-50781b2b910f','挽心友李應之判縣  其一','陽枋','宋','宋诗','song-poetry','','[]','書劍追隨徧蜀西，歸來窗月聽朝雞。',64,'全唐诗/poet.song.197000.json','["書劍追隨徧蜀西，歸來窗月聽朝雞。", "相期歲晚林中約，忍見佳城石上題。", "錦里人稀烟冉冉，橫川路迥草萋萋。", "黔南愧我催瓜戍，淚落巴山望欲迷。"]'),
('26b612c8-0cc1-4bcf-bfc9-358e7722d202','挽心友李應之判縣  其二','陽枋','宋','宋诗','song-poetry','','[]','妙歲麟經得興微，名成四十壯心違。',64,'全唐诗/poet.song.197000.json','["妙歲麟經得興微，名成四十壯心違。", "半生于德歸門駟，一節夷清在首薇。", "古禮事親輪月曉，新詩易簀片雲飛。", "九京他日如堪作，見說非公誰與歸。"]'),
('10a23ec4-4d0f-48a4-bf55-31f9e0046ed7','和郭廣文喜雨','陽枋','宋','宋诗','song-poetry','','[]','隨軒好雨决渠深，生意挽回天地心。',64,'全唐诗/poet.song.197000.json','["隨軒好雨决渠深，生意挽回天地心。", "不是一麾賢出守，何緣三日往爲霖。", "勤農襏襫田頭影，幽鳥間關花底吟。", "紫陌桑麻連菽粟，從教鼓腹曳裾衿。"]'),
('d804192f-361d-43bd-a3cd-f8e3948b72b9','見歐制幹  其一','陽枋','宋','宋诗','song-poetry','','[]','殿西歌徹采薇聲，記室煩君爲一行。',64,'全唐诗/poet.song.197000.json','["殿西歌徹采薇聲，記室煩君爲一行。", "竇幕有班燕刻重，裴寮得愈蔡功成。", "文書晝靜旌旗捲，籌畫宵閒鼓角清。", "今日元戎前長史，步趨脚跡好門生。"]'),
('2747a0e4-003a-4cae-beca-8623b416c950','見歐制幹  其二','陽枋','宋','宋诗','song-poetry','','[]','尋師萬里走東南，性學精微聞兩三。',64,'全唐诗/poet.song.197000.json','["尋師萬里走東南，性學精微聞兩三。", "風月歸來深體認，簞瓢自樂細沈涵。", "巖前靜索龜圖秘，蜀口驚呼蟻戰酣。", "欲覓底寮整殘斷，峽天分借一屏嵐。"]'),
('7d36aa4f-7db4-487c-8149-a2d86e4c876d','挽垓山陳宣義','陽枋','宋','宋诗','song-poetry','','[]','升堂曾得話從容，骨相清癯七十翁。',64,'全唐诗/poet.song.197000.json','["升堂曾得話從容，骨相清癯七十翁。", "唧唧愛人皆語妙，遲遲留客屢盃空。", "眼分青白斯文外，手作推敲雅詠中。", "我忝金蘭三世契，頗堪溪滸憶清風。"]'),
('af927ed3-1807-4a96-8846-655e18ef0570','池口下小港遇大風  其一','陽枋','宋','宋诗','song-poetry','','[]','萬雷豗擊一江聲，本是風從水上行。',64,'全唐诗/poet.song.197000.json','["萬雷豗擊一江聲，本是風從水上行。", "斷港不妨尋住計，修塗未信阻歸程。", "閒中已會性天靜，忙裏依然心地平。", "險阻怪崖行半百，扁舟肯學夜多驚。"]'),
('9a611ea7-6541-484c-bbcb-391e439ad4d7','池口下小港遇大風  其二','陽枋','宋','宋诗','song-poetry','','[]','詩翁下語寫心聲，說破雲濤阻客行。',64,'全唐诗/poet.song.197000.json','["詩翁下語寫心聲，說破雲濤阻客行。", "得意快吟三兩句，放懷休數八千程。", "時因極凍方回暖，水若無風還自平。", "一點陽和消息好，江邊柳眼又眠驚。"]'),
('4063f3fe-3aa3-49b4-9c00-5049e081519d','池口下小港遇大風  其三','陽枋','宋','宋诗','song-poetry','','[]','水本無聲風作聲，何心坎止與流行。',64,'全唐诗/poet.song.197000.json','["水本無聲風作聲，何心坎止與流行。", "掀天不礙翻洪浪，到海須知有去程。", "可以東西形暫激，不容軒輊性元平。", "懸知讀易如程子，舟壓銀濤膽不驚。"]'),
('576990ef-4d1b-4954-bd92-aba10ed4c801','挽李致政','陽枋','宋','宋诗','song-poetry','','[]','鷗閒伴侶子夔邊，錫類宗盟計百年。',64,'全唐诗/poet.song.197000.json','["鷗閒伴侶子夔邊，錫類宗盟計百年。", "準擬歸來尋舊約，不堪相送苾新阡。", "芝蘭笑語龍山事，桃李樽罍象澦天。", "鍾作數行臨老淚，爲君滴向碧溪淵。"]'),
('b2686c12-87d1-4785-be8c-4e4b53cc8e45','紹慶羅巡檢','陽枋','宋','宋诗','song-poetry','','[]','蕉溪煙水似羅浮，君著軒亭瞰碧流。',64,'全唐诗/poet.song.197000.json','["蕉溪煙水似羅浮，君著軒亭瞰碧流。", "東館聽鷄書伴月，南邊休馬鐸沈秋。", "憐人得飽倉捐粟，送客登山岸倚舟。", "種玉前村春意早，梅花带雪滿枝頭。"]'),
('85a8f865-f948-4014-b99e-4a96f9a29670','送田使君都統離夔赴合州','陽枋','宋','宋诗','song-poetry','','[]','英雄才略暫臨夔，泛綠依紅詫小兒。',64,'全唐诗/poet.song.197000.json','["英雄才略暫臨夔，泛綠依紅詫小兒。", "肯向稠人識毛遂，甘從走督得神師。", "魚城人喜景星出，象澦猿驚仙仗移。", "七十老翁怕趨走，峽江亭上倍臨歧。"]'),
('af88133d-ef78-4820-96e3-47c61ac22dd9','和桃源宰趙存禮韻','陽枋','宋','宋诗','song-poetry','','[]','三時不害試鳩工，築鑿輪輿職自攻。',64,'全唐诗/poet.song.197000.json','["三時不害試鳩工，築鑿輪輿職自攻。", "利器祇因盤錯見，淳風須信古今同。", "野桃川谷逢人好，春草池塘待雪融。", "洞口果教花似舊，支筇未肯作衰翁。"]'),
('8f4a6a2d-0f26-4f4e-9e9b-d87d852578d7','回奉節宰陽季明','陽枋','宋','宋诗','song-poetry','','[]','只緣心地樂寬平，便把青衫付外心。',64,'全唐诗/poet.song.197000.json','["只緣心地樂寬平，便把青衫付外心。", "健羨春鶑嬌出谷，自慚宿鳥倦投林。", "光陰有限嗟空度，義理無窮要極深。", "七十老翁聞好語，一回吟詠一回斟。"]'),
('8d6cbc64-6143-467a-a251-cf525fc16509','臘月二十八日與知宗提舉分歲郡中啜茶于北樓賞梅于忠獻堂知宗即席有詩次韻并簡提舶','陽枋','宋','宋诗','song-poetry','','[]','老病踰年卧晉江，耽詩性癖未能降。',64,'全唐诗/poet.song.197000.json','["老病踰年卧晉江，耽詩性癖未能降。", "園林牢落梅經眼，歲月崢嶸酒滿缸。", "堂上焚香敬勳德，樓頭回首念家鄉。", "黄柑未拜蕭嵩賜，鄉味分珍漫一雙。"]'),
('ba2507ed-b3c7-424e-9a98-abc0c5b7379f','癸亥守歲聰兒桃源黄溪村居  其一','陽枋','宋','宋诗','song-poetry','','[]','貪看子舍築溪濱，屈指除宵又及辰。',64,'全唐诗/poet.song.197000.json','["貪看子舍築溪濱，屈指除宵又及辰。", "七八再逢新甲子，十三重記舊庚申。", "一盃春酒紅衰臉，四世斑衣悅老身。", "爆竹聲聽桃洞曉，舉家疑是避秦人。"]'),
('61e995c8-3138-42d9-952f-d13d5005a133','癸亥守歲聰兒桃源黄溪村居  其二','陽枋','宋','宋诗','song-poetry','','[]','今年爆竹楚江濱，別歲迎春僅隔辰。',64,'全唐诗/poet.song.197000.json','["今年爆竹楚江濱，別歲迎春僅隔辰。", "小築地偏聊爾爾，幽居心遠自申申。", "兒從豹變當斯世，我得鷗閒着此身。", "學易假年天若許，橫書長作傍梅人。"]'),
('f72a4514-6862-4386-9d1b-109fd6cc13c1','癸未守歲','陽枋','宋','宋诗','song-poetry','','[]','歲宜鄉里守，杯共弟兄銜。',24,'全唐诗/poet.song.197000.json','["歲宜鄉里守，杯共弟兄銜。", "明日人相問，行年五十三。"]'),
('3ab32471-e286-44a9-94d2-1c0f773c56f0','逆風返順和東翔姪韻','陽枋','宋','宋诗','song-poetry','','[]','觀國丹心切，橫舟綠水遲。',24,'全唐诗/poet.song.197000.json','["觀國丹心切，橫舟綠水遲。", "東君如有意，風返曉江吹。"]'),
('ebce422d-6533-450f-9f0b-b6a4e84ee466','北高峰','陽枋','宋','宋诗','song-poetry','','[]','上到北高峰，京城一方冊。',24,'全唐诗/poet.song.197000.json','["上到北高峰，京城一方冊。", "天邊極雙眸，雲闊海門白。"]'),
('29f06bfd-910e-45ec-910e-fd3a6a999b1c','湖口和全父弟韻','陽枋','宋','宋诗','song-poetry','','[]','鄱陽湖口縣，山合鎖人烟。',24,'全唐诗/poet.song.197000.json','["鄱陽湖口縣，山合鎖人烟。", "石壁排屏翠，臨江障百川。"]'),
('c36524df-33e9-40b4-9038-77055e00cf52','秤錘峽','陽枋','宋','宋诗','song-poetry','','[]','秤錘盤巨石，藏重亦藏輕。',24,'全唐诗/poet.song.197000.json','["秤錘盤巨石，藏重亦藏輕。", "待出持衡手，一匡天下平。"]'),
('2e9ba995-5b19-4901-ba92-93749571ae9b','避地雲山全父弟詩寄梅花  其一','陽枋','宋','宋诗','song-poetry','','[]','入秋烽火無虛日，問谷尋巖陪隠逸。',32,'全唐诗/poet.song.197000.json','["入秋烽火無虛日，問谷尋巖陪隠逸。", "水冷山深梅已花，忙中不覺年華易。"]'),
('e89ea1cb-f4e3-4736-9825-8f67a619cd76','避地雲山全父弟詩寄梅花  其二','陽枋','宋','宋诗','song-poetry','','[]','地僻人稀花自妍，世衰學喪道終傳。',32,'全唐诗/poet.song.197000.json','["地僻人稀花自妍，世衰學喪道終傳。", "天機妙處人難解，一局閒棊學洞仙。"]'),
('ed917337-e651-4fd4-b9f6-44a41aa8517e','避地雲山全父弟詩寄梅花  其三','陽枋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','看花巖下興偏長，不減西湖水月光。',32,'全唐诗/poet.song.197000.json','["看花巖下興偏長，不減西湖水月光。", "鎮坐絕無塵一點，壽陽深笑靚宮粧。"]'),
('7823b973-d3bd-4f28-b1b1-c336f31f76e1','避地雲山全父弟詩寄梅花  其四','陽枋','宋','宋诗','song-poetry','','[]','骨中香徹骨中清，着雨問花不作聲。',32,'全唐诗/poet.song.197000.json','["骨中香徹骨中清，着雨問花不作聲。", "一氣本同形色異，人花清傑兩忘情。"]'),
('495dcd61-c042-4683-88d9-db65dd8a07a7','避地雲山全父弟詩寄梅花  其五','陽枋','宋','宋诗','song-poetry','','[]','久荒詩律廢陶鈞，妙句佳君語意新。',32,'全唐诗/poet.song.197000.json','["久荒詩律廢陶鈞，妙句佳君語意新。", "便欲支筇到巖底，不須折贈隴頭春。"]'),
('21c3b58e-9042-465b-bd5e-250693b86cbf','石筒峽','陽枋','宋','宋诗','song-poetry','','[]','槎枒怪石亂撐空，岸脚無沙到石筒。',32,'全唐诗/poet.song.197000.json','["槎枒怪石亂撐空，岸脚無沙到石筒。", "春水溶溶遲日麗，扁舟蕩槳穩朝東。"]'),
('92e06cfd-60d9-412c-b1fb-7f79edea0372','瞿唐峽  其一','陽枋','宋','宋诗','song-poetry','','[]','曾聞灧澦屹瞿唐，雪浪摧山勢獨當。',32,'全唐诗/poet.song.197000.json','["曾聞灧澦屹瞿唐，雪浪摧山勢獨當。", "我至韶融方二月，水平石出映斜陽。"]'),
('d4d4d6ae-6190-4236-801d-706bdaddaf5a','瞿唐峽  其二','陽枋','宋','宋诗','song-poetry','','[]','萬丈危屏水墨圖，江流带窄映雲衢。',32,'全唐诗/poet.song.197000.json','["萬丈危屏水墨圖，江流带窄映雲衢。", "莫怪波平瀾不倒，回狂灧澦一峰孤。"]'),
('339d2e6a-f3f6-4611-8ef6-589c31bc8052','井口鎮石牛詩','陽枋','宋','宋诗','song-poetry','','[]','巨石如牛泝綠漪，象名爲物本無知。',32,'全唐诗/poet.song.197000.json','["巨石如牛泝綠漪，象名爲物本無知。", "休言神禹忘疏鑿，付與馮夷日箠笞。"]'),
('4f7d036d-3607-4987-8936-ceda26bcb95d','登六和塔','陽枋','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','錢塘江上撐空塔，塔外遥山翠作堆。',32,'全唐诗/poet.song.197000.json','["錢塘江上撐空塔，塔外遥山翠作堆。", "酒罷凭欄呼落日，水雲深處子陵臺。"]'),
('66bbbae0-2383-446e-a516-7674811cc5a5','楊居士送眼藥','陽枋','宋','宋诗','song-poetry','','[]','雲來雲去不干山，花落花開春又還。',32,'全唐诗/poet.song.197000.json','["雲來雲去不干山，花落花開春又還。", "世事總歸明眼裏，皇王帝伯恁催班。"]'),
('ddbca4db-f766-497f-938b-4cf2f1bb791a','贈藺道士','陽枋','宋','宋诗','song-poetry','','[]','入水大蟲出火龍，一生看守贊神工。',32,'全唐诗/poet.song.197000.json','["入水大蟲出火龍，一生看守贊神工。", "知行例作等閒話，三尺兒童八十翁。"]'),
('a5ac46e2-3905-41ea-8947-15978364fd47','艘人誤同行錢文作詩解之  其一','陽枋','宋','宋诗','song-poetry','','[]','胯下當年甚可羞，身藏寶劍豈無謀。',32,'全唐诗/poet.song.197000.json','["胯下當年甚可羞，身藏寶劍豈無謀。", "暫時俯首依人去，贏取堂堂萬戶侯。"]'),
('f717d41c-30cf-42b4-a314-7e765b47df21','艘人誤同行錢文作詩解之  其二','陽枋','宋','宋诗','song-poetry','','[]','自反仁而自反忠，芳蓮開向火光中。',32,'全唐诗/poet.song.197000.json','["自反仁而自反忠，芳蓮開向火光中。", "同君九萬摶扶去，薄盡浮雲出太空。"]'),
('3064f96e-dda9-4f97-9110-adac6f2b92f8','文昌醮燈牌','陽枋','宋','宋诗','song-poetry','','[]','牡丹枝上先春蕊，翠杏壇邊未雨虹。',32,'全唐诗/poet.song.197000.json','["牡丹枝上先春蕊，翠杏壇邊未雨虹。", "知有文章光萬丈，鍾成佳氣滿黔中。"]'),
('68836c9b-6132-4f93-b0c6-7fb6560a7ac7','丁家洲','陽枋','宋','宋诗','song-poetry','','[]','水雲留住覺無計，杞菊催歸知有涯。',32,'全唐诗/poet.song.197000.json','["水雲留住覺無計，杞菊催歸知有涯。", "百丈黄昏牽月色，長洲灣處宿丁家。"]'),
('a38e071e-d747-4ad3-bc89-e6a4b7d35b9d','驚雷驟雨','陽枋','宋','宋诗','song-poetry','','[]','今年春晚天氣寒，桃李村村猶未吐。',32,'全唐诗/poet.song.197000.json','["今年春晚天氣寒，桃李村村猶未吐。", "豗擊雷聲送五更，江皋一陣催花雨。"]'),
('5c860987-42aa-4d49-92c8-56321af85fae','謁趙漕  其一','陽枋','宋','宋诗','song-poetry','','[]','山頭雲麥雜燒畬，桃李層層山半家。',32,'全唐诗/poet.song.197000.json','["山頭雲麥雜燒畬，桃李層層山半家。", "謳軋蠻歌聲滿峽，春生龍節爛光華。"]'),
('b22bbd35-32f5-4cf9-b1dc-9ecb55d7363d','謁趙漕  其二','陽枋','宋','宋诗','song-poetry','','[]','槎星爛照玉堂明，樓雪晴融白帝城。',32,'全唐诗/poet.song.197000.json','["槎星爛照玉堂明，樓雪晴融白帝城。", "鷗狎不知菱蕩轉，漫隨瀼水泛春聲。"]'),
('1884aaf3-b8a9-4c51-a060-1bda2b72dd91','謁趙漕  其三','陽枋','宋','宋诗','song-poetry','','[]','文公桃李筍班中，問學心旌日夜東。',32,'全唐诗/poet.song.197000.json','["文公桃李筍班中，問學心旌日夜東。", "時序催人烟水遠，臨流願借一帆風。"]'),
('824d1530-cd97-4ce4-a154-f600bf62c16b','社日過洞庭','陽枋','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','社風吹雨楚江晴，舟葉輕飛過洞庭。',32,'全唐诗/poet.song.197000.json','["社風吹雨楚江晴，舟葉輕飛過洞庭。", "萬里湖天天外水，君山一點望中青。"]'),
('4c7a8c7d-5382-4dda-b628-0db2612089b9','固城湖  其一','陽枋','宋','宋诗','song-poetry','','[]','掌似平蕪遠際空，灣灣曲曲水相通。',32,'全唐诗/poet.song.197000.json','["掌似平蕪遠際空，灣灣曲曲水相通。", "蘆汀蓼渚新秋裏，一段濃藍一段紅。"]'),
('b9a8d3d2-f30a-4f8d-aa6e-dd3b5953b51f','固城湖  其二','陽枋','宋','宋诗','song-poetry','','[]','有戶盡開楊影底，無軒不在水光中。',32,'全唐诗/poet.song.197000.json','["有戶盡開楊影底，無軒不在水光中。", "濃藍染就秋空碧，只欠斜飛幾點鴻。"]'),
('f379dc09-7c22-42da-828e-0c8ae66d3856','固城湖  其三','陽枋','宋','宋诗','song-poetry','','[]','溪平岸闊柳侵沙，潑潑遊鱗弄月華。',32,'全唐诗/poet.song.197000.json','["溪平岸闊柳侵沙，潑潑遊鱗弄月華。", "柔櫓數聲深夜悄，漁人相喚隔蘆葭。"]'),
('97dc71b6-e956-4a3d-9139-0849a9d7a33a','涪州北巖書院別王東卿歸樂邑','陽枋','宋','宋诗','song-poetry','','[]','雨前雨後山俱好，江瘦江肥水盡佳。',32,'全唐诗/poet.song.197000.json','["雨前雨後山俱好，江瘦江肥水盡佳。", "一見論心無久近，休言眼底各天涯。"]'),
