('fa32b8c9-ebaa-4def-b29d-8c19dac762a7','包家園','陽枋','宋','宋诗','song-poetry','','[]','衆綠爭齊敷夏蔭，老紅猶自駐春粧。',32,'全唐诗/poet.song.197000.json','["衆綠爭齊敷夏蔭，老紅猶自駐春粧。", "閒紅浪綠俱休問，爭似巖松一色蒼。"]'),
('8ab649a1-8207-4d58-ac7f-b2237cd15ba3','詠絲桐','陽枋','宋','宋诗','song-poetry','','[]','地闊天寬人一般，琴心會得語言難。',32,'全唐诗/poet.song.197000.json','["地闊天寬人一般，琴心會得語言難。", "高山流水知音少，月白風清時自彈。"]'),
('08415c72-efcb-4975-88f1-75553ac57fa4','下沱張西叔牡丹號奇品以詩寄花因用韻謝  其一','陽枋','宋','宋诗','song-poetry','','[]','天香吹落五雲來，滿眼浮花只浪開。',32,'全唐诗/poet.song.197000.json','["天香吹落五雲來，滿眼浮花只浪開。", "國色不關朝得酒，粧臺漫飲紫金盃。"]'),
('0157ba86-4cb0-4d53-86eb-5056d6fc316d','下沱張西叔牡丹號奇品以詩寄花因用韻謝  其二','陽枋','宋','宋诗','song-poetry','','[]','主人骨相花難比，折贈雙花副麗辭。',32,'全唐诗/poet.song.197000.json','["主人骨相花難比，折贈雙花副麗辭。", "爲報此花香第一，何須鉛粉巧粧褫。"]'),
('9e421992-2639-4f9e-ae0a-8f67c7d7dae9','句  其一','陽枋','宋','宋诗','song-poetry','','[]','五載彈冠尚覺忙。',8,'全唐诗/poet.song.197000.json','["五載彈冠尚覺忙。"]'),
('d80c8ded-dbb1-4ae3-b909-168d3d017e2f','句  其二','陽枋','宋','宋诗','song-poetry','','[]','文章不數向歆輩，姓字須教班馬香。',16,'全唐诗/poet.song.197000.json','["文章不數向歆輩，姓字須教班馬香。"]'),
('ba67e1ea-c6f3-4a51-ad49-4b4d6afcc1d3','句  其三','陽枋','宋','宋诗','song-poetry','','[]','豈但流王澤，應須沃朕心。',12,'全唐诗/poet.song.197000.json','["豈但流王澤，應須沃朕心。"]'),
('d3045b41-9cc8-42a0-babe-0b2c8404fede','句  其四','陽枋','宋','宋诗','song-poetry','','[]','霹靂一聲風卷去，誰家水館夕陽天。',16,'全唐诗/poet.song.197000.json','["霹靂一聲風卷去，誰家水館夕陽天。"]'),
('d0b34a12-cd31-45f9-b38f-488323384618','句  其五','陽枋','宋','宋诗','song-poetry','','[]','飽諳風月歸，庶幾無虛還。',12,'全唐诗/poet.song.197000.json','["飽諳風月歸，庶幾無虛還。"]'),
('bf5241e9-9ff0-4068-a2e8-13397c68e558','句  其六','陽枋','宋','宋诗','song-poetry','','[]','可奈紅塵飛白羽，不容黄叟卧青山。',16,'全唐诗/poet.song.197000.json','["可奈紅塵飛白羽，不容黄叟卧青山。"]'),
('86633aa4-8c65-4fe6-89a8-f61844dec4cb','句  其七','陽枋','宋','宋诗','song-poetry','','[]','白雲無心閒渡水，清風何意自開花。',16,'全唐诗/poet.song.197000.json','["白雲無心閒渡水，清風何意自開花。"]'),
('58d18727-3095-4d19-91f2-b86f6b6a665c','贈陽子','王濟之','宋','宋诗','song-poetry','','[]','陽子窮居在顔巷，有田一廛宅一區。',32,'全唐诗/poet.song.197000.json','["陽子窮居在顔巷，有田一廛宅一區。", "師門立雪得心傳，歸來兀兀哦古書。"]'),
('53319cb5-47a3-4bb9-b7dd-f02f07f99d64','郭璞墓','劉克莊','宋','宋诗','song-poetry','','[]','先生精數學，卜穴未應疎。',48,'全唐诗/poet.song.197000.json','["先生精數學，卜穴未應疎。", "因捋虎鬚死，還尋魚腹居。", "如何師鬼谷，却去友靈胥。", "此理憑誰詰，人方寶葬書。"]'),
('a46e106b-f9a5-4800-ae6e-9d439ef08066','魏太武廟','劉克莊','宋','宋诗','song-poetry','','[]','荒涼瓜步市，尚有佛狸祠。',48,'全唐诗/poet.song.197000.json','["荒涼瓜步市，尚有佛狸祠。", "俚俗傳來久，行人信復疑。", "亂鴉爭祭處，萬馬飲江時。", "意氣今安在，城笳暮更悲。"]'),
('69ff0a93-b79f-49ba-b476-ff36d026eff9','徐孺子墓','劉克莊','宋','宋诗','song-poetry','','[]','今曉安墳意，梅仙舊廨傍。',48,'全唐诗/poet.song.197000.json','["今曉安墳意，梅仙舊廨傍。", "醢成龍不至，羅設鳳高翔。", "黨錮人俱燼，先生骨尚香。", "小詩拈未出，何以侑椒漿。"]'),
('4605e130-f5a3-477d-b142-bc6821c31acb','北來人二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','試說東都事，添人白髮多。',48,'全唐诗/poet.song.197000.json','["試說東都事，添人白髮多。", "寢園殘石馬，廢殿泣銅駝。", "胡運占難久，邊情聽易訛。", "凄涼舊京女，粧髻尚宣和。"]'),
('95fc2027-9eec-4669-b033-2a3baf9f96b9','北來人二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','十口同離北，今成獨鴈飛。',48,'全唐诗/poet.song.197000.json','["十口同離北，今成獨鴈飛。", "饑鉏荒寺菜，貧著陷蕃衣。", "甲第歌鍾沸，沙場探騎稀。", "老身閩地死，不見翠鑾歸。"]'),
('0f6b8360-7750-4d10-b967-a8a40a820d46','北山作','劉克莊','宋','宋诗','song-poetry','','[]','骨法枯閑甚，惟堪作隠君。',48,'全唐诗/poet.song.197000.json','["骨法枯閑甚，惟堪作隠君。", "山行忘路脈，野坐認天文。", "字瘦偏題石，詩寒半說雲。", "近來仍喜聵，閑事不曾聞。"]'),
('e7c57d93-dcda-46d4-8ac7-c0fdbe4fa526','早行','劉克莊','宋','宋诗','song-poetry','','[]','店嫗明燈送，前村認未真。',48,'全唐诗/poet.song.197000.json','["店嫗明燈送，前村認未真。", "山頭雲似雪，陌上樹如人。", "漸覺高星少，纔分遠燒新。", "何煩看堠子，來往暗知津。"]'),
('732e94ec-9eb5-417b-9e4d-318a907bc8f4','黄檗山','劉克莊','宋','宋诗','song-poetry','','[]','出縣半程遥，松間認粉標。',48,'全唐诗/poet.song.197000.json','["出縣半程遥，松間認粉標。", "峯排神女峽，寺創德宗朝。", "鸛老巢高木，僧寒曬墮樵。", "早知人世淡，來住退居寮。"]'),
('4497ea2b-6bc5-4a59-98ac-f70f5284c828','第三龍湫','劉克莊','宋','宋诗','song-poetry','','[]','絕頂謁龍公，森寒石作宮。',48,'全唐诗/poet.song.197000.json','["絕頂謁龍公，森寒石作宮。", "路盤青壁上，瀑瀉白雲中。", "僧說聞雷出，人疑與海通。", "幾時陰晦夜，來此看拏空。"]'),
('e6c47d18-8aa8-423c-92ef-164a8cabb221','客中作','劉克莊','宋','宋诗','song-poetry','','[]','漂泊何須遠，離鄉即旅人。',48,'全唐诗/poet.song.197000.json','["漂泊何須遠，離鄉即旅人。", "吹薪嘗海品，書刺謁田鄰。", "家寄寒衣少，山來曉夢頻。", "小兒仍病瘧，詩句竟無神。"]'),
('c53510cc-3ae5-4668-82f2-6400c8de18e5','小寺','劉克莊','宋','宋诗','song-poetry','','[]','小寺無蹊逕，行時認蘚痕。',48,'全唐诗/poet.song.197000.json','["小寺無蹊逕，行時認蘚痕。", "犬寒鳴似豹，僧老瘦於猿。", "澗水來旋磨，山童出閉門。", "城中梅未見，已有數株繁。"]'),
('c138351e-ebec-4abc-86df-0167879f73e5','晚春','劉克莊','宋','宋诗','song-poetry','','[]','花事匆匆了，人家割麥初。',48,'全唐诗/poet.song.197000.json','["花事匆匆了，人家割麥初。", "雨多田有鸛，潮小市無魚。", "禿筆回僧簡，褒衣看古書。", "經年稀見客，磬折轉生疎。"]'),
('c3081039-4c89-439c-ad66-2a51da4c2290','哭葉孝錫教授','劉克莊','宋','宋诗','song-poetry','','[]','瘴雲深處死，太息柰君何。',48,'全唐诗/poet.song.197000.json','["瘴雲深處死，太息柰君何。", "詩友俱來弔，埋銘久未磨。", "箕裘無子繼，書畫落人多。", "舊宅今移主，斜陽掩涕過。"]'),
('9e56d0a9-e08e-432c-a28e-5a6a53545b20','夜過瑞香庵作','劉克莊','宋','宋诗','song-poetry','','[]','夜深捫絕頂，童子旋開扉。',48,'全唐诗/poet.song.197000.json','["夜深捫絕頂，童子旋開扉。", "問客來何暮，云僧去未歸。", "山空聞瀑瀉，林黑見螢飛。", "此境惟予愛，他人到想稀。"]'),
('f9b590ba-1a64-4760-ad94-733eed65d486','送薛明府','劉克莊','宋','宋诗','song-poetry','','[]','長官三載內，屢被督郵嗔。',48,'全唐诗/poet.song.197000.json','["長官三載內，屢被督郵嗔。", "鎮靜笞刑少，公清縣庫貧。", "減租霑野老，掃榻待詩人。", "祇恐鳬飛後，民間事事新。"]'),
('1a621dae-1659-4b83-8280-acdbfd9cabd8','蒜嶺','劉克莊','宋','宋诗','song-poetry','','[]','到此思家切，寒衣半淚痕。',48,'全唐诗/poet.song.197000.json','["到此思家切，寒衣半淚痕。", "燒餘山頂禿，潮至海波渾。", "僕怕昏無店，人言近有村。", "吾生輸野老，笑語掩柴門。"]'),
('72a4ce0f-90ad-4523-94aa-83547ec4d687','示觀老','劉克莊','宋','宋诗','song-poetry','','[]','住山仍黑瘦，瓶錫極蕭然。',48,'全唐诗/poet.song.197000.json','["住山仍黑瘦，瓶錫極蕭然。", "頂髮千莖雪，跏趺一縷煙。", "禪堪拈出衆，詩亦長於前。", "燒盡西窗燭，相看各不眠。"]'),
('ebe81be1-c083-4f64-aa18-3a6c96809465','武涉道中','劉克莊','宋','宋诗','song-poetry','','[]','一路荒凉極，無端過此頻。',48,'全唐诗/poet.song.197000.json','["一路荒凉極，無端過此頻。", "官於鹽起稅，俗事蠱爲神。", "暝色初逢驛，溪聲只隔林。", "留題空滿壁，不見有詩人。"]'),
('ba28124c-ba3e-433b-8c41-53393ece7ebc','浦城道中','劉克莊','宋','宋诗','song-poetry','','[]','纔入僊霞路，重裘尚不支。',48,'全唐诗/poet.song.197000.json','["纔入僊霞路，重裘尚不支。", "居人收桕實，客子辦梅詩。", "地濕然萁坐，霜寒隔被知。", "向來真錯計，不買草堂基。"]'),
('83c9baad-d319-41b8-bebb-52e89bb35399','幽居寺','劉克莊','宋','宋诗','song-poetry','','[]','相傳有儒者，唐季隠茲峯。',48,'全唐诗/poet.song.197000.json','["相傳有儒者，唐季隠茲峯。", "電已收遺藁，雲方鎖暮鍾。", "木碑無世次，石洞斷人蹤。", "此士何曾死，林深不可逢。"]'),
('e58ea09b-d2af-4b15-8355-eb5bd44d8b4f','大目寺','劉克莊','宋','宋诗','song-poetry','','[]','來人云虎出，留此到昏鍾。',48,'全唐诗/poet.song.197000.json','["來人云虎出，留此到昏鍾。", "寺小於諸剎，山高似衆峯。", "未寒先得雪，已夏尚如冬。", "老子曾游浙，微微有辨鋒。"]'),
('8e5c7568-9a9e-40fd-80d4-0cc2cf7080e7','哭容倅舅氏二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','老赴容州辟，移書勸不回。',48,'全唐诗/poet.song.197000.json','["老赴容州辟，移書勸不回。", "客迎蕭寺哭，喪附海舟來。", "瘴雨銘旌暗，空山梵磬哀。", "未知墳上柏，此去幾時栽。"]'),
('2f3ba525-debc-4086-aed5-8c9d20b8857a','哭容倅舅氏二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','尚記陪言笑，如今叫不譍。',48,'全唐诗/poet.song.197000.json','["尚記陪言笑，如今叫不譍。", "兒分身後俸，僧上殯前燈。", "宅有遺基在，田無一畝增。", "問天何至此，在日以廉稱。"]'),
('d1e726d4-a03e-4430-be6e-864ff4bf821c','吳大帝廟','劉克莊','宋','宋诗','song-poetry','','[]','露坐空山裏，英靈喚不迴。',48,'全唐诗/poet.song.197000.json','["露坐空山裏，英靈喚不迴。", "久無祠祭至，曾作帝王來。", "壞壁蟲傷畫，殘爐鼠印灰。", "今人渾忘却，江左是誰開。"]'),
('4d5896ca-d81f-4d9b-b4d3-9de375549739','鐵塔寺','劉克莊','宋','宋诗','song-poetry','','[]','細認苔間字，方知鑄塔時。',48,'全唐诗/poet.song.197000.json','["細認苔間字，方知鑄塔時。", "不因兵廢壞，似有物扶持。", "古殿人開少，深窗日上遲。", "僧言明受事，相對各攢眉。"]'),
('f4c0fc38-8c4d-43ed-9805-39e19407bb7e','聰老','劉克莊','宋','宋诗','song-poetry','','[]','聰老才堪將，髠緇意未平。',48,'全唐诗/poet.song.197000.json','["聰老才堪將，髠緇意未平。", "僧中能結客，禪外又談兵。", "喜聽詩家話，多知虜地情。", "何當長鬚髮，遣戍國西營。"]'),
('db3afd4b-e5b0-42a1-9877-6e1d7719d60f','哭薛子舒二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','醫自金壇至，猶言疾可爲。',48,'全唐诗/poet.song.197000.json','["醫自金壇至，猶言疾可爲。", "瀕危人未信，聞死世皆疑。", "友共收殘藁，妻能讀殮儀。", "借來書冊子，掩淚付孤兒。"]'),
('413e569e-9d7f-430a-9cf9-1681c0793f0c','哭薛子舒二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','忍死教磨墨，留書訣父兄。',48,'全唐诗/poet.song.197000.json','["忍死教磨墨，留書訣父兄。", "讀來堪下淚，寄去怕傷情。", "墓要師爲誌，詩於世有名。", "夜闌秋枕上，猶夢共山行。"]'),
('f07a047a-a064-44ee-9735-cd55cdf5d2ea','贈川郭','劉克莊','宋','宋诗','song-poetry','','[]','川郭顛狂甚，平生挾術游。',48,'全唐诗/poet.song.197000.json','["川郭顛狂甚，平生挾術游。", "老猶携侍女，貧不諂公侯。", "用藥多投病，酬錢或掉頭。", "金陵官酒貴，應典舊貂裘。"]'),
('9330f9c4-694d-42d0-98dd-3642a50f8f96','贈錢道人','劉克莊','宋','宋诗','song-poetry','','[]','除了布裘外，都無物自隨。',48,'全唐诗/poet.song.197000.json','["除了布裘外，都無物自隨。", "跣能行大雪，饑但嚥華池。", "說相言多驗，嫌錢事更奇。", "一般難曉處，裝背貴人詩。"]'),
('58c9589e-60e8-48c4-9c20-9af7f3339573','張麗華墓','劉克莊','宋','宋诗','song-poetry','','[]','臺上柏蕭蕭，空堂閉寂寥。',48,'全唐诗/poet.song.197000.json','["臺上柏蕭蕭，空堂閉寂寥。", "芳魂三尺土，往事幾迴潮。", "墮翠尋難見，埋紅恨未銷。", "猶勝江令在，白首入隋朝。"]'),
('ed796432-de1b-4680-9698-be6f41b0357f','送鄒景仁','劉克莊','宋','宋诗','song-poetry','','[]','衝寒何處去，新戍尚來年。',48,'全唐诗/poet.song.197000.json','["衝寒何處去，新戍尚來年。", "客勸休辭幙，君言已買船。", "霜清江有蟹，葉脫木無蟬。", "若過東林寺，携家往問禪。"]'),
('556c21f7-bef2-41af-8117-d48ed9f4b72d','二將','劉克莊','宋','宋诗','song-poetry','','[]','二將同時死，路人聞亦哀。',48,'全唐诗/poet.song.197000.json','["二將同時死，路人聞亦哀。", "力窮鏖轉急，圍厚突難開。", "戰骨尋應在，殘兵間有迴。", "傷心郵遞裏，隔日捷書來。"]'),
('7a5ece41-b762-4a44-811d-e660ef59e4a9','陳虛一','劉克莊','宋','宋诗','song-poetry','','[]','幾載皖山耕，忽提孤劍行。',48,'全唐诗/poet.song.197000.json','["幾載皖山耕，忽提孤劍行。", "戰場中有骨，尺籍上無名。", "馬自尋歸路，身空試賊營。", "却疑兵解去，曾說鍊丹成。"]'),
('79fa465b-952e-4aba-824e-6d78880840d8','揚州作','劉克莊','宋','宋诗','song-poetry','','[]','幾多精甲沒黄沙，野哭遥憐戰士家。',64,'全唐诗/poet.song.197000.json','["幾多精甲沒黄沙，野哭遥憐戰士家。", "瓜渡月明空粉堞，蕪城煙斷只昏鴉。", "似聞漢使攽王醢，尚喜胡兒剖帝羓。", "怊悵兩淮蠶織地，春風不復長桑芽。"]'),
('1b4a9aca-10bd-458b-985e-9b8064c5f922','南浦亭寄所思','劉克莊','宋','宋诗','song-poetry','','[]','只是從前瘦病身，官卑活計大清貧。',64,'全唐诗/poet.song.197000.json','["只是從前瘦病身，官卑活計大清貧。", "買來晉帖多成贋，吟得唐詩轉逼真。", "生擬棄家尋劍客，死當移冢近騷人。", "秋風爛熳吹雙鬢，目送停雲欲愴神。"]'),
('aff6d973-63c5-4f29-93cc-d278e7fa19fd','蒜嶺夜行','劉克莊','宋','宋诗','song-poetry','','[]','嶺頭無復一人來，漁店收燈戶不開。',64,'全唐诗/poet.song.197000.json','["嶺頭無復一人來，漁店收燈戶不開。", "松氣滿山涼似雨，海聲中夜近如雷。", "擬披醉髮橫簫去，只寄鄉書與劍迴。", "他日有人傳肘後，尚堪收拾作詩材。"]'),
('24287445-0154-4d56-9f71-3ac6acdf7cd8','別敖器之','劉克莊','宋','宋诗','song-poetry','','[]','舊說閩人苦節稀，先生獨抱歲寒姿。',64,'全唐诗/poet.song.197000.json','["舊說閩人苦節稀，先生獨抱歲寒姿。", "老年絳帳聊開講，當日烏臺要勘詩。", "東閤不游緣有氣，草堂未架爲無貲。", "輕煙小雪孤山路，折賸梅花寄一枝。"]'),
('2e17c425-a099-4d0e-b1ed-2d1da1c32078','哭楊吏部通老','劉克莊','宋','宋诗','song-poetry','','[]','白首除郎已晚哉，民間桑柘手親栽。',64,'全唐诗/poet.song.197000.json','["白首除郎已晚哉，民間桑柘手親栽。", "蓋棺只著深衣去，行李空擔語錄迴。", "主祭遺孤猶未冠，著書殘藁漫成堆。", "可憐薄命飄蓬客，虛事江西莫府來。"]'),
('0f3dfc49-27c3-4aa8-8faf-a2f042dc4534','老歎','劉克莊','宋','宋诗','song-poetry','','[]','肘後奇書懶更開，只今年鬢已相催。',64,'全唐诗/poet.song.197000.json','["肘後奇書懶更開，只今年鬢已相催。", "但聞方士騰空去，不見童男入海迴。", "無藥能留炎帝在，有人曾哭老聃來。", "醉鄉一路差堪向，終擬劉伶冢畔埋。"]'),
('0f5d9349-1b02-4e5d-9e2b-5cfed891daf9','答友生','劉克莊','宋','宋诗','song-poetry','','[]','讀易參禪事事奇，高情已恨挂冠遲。',64,'全唐诗/poet.song.197000.json','["讀易參禪事事奇，高情已恨挂冠遲。", "清於楚客滋蘭日，貧似唐人乞米時。", "家爲買琴添舊債，厨因養鶴減晨炊。", "君看江表英雄傳，何似孤山一卷詩。"]'),
('a6c39f2e-f1b9-4aef-b5c9-03a835a12e44','趙清獻墓','劉克莊','宋','宋诗','song-poetry','','[]','南渡先賢迹已稀，蕭然華表立山陂。',64,'全唐诗/poet.song.197000.json','["南渡先賢迹已稀，蕭然華表立山陂。", "可曾長吏修祠宇，便恐樵人落樹枝。", "幾度過墳偏下馬，向來出蜀只携龜。", "自憐日暮天寒客，不到林間讀隧碑。"]'),
('5d4fd6d7-03bd-406c-812e-b58707331acf','烏石山','劉克莊','宋','宋诗','song-poetry','','[]','客子家山亦此峯，可堪投宿聽疎鐘。',64,'全唐诗/poet.song.197000.json','["客子家山亦此峯，可堪投宿聽疎鐘。", "旋沽村酒開霜柿，欲訪禪扉隔暮松。", "鄉信寫成無便寄，寒衣著綻倩人縫。", "遠來只爲營瓜圃，不是貪渠萬戶封。"]'),
('326e9645-72ed-4271-930f-96fcceaaa7e6','除夕','劉克莊','宋','宋诗','song-poetry','','[]','憶昔都城值歲除，高樓張燭戲呼盧。',64,'全唐诗/poet.song.197000.json','["憶昔都城值歲除，高樓張燭戲呼盧。", "久依凈社參尊宿，難向新豐認酒徒。", "天子未知工草賦，鄰人或倩寫桃符。", "夜寒別有窮生活，點勘離騷擁地爐。"]'),
('8801c1e9-19a9-41d0-a76b-618f131a73bc','呈袁祕監','劉克莊','宋','宋诗','song-poetry','','[]','近日頻聞有峻除，人傳君相重師儒。',64,'全唐诗/poet.song.197000.json','["近日頻聞有峻除，人傳君相重師儒。", "細旃坐穩方輪講，羣玉峯高未要扶。", "別後曾過東閤否，新來亦乞鑑湖無。", "幾時供帳都門外，真寫先生作畫圖。"]'),
('35a5ba21-9301-422c-9a00-8f01d282038c','漁梁','劉克莊','宋','宋诗','song-poetry','','[]','春泥滑滑雨絲絲，一路陰寒少霽時。',64,'全唐诗/poet.song.197000.json','["春泥滑滑雨絲絲，一路陰寒少霽時。", "水入陂渠喧似瀑，雲從山崦上如炊。", "燎衣去傍田家火，炙燭來看野店詩。", "落盡梅花心事惡，獨搔蓬鬢遶殘枝。"]'),
('c2b4e089-622e-450a-8ece-a27b9eca5d8b','小梓人家','劉克莊','宋','宋诗','song-poetry','','[]','生來拙性嗜清幽，因過山家爲小留。',64,'全唐诗/poet.song.197000.json','["生來拙性嗜清幽，因過山家爲小留。", "頂笠兒歸行樹杪，提瓶婦去汲溪頭。", "參天老竹當門碧，盡日寒泉遶舍流。", "我料草堂猶未架，規模已被野人偷。"]'),
('e199d60d-d273-4cf4-8d1a-fefb039fb633','送拄杖還僧','劉克莊','宋','宋诗','song-poetry','','[]','頭白高僧行脚嬾，一枝筇竹久生苔。',64,'全唐诗/poet.song.197000.json','["頭白高僧行脚嬾，一枝筇竹久生苔。", "不逢太乙然藜照，時借山翁荷蓧廻。", "夜挂多尋蕭寺壁，曉拈恐化葛陂雷。", "還師此物禪須進，曾入詩人手內來。"]'),
('06997777-32b1-49e0-9605-b555629a13fc','雪峰寺','劉克莊','宋','宋诗','song-poetry','','[]','七里深林集暮鴉，插空金碧被林遮。',64,'全唐诗/poet.song.197000.json','["七里深林集暮鴉，插空金碧被林遮。", "華堂何止容千衲，菜地猶堪置萬家。", "虎去有靈知伏弩，僧來敘舊約分茶。", "世人要識峯頭冷，六月重綿坐結跏。"]'),
('8b744843-bca8-4d5e-8dd7-45b4e89d47ee','蓋竹廟','劉克莊','宋','宋诗','song-poetry','','[]','借榻叢祠日已曛，瓣香頻此謁靈君。',64,'全唐诗/poet.song.197000.json','["借榻叢祠日已曛，瓣香頻此謁靈君。", "儻來夢事休重卜，向去詩材進幾分。", "明主不消人諫獵，故山空使客移文。", "寄書報與荆妻說，十襲荷衣莫要焚。"]'),
('da6e44e5-2d2c-44a1-af2a-f98c1cf12df9','瓜洲城','劉克莊','宋','宋诗','song-poetry','','[]','先朝築此要防邊，不遣胡兒見戰船。',64,'全唐诗/poet.song.197000.json','["先朝築此要防邊，不遣胡兒見戰船。", "遮斷難傳河朔檄，修來大費水衡錢。", "書生空抱聞雞志，故老能言飲馬年。", "慙愧戍兵身手健，箔樓各占一間眠。"]'),
('be421ed4-0b7d-45bb-9285-15fa10c1387e','送仲白','劉克莊','宋','宋诗','song-poetry','','[]','官舍蕭條葦蓋簷，拾薪獨有一長髯。',64,'全唐诗/poet.song.197000.json','["官舍蕭條葦蓋簷，拾薪獨有一長髯。", "同來社友因饑瘦，遠作參軍得俸廉。", "國士交情窮乃見，古人詩律晚方嚴。", "中年各要身强健，別後寒衣切記添。"]'),
('0075daf7-839a-4630-a9f2-e9d51e2611b4','鳳凰臺晚眺','劉克莊','宋','宋诗','song-poetry','','[]','經月疎行臺上路，秣陵城郭忽秋風。',64,'全唐诗/poet.song.197000.json','["經月疎行臺上路，秣陵城郭忽秋風。", "馬嘶衛霍空營裏，螢起齊梁廢苑中。", "野寺舊曾開玉帳，翠華久不幸離宮。", "小儒記得隆興事，閑對山僧說魏公。"]'),
('2eaa15f7-d018-4d93-8c4f-184c68b833ee','贈玉隆劉道士','劉克莊','宋','宋诗','song-poetry','','[]','觀中曾訪老黄冠，爾尚爲童立醮壇。',64,'全唐诗/poet.song.197000.json','["觀中曾訪老黄冠，爾尚爲童立醮壇。", "新染氅衣披得稱，舊泥丹竈出來寒。", "詩非易作須勤讀，琴亦難精莫廢彈。", "憶上洪崖題瀑布，因游試爲拂塵看。"]'),
('691abd42-0696-47d6-ac78-12704033c4a3','晉元帝廟','劉克莊','宋','宋诗','song-poetry','','[]','元帝新祠西郭外，野人吊古獨來遊。',64,'全唐诗/poet.song.197000.json','["元帝新祠西郭外，野人吊古獨來遊。", "陰陰畫壁開冠劍，寂寂絲窠上璪旒。", "勢比龍盤猶在眼，事隨鴻去不迴頭。", "葉碑廊下無人看，欲去摩挲又少留。"]'),
('895352df-a8c4-46fb-9a8a-20dc5cdb6ccf','清凉寺','劉克莊','宋','宋诗','song-poetry','','[]','塔廟當年甲一方，千層金碧萬緇郎。',64,'全唐诗/poet.song.197000.json','["塔廟當年甲一方，千層金碧萬緇郎。", "開山佛已成胡鬼，住院僧猶說李王。", "遺像有塵龕壞壁，斷碑無首立斜陽。", "惟應駐馬坡頭月，曾見金輿夜納凉。"]'),
('d397e7e4-f598-4a48-b782-012b38384337','冶城','劉克莊','宋','宋诗','song-poetry','','[]','斷鏃遺鎗不可求，西風古意滿原頭。',64,'全唐诗/poet.song.197000.json','["斷鏃遺鎗不可求，西風古意滿原頭。", "孫劉數子如春夢，王謝千年有舊遊。", "高塔不知何代作，暮笳似說昔人愁。", "神州只在闌干北，度度來時怕上樓。"]'),
('8ee028f3-0ba5-4d43-ad22-a12eef75408f','雨華臺','劉克莊','宋','宋诗','song-poetry','','[]','昔日講師何處在，高臺猶以雨華名。',64,'全唐诗/poet.song.197000.json','["昔日講師何處在，高臺猶以雨華名。", "有時寶向泥尋得，一片山無草敢生。", "落日磬殘鄰寺閉，晴天牛上廢陵耕。", "登臨不用深懷古，君看鍾山幾箇爭。"]'),
('4b585e04-ec10-4775-89f4-bc01f4639f7a','新亭','劉克莊','宋','宋诗','song-poetry','','[]','此是晉人遊集處，當時風景與今同。',64,'全唐诗/poet.song.197000.json','["此是晉人遊集處，當時風景與今同。", "不干鐵鏁樓船力，似是蒲葵麈柄功。", "幾簇旌旗秋色裏，百年陵闕淚痕中。", "興亡畢竟緣何事，專罪清談恐未公。"]'),
('10c99f25-8100-422b-bdd9-1cd8fb7a6d1a','魏勝廟','劉克莊','宋','宋诗','song-poetry','','[]','天與精忠不與時，堂堂心在路人悲。',64,'全唐诗/poet.song.197000.json','["天與精忠不與時，堂堂心在路人悲。", "龍顔帝子方推轂，猨臂將軍忽死綏。", "灑泣我來瞻畫像，斷頭公耻立降旗。", "海州故老凋零盡，重見王師定幾時。"]'),
('26f630c1-cbc6-4d33-b763-6de46054b88a','真州北山','劉克莊','宋','宋诗','song-poetry','','[]','憶昔胡兒入控弦，官軍迎戰北山邊。',64,'全唐诗/poet.song.197000.json','["憶昔胡兒入控弦，官軍迎戰北山邊。", "笳簫有主安新葬，蓑笠無人墾廢田。", "兵散荒營吹戍笛，僧從敗屋起茶煙。", "遥憐鍾阜諸峯好，閑鎖行宮九十年。"]'),
('430515a1-12a7-4388-b708-4ebe733e34d2','故宅','劉克莊','宋','宋诗','song-poetry','','[]','恰則炎炎未百年，今看枯柳著疎蟬。',64,'全唐诗/poet.song.197000.json','["恰則炎炎未百年，今看枯柳著疎蟬。", "莊田置後頻移主，書畫殘來亦賣錢。", "春日有花開廢圃，歲時無酒滴荒阡。", "朱門從古多如此，想見魂歸也愴然。"]'),
('a2eb84dc-09f2-4db8-91b8-b78abd106f0b','送余子壽','劉克莊','宋','宋诗','song-poetry','','[]','去歲與君同聘召，何曾杯酒暫相離。',64,'全唐诗/poet.song.197000.json','["去歲與君同聘召，何曾杯酒暫相離。", "兵謀元帥多親訪，心事同官盡得知。", "三釜忽懷歸去檄，一枰未了著殘棋。", "此生聚散須牢記，記上揚州戰艦時。"]'),
('45715d57-df5a-4fe9-80a9-e91a4a1a3ff9','送周監門','劉克莊','宋','宋诗','song-poetry','','[]','一領青衫似敗荷，奈君母老秩卑何。',64,'全唐诗/poet.song.197000.json','["一領青衫似敗荷，奈君母老秩卑何。", "三年幕府無人薦，常日柴門有客過。", "身畔擔輕藏俸少，江頭船重載書多。", "故人若問軍中事，爲說防秋夜枕戈。"]'),
('040f4a64-835a-4cb7-962c-73a2069a54fe','挽黄巖趙郎中二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','朱公徒弟丘公壻，標致雖高氣宇和。',64,'全唐诗/poet.song.197000.json','["朱公徒弟丘公壻，標致雖高氣宇和。", "心向奏篇尤暴白，髮因時事欲蒼皤。", "訃傳淮甸邊情惜，路出蕭山巷祭多。", "最長郎君師友盛，我知墓碣有人磨。"]'),
('f028dd4e-f5ab-4fe5-af21-f2a15bc456d9','挽黄巖趙郎中二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','青衫昔作督郵時，賞鑒除公更有誰。',64,'全唐诗/poet.song.197000.json','["青衫昔作督郵時，賞鑒除公更有誰。", "勘獄不嫌人守法，撰文常對衆稱奇。", "築臺虛辱生前意，穿冢難酬地下知。", "欲寫哀思傳挽者，身今戎服不能詩。"]'),
('314293f5-621d-4a66-9663-30b867b4a8c6','寄趙昌父','劉克莊','宋','宋诗','song-poetry','','["\u8861\u5c71"]','世上久無遺逸禮，此翁白首不彈冠。',64,'全唐诗/poet.song.197000.json','["世上久無遺逸禮，此翁白首不彈冠。", "一生官職監南嶽，四海詩盟主玉山。", "經歲著書人少見，有時入郭俗爭看。", "何因樵服供薪水，得附高名野史間。"]'),
('d7e9df98-a7f5-4add-91b5-0a179d89fdf1','寄韓仲止','劉克莊','宋','宋诗','song-poetry','','[]','昨仕京華豪未減，脫鞾不問貴游嗔。',64,'全唐诗/poet.song.197000.json','["昨仕京華豪未減，脫鞾不問貴游嗔。", "詩家爭欲推盟主，丞相差教作散人。", "閉戶自爲千載計，入山又忍十年貧。", "幾思投劾從公去，背笈肩琴澗水濱。"]'),
('d37eaf07-51b9-4caf-8087-875c28000c95','戊辰書事','劉克莊','宋','宋诗','song-poetry','','["\u897f\u6e56"]','詩人安得有春衫，今歲和戎百萬縑。',32,'全唐诗/poet.song.197000.json','["詩人安得有春衫，今歲和戎百萬縑。", "從此西湖休插柳，剩栽桑樹養吳蠶。"]'),
('9331843d-fa3d-4ee7-86ae-9f142ed1da69','晚春','劉克莊','宋','宋诗','song-poetry','','[]','書幌泠泠子夜風，杜鵑啼月小牆東。',32,'全唐诗/poet.song.197000.json','["書幌泠泠子夜風，杜鵑啼月小牆東。", "江南詞客惜春老，清曉披衣拾墮紅。"]'),
('88da56db-4660-4db6-814a-21e827c12bf8','臨溪寺二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','綠染庭蕪一尺深，老師閲世幾駒陰。',32,'全唐诗/poet.song.197000.json','["綠染庭蕪一尺深，老師閲世幾駒陰。", "自言不看傳燈了，只讀楞嚴見佛心。"]'),
('84055cd5-35cd-4cea-83f3-2c4a85c3e24b','臨溪寺二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','一徑松花颭紫苔，東風落盡佛前梅。',32,'全唐诗/poet.song.197000.json','["一徑松花颭紫苔，東風落盡佛前梅。", "道人深掩禪關坐，莫聽鶑聲出定來。"]'),
('d3318246-649b-41bb-b2a8-f26a197a717e','即事','劉克莊','宋','宋诗','song-poetry','','[]','自汲新泉養牡丹，銀壺滿貯怕春殘。',32,'全唐诗/poet.song.197000.json','["自汲新泉養牡丹，銀壺滿貯怕春殘。", "畫簷一餉東風惡，爲掩窗綃護晚寒。"]'),
('51766e60-d718-4a2a-9376-d0b2bfe2ab5b','孺子祠','劉克莊','宋','宋诗','song-poetry','','[]','孺子祠堂插酒旗，游人那解薦江蘺。',32,'全唐诗/poet.song.197000.json','["孺子祠堂插酒旗，游人那解薦江蘺。", "白鷗欲下還驚起，曾見陳蕃解榻時。"]'),
('515b003d-10fd-4cad-88f8-b9a875f1e901','碧波亭','劉克莊','宋','宋诗','song-poetry','','[]','了却文書上馬遲，白蘋洲畔有心期。',32,'全唐诗/poet.song.197000.json','["了却文書上馬遲，白蘋洲畔有心期。", "斜陽忽到傳觴處，落盡梨花啼子規。"]'),
('b4d43324-2efb-4b10-8f8f-ab1fb89df8a6','豫章溝二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','溝水泠泠草樹香，獨穿支徑入垂楊。',32,'全唐诗/poet.song.197000.json','["溝水泠泠草樹香，獨穿支徑入垂楊。", "薺花滿地無人見，唯有山蜂度短牆。"]'),
('0fc5035d-bc18-4ad3-a433-4d7326e9d878','豫章溝二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','野店蕭蕭掩竹門，岸沙猶記履綦痕。',32,'全唐诗/poet.song.197000.json','["野店蕭蕭掩竹門，岸沙猶記履綦痕。", "東風枉是吹花急，綠盡平蕪却斷魂。"]'),
('3d13b1f8-97e0-4cba-b2f4-715c7eebccdd','題寺壁二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','柏子熏衣眉暈銷，女垣榆影冷蕭蕭。',32,'全唐诗/poet.song.197000.json','["柏子熏衣眉暈銷，女垣榆影冷蕭蕭。", "屏山一枕游方夢，橫錫飄然過石橋。"]'),
('12dbce0a-79b3-4b82-9a6c-4cc9deffd59b','題寺壁二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','素練寬裁白社衣，普陀煙裏現幽姿。',32,'全唐诗/poet.song.197000.json','["素練寬裁白社衣，普陀煙裏現幽姿。", "日長讀徹楞伽了，閑折柑花供祖師。"]'),
('7c40acaf-c9c3-4b84-b4d0-ffcb164eee19','西山','劉克莊','宋','宋诗','song-poetry','','[]','絕頂遥知有隠君，餐芝種朮鹿爲羣。',32,'全唐诗/poet.song.197000.json','["絕頂遥知有隠君，餐芝種朮鹿爲羣。", "多應午竈茶煙起，山下看來是白雲。"]'),
('e046a7e5-ae8e-4921-bb51-76c7e28d7e30','宮詞四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','出海新蟾玉半鈎，風翻荷蕩起栖鷗。',32,'全唐诗/poet.song.197000.json','["出海新蟾玉半鈎，風翻荷蕩起栖鷗。", "女郎定有穿針約，偷看明河記立秋。"]'),
('4eb5ffae-0818-4ab1-8dc1-9f5c9facef2a','宮詞四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','涼殿吹笙露滿天，木犀花發月初圓。',32,'全唐诗/poet.song.197000.json','["涼殿吹笙露滿天，木犀花發月初圓。", "君王少御珊瑚枕，多就宮人玉臂眠。"]'),
('0212a0d6-5def-413e-9b26-60ef8cfd04a1','宮詞四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','一夜秋風入碧梧，蟬聲永巷月華孤。',32,'全唐诗/poet.song.197000.json','["一夜秋風入碧梧，蟬聲永巷月華孤。", "幾回夢裏羊車過，又是銀牀轉轆轤。"]'),
('421f7774-b73c-40d1-9193-b35fa1e58281','宮詞四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','先帝宮人總道粧，遥瞻陵柏淚成行。',32,'全唐诗/poet.song.197000.json','["先帝宮人總道粧，遥瞻陵柏淚成行。", "舊恩恰似薔薇水，滴在羅衣到死香。"]'),
('305077b9-4b05-4b14-a0f3-bb439045788f','秋風','劉克莊','宋','宋诗','song-poetry','','[]','黄葉蕭蕭忽滿街，獨騎瘦馬豫章臺。',32,'全唐诗/poet.song.197000.json','["黄葉蕭蕭忽滿街，獨騎瘦馬豫章臺。", "莫將宋玉心中事，吹向潘郎鬢畔來。"]'),
('dcb48831-65d9-4ff2-9f6f-2ef588d9ceec','跋小寺舊題','劉克莊','宋','宋诗','song-poetry','','[]','禪几曾陪白氎巾，柑花似雪鬭芳新。',32,'全唐诗/poet.song.197000.json','["禪几曾陪白氎巾，柑花似雪鬭芳新。", "而今柑子圓如彈，不見澆花供佛人。"]'),
('98139d1f-41f9-40af-94d1-b7ecb4c86805','憶殤女','劉克莊','宋','宋诗','song-poetry','','[]','靈照覊魂章水西，冷風殘雪古招提。',32,'全唐诗/poet.song.197000.json','["靈照覊魂章水西，冷風殘雪古招提。", "老懷已作空花看，更把楞嚴曉病妻。"]'),
('bce96b33-0605-46b1-b76e-cbc371bcbb2d','報恩寺','劉克莊','宋','宋诗','song-poetry','','[]','一抹斜陽上繚垣，芫花滿地柏陰繁。',32,'全唐诗/poet.song.197000.json','["一抹斜陽上繚垣，芫花滿地柏陰繁。", "城中客子聞鐘去，獨立空山聽斷猿。"]'),
('365aee98-7ffa-4b08-97e3-e94ebf3478d8','歸至武陽渡作','劉克莊','宋','宋诗','song-poetry','','[]','夾岸盲風掃楝花，高城已近被雲遮。',32,'全唐诗/poet.song.197000.json','["夾岸盲風掃楝花，高城已近被雲遮。", "遮時留取城西塔，篷底歸人要認家。"]'),
('6a12a029-0666-45ba-8e8c-646ffc4c88bb','舟中寄景建','劉克莊','宋','宋诗','song-poetry','','[]','低篷小雨夢殘時，忽憶同尋楚老祠。',32,'全唐诗/poet.song.197000.json','["低篷小雨夢殘時，忽憶同尋楚老祠。", "夜過豐城占斗氣，想公別後有新詩。"]'),
('137df028-a323-41bb-ab74-7dbea5e4bf36','書山壁','劉克莊','宋','宋诗','song-poetry','','[]','斸地栽林自起墳，一燈精舍疏玄文。',32,'全唐诗/poet.song.197000.json','["斸地栽林自起墳，一燈精舍疏玄文。", "詩成莫洒酒家壁，題徧青山題白雲。"]'),
('9f1fa0a9-b798-4a0d-a420-9c6197fc8f21','華嚴寺逢舊蒼頭','劉克莊','宋','宋诗','song-poetry','','[]','曾向叢林寄幅巾，十年塵涴卧雲身。',32,'全唐诗/poet.song.197000.json','["曾向叢林寄幅巾，十年塵涴卧雲身。", "侍琴童子長於竹，去禮山僧作主人。"]'),
('81e58ac8-e315-40af-a618-63b88bb0cc99','田舍','劉克莊','宋','宋诗','song-poetry','','[]','稚子呼牛女拾薪，萊妻自鱠小溪鱗。',32,'全唐诗/poet.song.197000.json','["稚子呼牛女拾薪，萊妻自鱠小溪鱗。", "安知曝背庭中老，不是淵明輩行人。"]'),
('357606b8-8acf-4980-bbfc-37c9372246c9','古墓','劉克莊','宋','宋诗','song-poetry','','[]','石麟闕耳筍生苔，要讀豐碑與客來。',32,'全唐诗/poet.song.197000.json','["石麟闕耳筍生苔，要讀豐碑與客來。", "精舍荒涼僧已出，瓦牆一朵佛桑開。"]'),
('a79bd251-73cc-4985-bf8b-52b25cc81836','題本草','劉克莊','宋','宋诗','song-poetry','','[]','勤讀方書不爲身，里中耆舊半成塵。',32,'全唐诗/poet.song.197000.json','["勤讀方書不爲身，里中耆舊半成塵。", "幾時作箇荒山主，多種黄精售與人。"]'),
('ad23f6e0-db46-4780-b6d1-d525e756dfde','下蜀驛','劉克莊','宋','宋诗','song-poetry','','[]','幄殿荒涼屋欠扶，紹興遺老故應無。',32,'全唐诗/poet.song.197000.json','["幄殿荒涼屋欠扶，紹興遺老故應無。", "舊來曾識高皇帝，尚有庭前柳一株。"]'),
('8733a650-3a80-4b76-a6e9-8ee3df7da619','出郭','劉克莊','宋','宋诗','song-poetry','','[]','江邊一雨洗秋容，北郭東郊野意濃。',32,'全唐诗/poet.song.197000.json','["江邊一雨洗秋容，北郭東郊野意濃。", "老大怕它人檢點，隔溪隔柳看芙蓉。"]'),
('1d654911-e9f8-4461-a801-7c573829e7d5','病起','劉克莊','宋','宋诗','song-poetry','','[]','病起登樓怯曉風，愛他殘雪映前峯。',32,'全唐诗/poet.song.197000.json','["病起登樓怯曉風，愛他殘雪映前峯。", "傍人休問何郎瘦，不見梅花過一冬。"]'),
('38ad1d1f-e4c6-450a-a7e8-b73a8f705838','再贈錢道人二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','拙貌慙君子細看，鏡中我自覺神寒。',32,'全唐诗/poet.song.197000.json','["拙貌慙君子細看，鏡中我自覺神寒。", "直從杜甫編排起，幾箇吟人作大官。"]'),
('cf8bea8c-c818-4f2a-aee6-6feb8d811341','再贈錢道人二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','尋師入蜀未曾逢，要看羅浮曉日紅。',32,'全唐诗/poet.song.197000.json','["尋師入蜀未曾逢，要看羅浮曉日紅。", "若見仙人知去處，却來相引到山中。"]'),
('ce88d8b3-b6db-42a2-8e58-b432433ffdcf','蒙恩監南嶽廟','劉克莊','宋','宋诗','song-poetry','','["\u8861\u5c71"]','久問嫖姚乞退閑，今朝準敕放生還。',64,'全唐诗/poet.song.197000.json','["久問嫖姚乞退閑，今朝準敕放生還。", "人欺解罷青油幕，帝遣監臨紫蓋山。", "營卒展辭回玉帳，林僧講賀到柴關。", "丈夫不辦封侯事，猶要名標處士間。"]'),
('7c83bab8-0f2b-4753-9f25-6dcbc63e9b0c','烏石山','劉克莊','宋','宋诗','song-poetry','','[]','兒時逃學頻來此，一一重尋盡有蹤。',64,'全唐诗/poet.song.197000.json','["兒時逃學頻來此，一一重尋盡有蹤。", "因漉戲魚羣下水，緣敲響石鬭登峯。", "熟知舊事惟鄰叟，催去韶華是暮鍾。", "畢竟世間何物壽，寺前雷仆百年松。"]'),
('4d0e8de3-83d3-4bfa-9b9b-f21c844a2ba3','葺居一首','劉克莊','宋','宋诗','song-poetry','','[]','兵火間關鬢欲絲，歸來聊卜草堂基。',64,'全唐诗/poet.song.197000.json','["兵火間關鬢欲絲，歸來聊卜草堂基。", "架留手澤書堪看，爨有躬耕米可炊。", "畏濕先開通水竇，貪明稍斫近簷枝。", "旋移梅樹臨窗下，準備花時要索詩。"]'),
('064b5fac-8b5a-496f-a098-d75700510ebb','挽郭處士','劉克莊','宋','宋诗','song-poetry','','[]','昔聞東郭先生者，處士寧非是遠孫。',64,'全唐诗/poet.song.197000.json','["昔聞東郭先生者，處士寧非是遠孫。", "空有新詩喧一邑，竟無明詔老孤村。", "雷琴酷愛應同殉，草字尤工惜不存。", "復說歸從葱嶺去，騷成何路可招魂。"]'),
('fcb6304b-81e6-4f73-808c-3b72980824b9','老將一首','劉克莊','宋','宋诗','song-poetry','','[]','昨解兵符歸故里，耳聽邊事幾番新。',64,'全唐诗/poet.song.197000.json','["昨解兵符歸故里，耳聽邊事幾番新。", "偶逢戲下來猶識，欲說遼陽記不真。", "兒覓寶刀偏愛惜，奴吹蘆管輒悲辛。", "夜寒忽作關山夢，萬一君王起舊人。"]'),
('30d7ee29-5074-40a7-a16c-0bcdafb0dce5','老馬一首','劉克莊','宋','宋诗','song-poetry','','[]','脊瘡蹄蹇瘦闌干，火印年深字已漫。',64,'全唐诗/poet.song.197000.json','["脊瘡蹄蹇瘦闌干，火印年深字已漫。", "野磵有冰朝洗怯，破坊無壁夜嘶寒。", "身同退卒支殘料，眼見新駒鞁寶鞍。", "昔走塞垣如抹電，安知末路出門難。"]'),
('08fb221b-ab55-425b-98ed-ab71fe61ef70','老妓一首','劉克莊','宋','宋诗','song-poetry','','[]','籍中歌舞昔馳聲，憔悴猶存態與情。',64,'全唐诗/poet.song.197000.json','["籍中歌舞昔馳聲，憔悴猶存態與情。", "愛說舊官當日寵，偏呼狎客小時名。", "薄鬟易脫梳難就，半被常空睡不成。", "却羨鄰姬門戶熱，隔樓張燭到天明。"]'),
('7e8c0704-e4e9-461b-8a50-ce2e1a7e46f0','挽趙仲白二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','生被才名譴，摧殘到死休。',48,'全唐诗/poet.song.197000.json','["生被才名譴，摧殘到死休。", "家留遺藁在，棺問故人求。", "對月悲孤詠，逢山憶共遊。", "昔年携手地，今送入松楸。"]'),
('6e9c9400-9044-422e-9507-3b1e311d6da6','挽趙仲白二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','昨吊寢門外，萊妻泣最悲。',48,'全唐诗/poet.song.197000.json','["昨吊寢門外，萊妻泣最悲。", "因言兒上學，復爲墓求碑。", "零落燒丹訣，淒涼哭鶴詩。", "託孤朋友事，非謂九泉知。"]'),
('84da1290-da34-43bb-8708-f433da458721','贈風水僧','劉克莊','宋','宋诗','song-poetry','','[]','向人說葬又談空，郭璞瞿曇併入宗。',64,'全唐诗/poet.song.197000.json','["向人說葬又談空，郭璞瞿曇併入宗。", "背得山經如誦呪，頂將禪笠去尋龍。", "徧爲檀越裁生壙，預定公侯出某峯。", "想亦自營歸寂處，一丘卵塔種青松。"]'),
('4062afbf-9f0e-4caf-ac50-70e7cfd68878','挽鄭夫人二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','九秩復何憾，生榮沒更哀。',48,'全唐诗/poet.song.197000.json','["九秩復何憾，生榮沒更哀。", "閨門天下則，地位佛中來。", "貝葉從頭看，庭槐一手栽。", "侍兒聞曉磬，猶恐坐禪迴。"]'),
('6242bcd7-431d-42fd-84f1-1b18896139a9','挽鄭夫人二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','昔事征西幕，年年拜壽闈。',48,'全唐诗/poet.song.197000.json','["昔事征西幕，年年拜壽闈。", "那知丹旐至，曾勸板輿歸。", "元帥拋金印，諸生返布衣。", "感恩惟有淚，來向路傍揮。"]'),
('4c5eb84d-8178-4238-82b6-51800424d3a8','除夕','劉克莊','宋','宋诗','song-poetry','','[]','除夕陰寒怕卷簾，雨聲斷續下疎簷。',64,'全唐诗/poet.song.197000.json','["除夕陰寒怕卷簾，雨聲斷續下疎簷。", "壁穿自和乾泥補，窗損教尋廢紙粘。", "祇有青燈相守定，縱無白髮亦生添。", "更殘自算明年事，不就君平卦肆占。"]'),
('3bb44bd2-3b32-4086-8b49-462d5a293cd5','挽鄭淑人','劉克莊','宋','宋诗','song-poetry','','[]','憶在軍中爲記室，謝公門館事皆知。',64,'全唐诗/poet.song.197000.json','["憶在軍中爲記室，謝公門館事皆知。", "謙卑若婦初嬪日，儉素猶夫未貴時。", "病了死生惟點首，晚憂家國每顰眉。", "舊人獨有任安在，攬涕西風獻些詞。"]'),
('79b0e8f4-c577-458b-bf1e-e83f6b76174a','悼阿昇','劉克莊','宋','宋诗','song-poetry','','[]','寶惜吾兒如拱璧，那知變滅只須臾。',64,'全唐诗/poet.song.197000.json','["寶惜吾兒如拱璧，那知變滅只須臾。", "畏啼尚宿通宵火，塗顖猶殘隔日朱。", "坐客相寬云夢幻，故人來吊訝清癯。", "荒山歲晚無行迹，心折原頭樹影孤。"]'),
('ba451002-bb99-4483-8377-4a5511088fea','送真舍人帥江西八首  其一','劉克莊','宋','宋诗','song-poetry','','[]','諫書元不爲求名，上有穹蒼鑒至誠。',32,'全唐诗/poet.song.197000.json','["諫書元不爲求名，上有穹蒼鑒至誠。", "索虜傳觀皆動色，豈知難悟漢公卿。"]'),
('d1d92aa9-311a-4858-8d4c-68a7beba08d9','送真舍人帥江西八首  其二','劉克莊','宋','宋诗','song-poetry','','[]','聞道泉人截𩍐留，翰林從此去吾州。',32,'全唐诗/poet.song.197000.json','["聞道泉人截𩍐留，翰林從此去吾州。", "村中父老相持泣，但祝今侯似故侯。"]'),
('08514d53-3e80-40bb-b018-f157b0b3c9f2','送真舍人帥江西八首  其三','劉克莊','宋','宋诗','song-poetry','','[]','舶客珠犀湊郡城，向來點涴幾名卿。',32,'全唐诗/poet.song.197000.json','["舶客珠犀湊郡城，向來點涴幾名卿。", "海神亦歎公清德，少見歸舟箇樣輕。"]'),
('298ef5d8-bee0-4aec-ab7b-8671e4cf4d7e','送真舍人帥江西八首  其四','劉克莊','宋','宋诗','song-poetry','','[]','應對詼諧路亦開，漢家天子日招徠。',32,'全唐诗/poet.song.197000.json','["應對詼諧路亦開，漢家天子日招徠。", "當時惟有膠西相，不向平津閤裏來。"]'),
('d3839a30-fa82-4ef5-bcff-2916782d809d','送真舍人帥江西八首  其五','劉克莊','宋','宋诗','song-poetry','','[]','淮漢沄沄戰血腥，蜀山鬼哭不堪聽。',32,'全唐诗/poet.song.197000.json','["淮漢沄沄戰血腥，蜀山鬼哭不堪聽。", "如何一綫江西路，獨現奎星併福星。"]'),
('8c7ad349-538e-4ccd-94cc-867bc6e48eca','送真舍人帥江西八首  其六','劉克莊','宋','宋诗','song-poetry','','[]','自昔安危等置棋，繫人著數匪天爲。',32,'全唐诗/poet.song.197000.json','["自昔安危等置棋，繫人著數匪天爲。", "何因國手來當局，要看開奩布子時。"]'),
('863651f0-1cbc-42dd-860d-15589a6f0a7a','送真舍人帥江西八首  其七','劉克莊','宋','宋诗','song-poetry','','[]','少小聞人說復讎，至今禾黍徧宗周。',32,'全唐诗/poet.song.197000.json','["少小聞人說復讎，至今禾黍徧宗周。", "自憐謝病離軍去，始聽王師下海州。"]'),
('b8c011f7-edbf-4e0e-b6e8-838adc814507','送真舍人帥江西八首  其八','劉克莊','宋','宋诗','song-poetry','','[]','身已爲民與世疎，的無一步離村居。',32,'全唐诗/poet.song.197000.json','["身已爲民與世疎，的無一步離村居。", "昨朝出郭遲公至，廢了窗間數葉書。"]'),
('55aa0b82-7cd0-4e20-93e8-398f1f10c7e1','與客送仲白葬回登石室','劉克莊','宋','宋诗','song-poetry','','[]','絕頂荒寒斷客過，偶携之子共捫蘿。',64,'全唐诗/poet.song.197000.json','["絕頂荒寒斷客過，偶携之子共捫蘿。", "縱觀天外皆鯨浸，下視城中等螘窠。", "悼友孤懷方濩落，逢僧逆境暫銷磨。", "夜歸剩乞松明火，霜滿前山滑處多。"]'),
('a08ad550-9cc7-4f28-8ca5-db54de3689cf','立春二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','恰歸舊隠再逢春，村巷荒涼草沒人。',64,'全唐诗/poet.song.197000.json','["恰歸舊隠再逢春，村巷荒涼草沒人。", "犬壞園中門作竇，盜規墳上樹爲薪。", "官如巫祝難羞賤，家似樵漁敢諱貧。", "聞說鄰醅低價賣，病夫一滴未沾脣。"]'),
('715958ff-62f1-4258-9979-eb654f9fa6b7','立春二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','今歲春盤始住家，也勝覊旅走天涯。',64,'全唐诗/poet.song.197000.json','["今歲春盤始住家，也勝覊旅走天涯。", "圃晴菜拆經霜甲，林暖梅飛徧地花。", "閑有工夫憂世事，老無勳業惜年華。", "近來死盡吟詩者，得句聊從野叟誇。"]'),
('45c95dec-8796-4700-b01c-ca85be4a76c3','去春','劉克莊','宋','宋诗','song-poetry','','[]','去春烽火照江邊，曾草軍書夕廢眠。',64,'全唐诗/poet.song.197000.json','["去春烽火照江邊，曾草軍書夕廢眠。", "萬里旌旗真屬命，一丘耕釣且隨緣。", "偶然謝客元非病，間亦尋僧不爲禪。", "尚有惜花情味在，銅瓶終日玩芳妍。"]'),
('8cedda9f-924e-424d-b57e-e0ffec0b0021','燈夕','劉克莊','宋','宋诗','song-poetry','','[]','千炬金梔映玉蕖，臺城昨夢又年餘。',64,'全唐诗/poet.song.197000.json','["千炬金梔映玉蕖，臺城昨夢又年餘。", "斷無絃索鳴華屋，惟見炊煙起草廬。", "兒報瓶空因止酒，婢言油盡暫停書。", "蓬窗亦有精勤士，何必然藜向石渠。"]'),
('3ff9282d-f0b3-434a-8108-596241ea53a8','戲孫季蕃','劉克莊','宋','宋诗','song-poetry','','[]','少日逢春一味癡，輕鞭小袖趁芳時。',64,'全唐诗/poet.song.197000.json','["少日逢春一味癡，輕鞭小袖趁芳時。", "常過茶邸租船出，或在禪林借枕欹。", "名妓難呼多占定，好花易落况開遲。", "身今惟悴投空谷，悔不當年秉燭嬉。"]'),
('7ffcb8e0-991c-42f5-8cd3-ee6afb47452c','匹馬','劉克莊','宋','宋诗','song-poetry','','[]','匹馬曾經小店炊，一株玉雪映疎籬。',64,'全唐诗/poet.song.197000.json','["匹馬曾經小店炊，一株玉雪映疎籬。", "無言誰識含情處，有韻全看背面時。", "乍見心方驚絕艷，重來人已折繁枝。", "斷烟殘照山村路，消得劉郎一首詩。"]'),
('21f51def-a628-47cd-a438-0ef72ecdb249','宿囊山懷洪岳二上人','劉克莊','宋','宋诗','song-poetry','','[]','憶在山中識二僧，一亡一已拂衣行。',64,'全唐诗/poet.song.197000.json','["憶在山中識二僧，一亡一已拂衣行。", "壁間笠徙名藍掛，寺外松過壽塔生。", "隴月定知今夕恨，澗泉猶咽舊時聲。", "隔房侍者皆新剃，不似閑人却有情。"]'),
('e2b723cf-1f08-4c68-8d65-5e2f7832056d','訪辟支巖絕頂二僧值雨','劉克莊','宋','宋诗','song-poetry','','[]','聞有比丘隠絕巔，多年無跡下山前。',64,'全唐诗/poet.song.197000.json','["聞有比丘隠絕巔，多年無跡下山前。", "僧稱功行幾如佛，樵說神通復近僊。", "食少僅炊盈握米，身寒不挂半銖綿。", "重巖風雨妨遊陟，回眺蒼烟一惘然。"]'),
('e832db62-a66a-4f0b-95ff-f7feaa34325b','送王實之赴長沙幕','劉克莊','宋','宋诗','song-poetry','','["\u8861\u5c71"]','賈傅遺蹤在，君於此泛蓮。',48,'全唐诗/poet.song.197000.json','["賈傅遺蹤在，君於此泛蓮。", "不應卑濕地，猶著廣寒仙。", "策好人爭誦，名高士責全。", "衡山余所管，擬結草鞵緣。"]'),
('591d0978-2ad1-4ef3-b9bd-aac1e5633b0e','哭豐宅之吏部二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','江表依公稍自强，訃聞朝野共凄涼。',64,'全唐诗/poet.song.197000.json','["江表依公稍自强，訃聞朝野共凄涼。", "纛移北府兵皆散，笳返西州宅已荒。", "舊戍交鋒淮水赤，新墳埋劍越山蒼。", "此身虛作田橫客，血淚無因滴壠旁。"]'),
('12ec9305-f71b-4603-99f8-bc40262d420c','哭豐宅之吏部二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','康時才業未全伸，晚建油幢白髮新。',64,'全唐诗/poet.song.197000.json','["康時才業未全伸，晚建油幢白髮新。", "畚土爲城塵滿面，握拳猶戰膽通身。", "一生偏任公家怨，四海皆知後事貧。", "多少貴交方厚祿，恤孤吊墓屬何人。"]'),
('13ca5796-be8c-42e4-9ddf-92235a4ecab5','深村','劉克莊','宋','宋诗','song-poetry','','[]','身老深村負歲華，青苔逕裏是貧家。',32,'全唐诗/poet.song.197000.json','["身老深村負歲華，青苔逕裏是貧家。", "晚風一陣無端急，不爲山人惜柚花。"]'),
('15a9329d-7863-409f-acfc-71051ff25aa5','挽林進士','劉克莊','宋','宋诗','song-poetry','','[]','一門皆擢第，君獨老儒冠。',48,'全唐诗/poet.song.197000.json','["一門皆擢第，君獨老儒冠。", "試卷年年納，經書日日看。", "文爲前輩賞，命合主司難。", "遥想泉臺恨，銘旌未寫官。"]'),
('18987fc1-3da9-415d-8db0-6e76a0230b88','柬人求馿子','劉克莊','宋','宋诗','song-poetry','','[]','聞在江寧得小馿，價高人說是名駒。',64,'全唐诗/poet.song.197000.json','["聞在江寧得小馿，價高人說是名駒。", "行時亦肯過橋否，饑後還能飲澗無。", "不稱金鞍馱侍女，只宜席帽載貧儒。", "灞陵雨雪詩家事，乞與它年做畫圖。"]'),
('acfacc9b-85f3-48c7-a395-eec6ad3d932b','寄漢陽守王中甫','劉克莊','宋','宋诗','song-poetry','','[]','自辭莫府徑歸耕，同舍分携闕寄聲。',64,'全唐诗/poet.song.197000.json','["自辭莫府徑歸耕，同舍分携闕寄聲。", "帳下飛書空有草，軍中上級獨無名。", "山深僕不聞時事，塞近君應得虜情。", "聞道漢東堪卧治，訊來依舊說招兵。"]'),
('81ffa6df-5d58-4e45-8f23-4aa32845416f','與客登壺山絕頂','劉克莊','宋','宋诗','song-poetry','','[]','十里稀逢寸地平，且無木影蔭人行。',64,'全唐诗/poet.song.197000.json','["十里稀逢寸地平，且無木影蔭人行。", "鳬飛難學王喬舄，魚貫全如鄧艾兵。", "樵子獻花簪帽重，山靈供水入瓢清。", "捫蘿莫怪匆匆下，恐賺林僧束炬迎。"]'),
('9914d78c-7567-4d22-b953-5a2c841b4a42','戲答同游','劉克莊','宋','宋诗','song-poetry','','[]','君到中峯力不加，却疑絕頂事皆誇。',32,'全唐诗/poet.song.197000.json','["君到中峯力不加，却疑絕頂事皆誇。", "烟含晚市微分塔，日照鄰州近隔沙。"]'),
('537e9271-852f-4523-8d16-aac034ac7901','次方武成壺山韻','劉克莊','宋','宋诗','song-poetry','','[]','圖經云此有神仙，曾見壺公跳入年。',64,'全唐诗/poet.song.197000.json','["圖經云此有神仙，曾見壺公跳入年。", "斫木人多山漸瘦，結庵僧去石誰眠。", "鳥歸半嶺銜斜日，樵返疎村起遠煙。", "君若能拋塵裏事，一龕共占野雲邊。"]'),
('03fe877f-8b17-4e60-a232-fec041561960','挽林推官內方孺人','劉克莊','宋','宋诗','song-poetry','','[]','身畔無釵澤，何由葬禮奢。',48,'全唐诗/poet.song.197000.json','["身畔無釵澤，何由葬禮奢。", "明時選人婦，先帝近臣家。", "白首持巾帨，青燈緝苧麻。", "寺西同窆處，風日愴寒笳。"]'),
('69ea52ea-091f-4cfe-b8f8-a89d427239e3','方湖泛舟得南字','劉克莊','宋','宋诗','song-poetry','','[]','湖波煙雨綠如藍，小𦩘閑携客二三。',64,'全唐诗/poet.song.197000.json','["湖波煙雨綠如藍，小𦩘閑携客二三。", "墜絮颭萍生細浪，驚魚避鷺沒深潭。", "入荷似覺傍無岸，穿石方知上有巖。", "却凭朱樓同望海，一規寒玉帖西南。"]'),
('58e31c93-f4da-445b-b2dc-e1c8dd063fe5','空寂院','劉克莊','宋','宋诗','song-poetry','','[]','院名誰遣稱空寂，入得門來寂又空。',64,'全唐诗/poet.song.197000.json','["院名誰遣稱空寂，入得門來寂又空。", "舊有田園官戶占，別無衣鉢老尼窮。", "砌傾苔色侵堂上，厨廢炊煙起草中。", "或說古碑巢寇寫，栖禽不下似傷弓。"]'),
('5a16c8e0-69c6-491d-af0d-e39b94c17284','紫澤觀','劉克莊','宋','宋诗','song-poetry','','[]','修持盡是女黄冠，自小辭家學住山。',64,'全唐诗/poet.song.197000.json','["修持盡是女黄冠，自小辭家學住山。", "簾影靜垂斜日裏，磬聲徐出落花間。", "祭星綠簡親書字，避客青衣密掩關。", "最愛粉牆堪試筆，苦無才思又空還。"]'),
('010eb867-62fa-425c-815c-6526d8f23f5d','靈寶道院','劉克莊','宋','宋诗','song-poetry','','[]','兩行松繞垣，數箇竹當軒。',48,'全唐诗/poet.song.197000.json','["兩行松繞垣，數箇竹當軒。", "山主出何處，道人知不言。", "只携詩草至，尚覺磬聲煩。", "俗奉醫僊謹，儒家亦捨旛。"]'),
('1b023a37-72ae-4d40-bc39-8551ae1f4cb3','方寺丞新第二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','宅成天下借圖看，始笑書生眼力慳。',64,'全唐诗/poet.song.197000.json','["宅成天下借圖看，始笑書生眼力慳。", "地占百弓多是水，樓無一面不當山。", "荷深似入苕溪路，石怪疑行鴈蕩間。", "只恐中原方鼎沸，天心未遣主人閑。"]'),
('043f8b01-10e4-45e8-bb88-6940b5bbfc76','方寺丞新第二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','一生不蓄買田錢，華屋何心亦偶然。',64,'全唐诗/poet.song.197000.json','["一生不蓄買田錢，華屋何心亦偶然。", "客至多逢僧在坐，釣歸惟許鶴隨船。", "按行花木皆僚友，主掌湖山即事權。", "京洛貴人金谷裏，安知世上有林泉。"]'),
('9a22d36f-de7d-45f8-b9ac-3334421464be','小齋','劉克莊','宋','宋诗','song-poetry','','[]','小齋自理畫并琴，匣貯香薰怕蠹侵。',64,'全唐诗/poet.song.197000.json','["小齋自理畫并琴，匣貯香薰怕蠹侵。", "出塞已忘傳檄夢，入山猶有著書心。", "南船不至城無米，北貨難通藥闕參。", "却爲貧居還往少，門前留得綠蕪深。"]'),
('29abf78a-9720-435f-b8bd-148a88b94771','東巖寺避暑','劉克莊','宋','宋诗','song-poetry','','[]','若非來寺裏，無地避炎蒸。',48,'全唐诗/poet.song.197000.json','["若非來寺裏，無地避炎蒸。", "經雨房基潤，依山井氣冰。", "榻虛涼睡客，松濕滴歸僧。", "對此專宜靜，爲詩亦不應。"]'),
('04251128-ee70-4423-8dc3-c9268a0b36a5','方寺丞𦩘子初成','劉克莊','宋','宋诗','song-poetry','','[]','船成莫厭野人過，久欲從公具釣蓑。',64,'全唐诗/poet.song.197000.json','["船成莫厭野人過，久欲從公具釣蓑。", "積雨晴來湖面闊，殘花落盡樹陰多。", "新營小店皆依柳，舊有危亭尚隔荷。", "所恨前峯含暝色，不然和月宿烟波。"]'),
('43b9f91c-5614-4524-9045-a60f0b4a7e9d','友人病瘡','劉克莊','宋','宋诗','song-poetry','','[]','自檢方書坐一床，教尋蒿白采蒲黄。',64,'全唐诗/poet.song.197000.json','["自檢方書坐一床，教尋蒿白采蒲黄。", "畫眉連日疎粧閤，鍊氣通宵住道房。", "倦聽瀑聲令睡醒，悶拈詩卷遣心涼。", "猶勝華髮從軍客，歸卧茅簷養戰瘡。"]'),
('55cfb36a-baff-4615-a481-3e3f68a84b82','乍暑一首','劉克莊','宋','宋诗','song-poetry','','[]','南州四月氣如蒸，却憶吳中始賣冰。',64,'全唐诗/poet.song.197000.json','["南州四月氣如蒸，却憶吳中始賣冰。", "綠浦遊船常載妓，畫廊浴鼓或隨僧。", "夢過水榭聞涼笛，身在山房伴曉燈。", "怊悵烏絲欄上筆，蓬窗學寫字如蠅。"]'),
('2f76fa1c-cb33-46e1-80bf-f1abaa905828','衛生','劉克莊','宋','宋诗','song-poetry','','[]','衛生草草昧周防，小郡無醫自處方。',64,'全唐诗/poet.song.197000.json','["衛生草草昧周防，小郡無醫自處方。", "採下菊宜爲枕睡，碾來芎可入茶嘗。", "身因病轉添蕭颯，人到衰難再盛强。", "舊喜讀書今亦懶，銅鑪慢炷一銖香。"]'),
('6dfc7dc1-53b4-4d6c-af52-d31ab9fac784','先儒','劉克莊','宋','宋诗','song-poetry','','[]','先儒緒業有師承，非謂聞風便服膺。',64,'全唐诗/poet.song.197000.json','["先儒緒業有師承，非謂聞風便服膺。", "康節易傳於隠者，濂溪學得自高僧。", "衆宗虛譽相賢聖，獨守遺編當友朋。", "門掩荒村人掃迹，空鈔小字對孤燈。"]'),
('1856e583-b5f1-4d43-879c-a6342a85abf4','同孫季蕃游浄居諸庵  其一','劉克莊','宋','宋诗','song-poetry','','[]','捨俗依空事梵王，韶顔寂寂度年芳。',64,'全唐诗/poet.song.197000.json','["捨俗依空事梵王，韶顔寂寂度年芳。", "門前草色迷行徑，院裏花陰接步廊。", "弓樣展來靴尚窄，黛痕剃出頂應涼。", "當時若使窺鸞鏡，一步何因出洞房。"]'),
('5a43d580-656d-4866-a39b-e0284691e4e4','同孫季蕃游浄居諸庵  其二','劉克莊','宋','宋诗','song-poetry','','[]','滿院靜沉沉，微聞有梵音。',48,'全唐诗/poet.song.197000.json','["滿院靜沉沉，微聞有梵音。", "不來陪客語，應恐壞禪心。", "母處歸全少，師邊悟已深。", "戒衣皆自衲，因講始停針。"]'),
('fe919ca1-6767-4639-bfde-1b202443b038','孟夏汎方湖得同字','劉克莊','宋','宋诗','song-poetry','','[]','長笛橫吹露滿空，柂行渾不辨西東。',64,'全唐诗/poet.song.197000.json','["長笛橫吹露滿空，柂行渾不辨西東。", "岸回初見遥峯出，浦盡新疏別港通。", "月照鷺身明石畔，風翻螢影沒荷中。", "書生此樂關時命，歎息無因夜夜同。"]'),
('59d2267a-1f89-40a3-b841-ce5f09b28af1','又得湖字','劉克莊','宋','宋诗','song-poetry','','[]','帝賜先生一曲湖，畫船領客汎菰蒲。',64,'全唐诗/poet.song.197000.json','["帝賜先生一曲湖，畫船領客汎菰蒲。", "覆茅亭子尋猶遠，隔柳人家看似無。", "渴嗜瀑泉頻遣汲，醉行釣岸屢嗔扶。", "假令不立功名死，史筆須編入酒徒。"]'),
('f6161287-107c-42b6-a044-9460a2088d86','問友人病','劉克莊','宋','宋诗','song-poetry','','[]','病來清瘦欲通僊，深炷香篝掃地眠。',64,'全唐诗/poet.song.197000.json','["病來清瘦欲通僊，深炷香篝掃地眠。", "野客勸尋廉藥買，外人偷出近詩傳。", "術庸難靠醫求效，俗陋多依鬼乞憐。", "鷗鷺如欺行迹少，分明溪上占漁船。"]'),
('c5b06e70-850c-4d13-bbea-8fb4b03ad263','偶賦','劉克莊','宋','宋诗','song-poetry','','[]','身已深藏畏俗知，客來鄰曲善爲辭。',64,'全唐诗/poet.song.197000.json','["身已深藏畏俗知，客來鄰曲善爲辭。", "偶彈冠起成何事，徑拂衣歸自一奇。", "村飲婦常留燭待，山行童亦挾書隨。", "明時性學尤通顯，却悔從初業小詩。"]'),
('76da304a-508f-48a4-a4f1-5992eebe77a7','滄浪館夜歸二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','萬疋沙場似電奔，轟天笳吹簇轅門。',32,'全唐诗/poet.song.197000.json','["萬疋沙場似電奔，轟天笳吹簇轅門。", "而今出借東家馬，煙雨孤行小麥村。"]'),
('bd55312a-b338-49ff-9e6f-1de9a1ddcc46','滄浪館夜歸二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','立馬飛書萬衆看，雪花滿硯指皆寒。',32,'全唐诗/poet.song.197000.json','["立馬飛書萬衆看，雪花滿硯指皆寒。", "自憐衰憊今如此，枕上裁詩字未安。"]'),
('f99ed83c-a3c1-4f62-8e89-d30e205398c7','贈翁定','劉克莊','宋','宋诗','song-poetry','','[]','相逢乍似生朋友，坐久方驚隔闊餘。',64,'全唐诗/poet.song.197000.json','["相逢乍似生朋友，坐久方驚隔闊餘。", "徧問諸郎皆冠带，自言別業可樵漁。", "住鄰秦系曾居里，老讀文公所著書。", "十七年間如電瞥，君鬚我鬢兩蕭疎。"]'),
('1f2110f4-c230-4bbc-b910-0b8cfcd18690','送孫季蕃','劉克莊','宋','宋诗','song-poetry','','["\u8861\u5c71"]','家在吳中處處移，的於何地結茅茨。',64,'全唐诗/poet.song.197000.json','["家在吳中處處移，的於何地結茅茨。", "囊空不肯投牋乞，程遠多應稅馬騎。", "短劍易錢平近債，長瓶傾酒話餘悲。", "衡山老祝凄凉甚，明日無人共講詩。"]'),
('5c1e0f80-352b-4866-9a26-a12e7bfef65e','哭毛易甫','劉克莊','宋','宋诗','song-poetry','','[]','至尊殿上主文衡，誰料臺中有異評。',64,'全唐诗/poet.song.197000.json','["至尊殿上主文衡，誰料臺中有異評。", "垂二十年猶入幙，後三四榜盡登瀛。", "白頭親痛終天訣，丹穴雛方隔歲生。", "策比諸儒無媿色，自緣命不到公卿。"]'),
('153a4334-8f19-48e2-9c17-68cab2cf1a5a','月下聽孫季蕃吹笛','劉克莊','宋','宋诗','song-poetry','','[]','孫郎痛飲橫長笛，玉雪胸襟鐵石顔。',64,'全唐诗/poet.song.197000.json','["孫郎痛飲橫長笛，玉雪胸襟鐵石顔。", "解噴清霜飛座上，能呼涼月出雲間。", "病創凍馬嘶荒塞，失侶窮猿叫亂山。", "可惜調高無聽者，紫髯白盡鬢毛斑。"]'),
('4341d90f-8921-4710-ab28-0a5d26df8ec7','哀陳璹','劉克莊','宋','宋诗','song-poetry','','[]','滿懷干世策，自請戍邊城。',48,'全唐诗/poet.song.197000.json','["滿懷干世策，自請戍邊城。", "不得兵書力，翻成禮部名。", "妓方調錦瑟，客已吊丹旌。", "都下人來說，還因喜喪生。"]'),
('e479bb4b-388a-4dfc-ab0b-34a460d222a9','題方武成詩草','劉克莊','宋','宋诗','song-poetry','','[]','性僻愛詩如至寶，借君詩卷百迴看。',64,'全唐诗/poet.song.197000.json','["性僻愛詩如至寶，借君詩卷百迴看。", "吟來體犯諸家少，改定人移一字難。", "束瀑爲題猶夭矯，吞山入句尚蒼寒。", "嗟余老鈍資磨琢，安得同衾語夜闌。"]'),
('7b7c7033-1805-4a41-9ac1-858675fc3199','送劉連江之官','劉克莊','宋','宋诗','song-poetry','','[]','舊說土風淳，今聞未易馴。',48,'全唐诗/poet.song.197000.json','["舊說土風淳，今聞未易馴。", "勢侵官府弱，稅去縣衙貧。", "襆印辭州遠，開軒與海鄰。", "中朝峩豸者，多用滿歸人。"]'),
('6d3060e7-7bfc-44d1-9dcb-f0391c2bd493','挽柯東海','劉克莊','宋','宋诗','song-poetry','','[]','不持寸鐵霸斯文，疇昔曾將膽許君。',64,'全唐诗/poet.song.197000.json','["不持寸鐵霸斯文，疇昔曾將膽許君。", "撰出騷詞奴宋玉，寫成帖字婢羊欣。", "喪無歸費人爭賻，詩有高名虜亦聞。", "昨覽埋銘增感愴，纍纍舊友去爲墳。"]'),
('4bc0b801-d50b-4058-9a69-758d3e89cd0e','送客','劉克莊','宋','宋诗','song-poetry','','[]','騎馿送客一壺隨，汗透中單熱似炊。',32,'全唐诗/poet.song.197000.json','["騎馿送客一壺隨，汗透中單熱似炊。", "客又不來天落雨，路邊茅舍坐移時。"]'),
('f5dc8fca-993e-43f3-83c5-8a8e2c2322da','哭王宗可','劉克莊','宋','宋诗','song-poetry','','[]','昨現官身往，今迎影子迴。',48,'全唐诗/poet.song.197000.json','["昨現官身往，今迎影子迴。", "總云鳬入覲，誰料鵩爲災。", "巷靜公人去，門荒吊客來。", "故園花滿架，猶似去年開。"]'),
('9a044cff-ba05-4b64-a740-67dc36141d7e','書考一首','劉克莊','宋','宋诗','song-poetry','','[]','香火精勤閲一朞，孤臣無路答鴻私。',64,'全唐诗/poet.song.198000.json','["香火精勤閲一朞，孤臣無路答鴻私。", "銜如已廢陳人樣，俸比初開小學時。", "世上升沉姑付酒，考中功狀是吟詩。", "五錢買得羊毛筆，自寫年勞送有司。"]'),
('682db73b-8a73-41a8-acab-c45ed759a536','哭常權','劉克莊','宋','宋诗','song-poetry','','[]','曾佐下風山縣裏，長官貴重若神明。',64,'全唐诗/poet.song.198000.json','["曾佐下風山縣裏，長官貴重若神明。", "行香野寺徐方至，白事琴堂久始迎。", "遠遞無書悲契闊，老襟有淚愴生平。", "郎君如玉聞先夭，誰護丹旌問去程。"]'),
('dda5779f-c4a4-4f45-8c62-7b7b00f1070e','穴蟻一首','劉克莊','宋','宋诗','song-poetry','','[]','穴蟻能防患，常於未雨移。',48,'全唐诗/poet.song.198000.json','["穴蟻能防患，常於未雨移。", "聚如營洛日，散似去邠時。", "斷續緣高壁，周遭避淺池。", "誰爲謀國者，見事反傷遲。"]'),
('fcb4ad46-529b-462c-bdbd-c02169a55f96','方寺丞除雲臺觀','劉克莊','宋','宋诗','song-poetry','','[]','河嶽腥羶憤未忘，羨公遥領舊靈光。',64,'全唐诗/poet.song.198000.json','["河嶽腥羶憤未忘，羨公遥領舊靈光。", "草荒太白騎馿跡，雲冷希夷委蛻裳。", "定有遺民來獻土，可無散吏去焚香。", "吾聞同華多奇觀，不比炎州寂寞鄉。"]'),
('c2405d2c-e9c0-4f21-b4cd-a9f2b855360a','哭方主簿伋','劉克莊','宋','宋诗','song-poetry','','[]','鶉衣不似擁千金，用破燈窗一世心。',64,'全唐诗/poet.song.198000.json','["鶉衣不似擁千金，用破燈窗一世心。", "太學空聞能賦久，春官未察讀書深。", "柴車巾出身猶健，槐簡拈歸病已侵。", "寂寞殯宮來客少，故人野外獨沾襟。"]'),
('a1dd97c0-b2e5-4293-9840-10d85c657870','陳寺丞續荔枝譜','劉克莊','宋','宋诗','song-poetry','','[]','蔡公絕筆山川歇，荔子蕭條二百年。',64,'全唐诗/poet.song.198000.json','["蔡公絕筆山川歇，荔子蕭條二百年。", "選貌略如唐進士，慕名幾似晉諸賢。", "豈無品劣聲虛得，亦有形佳味不然。", "題徧貴家臺沼後，請君物色到林泉。"]'),
('50c6bacc-b026-47cb-a337-e9325dcee15b','棋','劉克莊','宋','宋诗','song-poetry','','[]','十年學弈天機淺，技不能高謾自娛。',64,'全唐诗/poet.song.198000.json','["十年學弈天機淺，技不能高謾自娛。", "遠聽子聲疑有著，近看局勢始知輸。", "危如巡遠支孤壘，狹似孫劉保一隅。", "未肯人間稱拙手，夜齋明燭按新圖。"]'),
('8212a72b-601c-4400-b6f3-0e4d881aead5','宿千歲庵聽泉','劉克莊','宋','宋诗','song-poetry','','[]','因愛庵前一脈泉，襆衾來此借房眠。',64,'全唐诗/poet.song.198000.json','["因愛庵前一脈泉，襆衾來此借房眠。", "驟聞將謂溪當戶，久聽翻疑屋是船。", "變作怒聲猶壯偉，滴成細點更清圓。", "君看昔日蘭亭帖，亦把湍流替管絃。"]'),
('3c979d0e-c29c-4b4c-84c7-881874338113','題方寺丞西重山瀑布亭','劉克莊','宋','宋诗','song-poetry','','[]','與客窮源上盡山，林霏初卷嶺泥乾。',64,'全唐诗/poet.song.198000.json','["與客窮源上盡山，林霏初卷嶺泥乾。", "似嫌甲第施朱戟，別築茅亭俯碧湍。", "龍怒豈容緣磴汲，雹寒不敢近崖看。", "平生粗有登臨膽，今日凭高立未安。"]'),
('5bd31b61-1a0d-4f1e-96ee-12871739fe1c','秋夜有懷傅至叔太博父子','劉克莊','宋','宋诗','song-poetry','','[]','憶昔遊君父子間，高才窮力莫追攀。',64,'全唐诗/poet.song.198000.json','["憶昔遊君父子間，高才窮力莫追攀。", "讀書衆壑歸滄海，下筆微雲起太山。", "幼嗣尚存宗武在，遺文難附所忠還。", "荒丘衰草埋雙璧，兀坐空齋涕自潸。"]'),
('31f41b3d-77e9-47c1-bace-1b54dd0ed5ed','書小窗所見','劉克莊','宋','宋诗','song-poetry','','[]','幹接枝分整復斜，隨緣裝點野人家。',32,'全唐诗/poet.song.198000.json','["幹接枝分整復斜，隨緣裝點野人家。", "小窗有喜無人見，蘭在林中出一花。"]'),
('d9b7364d-c289-4f35-a439-1d7706114fa5','哭宋君輔','劉克莊','宋','宋诗','song-poetry','','[]','早題淡墨魁多士，晚著青衫事護軍。',64,'全唐诗/poet.song.198000.json','["早題淡墨魁多士，晚著青衫事護軍。", "方見叔孫來議禮，已傳子夏去修文。", "先朝繅藉爲圭璧，近世摧殘用斧斤。", "回首冶城棋飲地，鴈悽蟬咽不堪聞。"]'),
('16407eb5-7fba-420e-9fbb-e15665f10a0d','曝書一首','劉克莊','宋','宋诗','song-poetry','','[]','秋齋近午氣尤炎，命僕開箱更發奩。',64,'全唐诗/poet.song.198000.json','["秋齋近午氣尤炎，命僕開箱更發奩。", "蟲蝕闕文勞注乙，嵐侵脫葉費裝黏。", "雲迷玉帝藏書府，日在山人炙背簷。", "誰道閑居無一事，袒衣揮扇曝芸籤。"]'),
('d03893f9-f82a-48cb-bd2a-f51f19ac665f','觀元祐黨籍碑','劉克莊','宋','宋诗','song-poetry','','[]','嶺外瘴魂多不返，冢中枯骨亦加刑。',64,'全唐诗/poet.song.198000.json','["嶺外瘴魂多不返，冢中枯骨亦加刑。", "稍寬末後因奎宿，暫仆中間得彗星。", "蚤日大程知反覆，莫年小范要調停。", "書生幾點殘碑淚，一弔諸賢地下靈。"]'),
('d2292060-0f54-4514-a5d1-b99a4e136ea7','答翁定','劉克莊','宋','宋诗','song-poetry','','[]','牢落祠官冷似秋，頼詩消遣一襟愁。',64,'全唐诗/poet.song.198000.json','["牢落祠官冷似秋，頼詩消遣一襟愁。", "喜延明月常開戶，貪對青山懶下樓。", "客詫瀑奇邀往看，僧誇寺僻約來游。", "何當與子分峯隠，饑嗅巖花渴飲流。"]'),
('5beb508b-783d-42fc-a881-59d11df59e9f','挽陳潮州伯霆','劉克莊','宋','宋诗','song-poetry','','[]','當年舍選最居優，上到青雲亦白頭。',64,'全唐诗/poet.song.198000.json','["當年舍選最居優，上到青雲亦白頭。", "律賦數篇天下誦，遺書幾卷館中留。", "入游太乙曾臨地，出牧昌黎所典州。", "耆舊凋零今欲盡，傷心笳吹掩新丘。"]'),
('c0b6ef55-9a56-405d-b17a-aadfd14bcd60','聞城中募兵有感二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','調發年多籍半空，虎符招補至閩中。',64,'全唐诗/poet.song.198000.json','["調發年多籍半空，虎符招補至閩中。", "莊農戎服來操戟，太守儒裝學拍弓。", "去日初辭鄉樹綠，到時愁見戍旗紅。", "募金莫作纏頭費，留製衣袍禦北風。"]'),
('2e7a9dc4-3c56-403e-a848-adedbe1c91a9','聞城中募兵有感二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','昔在軍中日募兵，萬夫魚貫列行營。',64,'全唐诗/poet.song.198000.json','["昔在軍中日募兵，萬夫魚貫列行營。", "懸金都市招徠廣，立的轅門去取精。", "二石開弓猶恨少，雙重被鎧尚嫌輕。", "伍符今屬他人手，歷歷空能記姓名。"]'),
('ffdb39b9-b8b1-4c3d-89ac-f27a9532e322','哭張玉父','劉克莊','宋','宋诗','song-poetry','','[]','華髮客朱門，文高道又尊。',48,'全唐诗/poet.song.198000.json','["華髮客朱門，文高道又尊。", "十分窮不屈，一片氣長存。", "籬掩湖邊宅，墳依郭外村。", "二孤彈舊鋏，泣感孟嘗恩。"]'),
('ecd54519-15b5-4a9d-a955-38b51547294d','友人病痁','劉克莊','宋','宋诗','song-poetry','','[]','昔聞詩可驅痁疾，今日詩人疾自嬰。',64,'全唐诗/poet.song.198000.json','["昔聞詩可驅痁疾，今日詩人疾自嬰。", "勢似邊兵鏖未解，根同野草剗還生。", "能蠲熱障惟山色，解洗煩襟只澗聲。", "溪友祝君如虎健，督僧栽種課奴耕。"]'),
('6c8b19da-dda7-4395-b6e9-bc7e99012711','書事二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','黄旗旁午責軍需，括匠搜船遍里閭。',64,'全唐诗/poet.song.198000.json','["黄旗旁午責軍需，括匠搜船遍里閭。", "士稚去時無鎧仗，武侯屯處有儲胥。", "粟空都內憂難繼，甲出民間策恐疎。", "昔補戎行今簡汰，空搔短髮看兵書。"]'),
('2ab9ac09-f100-42eb-a25d-5bf8dba0abea','書事二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','人道山東入職方，書生膽小慮空長。',64,'全唐诗/poet.song.198000.json','["人道山東入職方，書生膽小慮空長。", "遺民似蟻饑難給，俠士如鷹飽易揚。", "未見馳車修寢廟，先聞鑄印拜侯王。", "青齊父老應流涕，何日鸞旗駐路旁。"]'),
('3c968421-a307-4985-8fad-1ae20b03c91d','李文饒一首','劉克莊','宋','宋诗','song-poetry','','[]','畫取維州如槁葉，策禽潞將似嬰兒。',32,'全唐诗/poet.song.198000.json','["畫取維州如槁葉，策禽潞將似嬰兒。", "九原精爽人猶畏，想見中書秉筆時。"]'),
('eb676f2d-696a-4e04-82e8-0e2b116314cc','西風二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','性愛芙蓉淡復穠，倚欄日日待西風。',32,'全唐诗/poet.song.198000.json','["性愛芙蓉淡復穠，倚欄日日待西風。", "池邊數本無消息，愁絕東家半樹紅。"]'),
('0ea93537-4d6b-4cf3-a382-9d38830f9c9d','西風二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','老業猶存是苦吟，或投野店憩寒林。',32,'全唐诗/poet.song.198000.json','["老業猶存是苦吟，或投野店憩寒林。", "西風何處無詩料，水際山顛亦去尋。"]'),
('7902b19f-0b51-4804-82bf-f94baaa54544','昔仕','劉克莊','宋','宋诗','song-poetry','','["\u8861\u5c71"]','昔仕年傷早，今歸計恨遲。',24,'全唐诗/poet.song.198000.json','["昔仕年傷早，今歸計恨遲。", "頼存南嶽草，可答北山移。"]'),
('2b268434-87d1-4673-9461-f9098b793b76','九日次方寺丞韻','劉克莊','宋','宋诗','song-poetry','','[]','木落山凋水見涯，感時短髮半蒼華。',64,'全唐诗/poet.song.198000.json','["木落山凋水見涯，感時短髮半蒼華。", "人陪桓大將軍宴，誰管陶潜處士家。", "砧動寒衣貧未剪，杯空鄰酒貴難賒。", "病身索漠如黄蝶，繞匝籬邊未有花。"]'),
('9666a693-d8fc-42cc-a070-524bf0958d52','戲鄭閩清灼艾','劉克莊','宋','宋诗','song-poetry','','[]','點穴不須醫，針經手自披。',48,'全唐诗/poet.song.198000.json','["點穴不須醫，針經手自披。", "既云丹熟後，焉用火攻爲。", "簡出創牽步，端居痛上眉。", "閉門功行滿，應有解飛時。"]'),
('c0551961-4c56-4cee-a863-a6a94d7c4964','暝色','劉克莊','宋','宋诗','song-poetry','','[]','暝色千村靜，遥峯带淺霞。',48,'全唐诗/poet.song.198000.json','["暝色千村靜，遥峯带淺霞。", "荷鋤歸別墅，乞火到鄰家。", "疎鼓聞更遠，昏燈見字斜。", "小軒風露冷，自起灌蘭花。"]'),
('f8a3a367-f8e1-4ce6-9349-5d2ab566164e','示寶上人','劉克莊','宋','宋诗','song-poetry','','[]','昔尋老岳到庵西，岳死庵空路已迷。',32,'全唐诗/poet.song.198000.json','["昔尋老岳到庵西，岳死庵空路已迷。", "師舉舊詩余不記，茫然恐是夢中題。"]'),
('79441479-9f33-4ba9-bfd0-6f2ae354e237','海口官舍','劉克莊','宋','宋诗','song-poetry','','[]','曉起齋中望，千家未啟扉。',48,'全唐诗/poet.song.198000.json','["曉起齋中望，千家未啟扉。", "潮能驅海走，風欲挾人飛。", "煙寺鍾初定，霜林葉半稀。", "客身偏畏冷，著盡带來衣。"]'),
('ab60564a-fbb8-49e7-903c-d8a86c9ecf7a','瑞峰寺','劉克莊','宋','宋诗','song-poetry','','[]','寺在高山頂，天寒偶一登。',48,'全唐诗/poet.song.198000.json','["寺在高山頂，天寒偶一登。", "孤僧營粥飯，諸佛闕香燈。", "潮落洲分派，林疎塔見層。", "危欄宜老眼，欲去幾迴凭。"]'),
('59c3d365-9429-4fe2-80c1-90362f4e2229','瑞巖','劉克莊','宋','宋诗','song-poetry','','[]','金碧千間盡，惟庵免劫灰。',48,'全唐诗/poet.song.198000.json','["金碧千間盡，惟庵免劫灰。", "佛歸何國去，僧自別峯來。", "巨石神鞭至，懸崖帝鑿開。", "幽尋情未已，木杪夕陽催。"]'),
('8a93015b-91c0-460e-a335-66fdec97aebc','答湯升伯因悼紫芝','劉克莊','宋','宋诗','song-poetry','','["\u897f\u6e56"]','紫芝曾說子能詩，開卷如親玉樹枝。',64,'全唐诗/poet.song.198000.json','["紫芝曾說子能詩，開卷如親玉樹枝。", "古佛寫成翻水偈，天仙遺下步虛詞。", "的然沈謝何難識，逝矣應劉不可追。", "寂寞西湖三尺墓，誰携斗酒一澆之。"]'),
('36146ef3-25db-4f00-90ef-598ff245d754','挽林宜人','劉克莊','宋','宋诗','song-poetry','','[]','曾究西方學，儒書亦有聞。',48,'全唐诗/poet.song.198000.json','["曾究西方學，儒書亦有聞。", "賜金存日施，遺珥病時分。", "白首夫同穴，青山子結墳。", "吾詩非溢美，字字考埋文。"]'),
('7bd78b27-de69-4211-8409-08cb16de3605','送葉知郡','劉克莊','宋','宋诗','song-poetry','','[]','家在春風住二年，借侯無路意悽然。',64,'全唐诗/poet.song.198000.json','["家在春風住二年，借侯無路意悽然。", "到來不飲官中水，歸去難謀郭外田。", "燈遠村民多點塔，擔輕津吏易排船。", "壺公亦似追程送，青過囊山古寺前。"]'),
('3ec7d6e8-ac20-4604-bde3-708f9f6dead5','送人赴廬陵尉','劉克莊','宋','宋诗','song-poetry','','[]','聞說江西路，而今不宿師。',48,'全唐诗/poet.song.198000.json','["聞說江西路，而今不宿師。", "省民來著業，少府去吟詩。", "夜月營門鼓，春風射圃旗。", "雖然溪峒事，閑暇要先知。"]'),
('e2b6ec89-d6a1-4acb-8751-3bb8bf844798','別翁定宿瀑上','劉克莊','宋','宋诗','song-poetry','','[]','偶送詩人共宿山，擁爐吹燭聽潺湲。',64,'全唐诗/poet.song.198000.json','["偶送詩人共宿山，擁爐吹燭聽潺湲。", "已修茗事將安枕，因看梅花復啟關。", "崖色無苔通磵底，月光如練抹林間。", "平生所歷同郵寄，獨到庵中不忍還。"]'),
('728185b4-9b6c-4815-acf9-98c9c210eb79','身在一首','劉克莊','宋','宋诗','song-poetry','','[]','身在樵村釣瀨行，秋豪不與市朝爭。',64,'全唐诗/poet.song.198000.json','["身在樵村釣瀨行，秋豪不與市朝爭。", "目云嗜酒相繩急，謗到吟詩所犯輕。", "沉水一銖銷永晝，蠹書數葉伴殘更。", "閉門孤學無窮味，笑殺韓公接後生。"]'),
('882bbd18-e513-4ea0-bfa8-7ec69e41b443','臘月十日至外祖尚書家','劉克莊','宋','宋诗','song-poetry','','[]','古樹暗朱門，空階篆蘚痕。',48,'全唐诗/poet.song.198000.json','["古樹暗朱門，空階篆蘚痕。", "昔容萬間屋，今止數家村。", "泉少池因廢，田荒廩尚存。", "遺書零落盡，身愧史遷孫。"]'),
('be9beee0-2309-4133-a28e-36e0c2a63aba','命拙','劉克莊','宋','宋诗','song-poetry','','[]','命拙躬耕逢歉歲，旋營水菽度晨昏。',64,'全唐诗/poet.song.198000.json','["命拙躬耕逢歉歲，旋營水菽度晨昏。", "晴天田舍禾歸窖，臘日山家酒滿盆。", "護竹短牆修復壞，澆花小井汲來渾。", "早知不是封侯相，蓑笠何因肯出村。"]'),
('791e0a15-2c67-49da-9f97-f092d8a56b0d','憶真州梅園','劉克莊','宋','宋诗','song-poetry','','[]','當年飛蓋此追隨，慘澹淮天月上時。',64,'全唐诗/poet.song.198000.json','["當年飛蓋此追隨，慘澹淮天月上時。", "樹密徑鋪氈共飲，花寒常怕笛先吹。", "心憐玉雪空存夢，塵暗關山阻寄詩。", "縱使京東兵暫過，可無一二斫殘枝。"]'),
('4ba89dd9-f6ad-4b96-87a2-3d2161ddb6b7','歲晚書事十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','荒苔野蔓上籬笆，客至多疑不在家。',32,'全唐诗/poet.song.198000.json','["荒苔野蔓上籬笆，客至多疑不在家。", "病眼看人殊草草，隔林迢遞見梅花。"]'),
('1f88fdc4-8ee4-4a13-8379-0ed7dc501368','歲晚書事十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','日日抄書懶出門，小窗弄筆到黄昏。',32,'全唐诗/poet.song.198000.json','["日日抄書懶出門，小窗弄筆到黄昏。", "丫頭婢子忙勻粉，不管先生硯水渾。"]'),
('8b289e6f-514e-4d19-9cb8-adcd3b7a1f99','歲晚書事十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','踏破儂家一逕苔，雙魚去換隻雞回。',32,'全唐诗/poet.song.198000.json','["踏破儂家一逕苔，雙魚去換隻雞回。", "幸然不識聱牙字，省得閑人載酒來。"]'),
('08e1a031-3dad-470b-a45e-d9f476916d0d','歲晚書事十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','書生元不信禨祥，老去無端慮事詳。',32,'全唐诗/poet.song.198000.json','["書生元不信禨祥，老去無端慮事詳。", "白髮社巫云日吉，明朝渫井更苫牆。"]'),
('655f185c-4f7a-4f3e-b05f-16c3a6220329','歲晚書事十首  其五','劉克莊','宋','宋诗','song-poetry','','["\u8861\u5c71"]','鬰壘鍾馗尚改更，青雲變幻幾公卿。',32,'全唐诗/poet.song.198000.json','["鬰壘鍾馗尚改更，青雲變幻幾公卿。", "人間止有章泉叟，撲斷衡山了一生。"]'),
('71794942-47ec-4e4f-b5de-c749d2e81e31','歲晚書事十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','細君炊秫婢繰絲，綵勝酥花總不知。',32,'全唐诗/poet.song.198000.json','["細君炊秫婢繰絲，綵勝酥花總不知。", "窗下老儒衣露肘，挑燈自揀一年詩。"]'),
('b479fefa-1ecd-411c-b08e-51e0d582c742','歲晚書事十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','門冷如冰儘不妨，由來富貴屬蒼蒼。',32,'全唐诗/poet.song.198000.json','["門冷如冰儘不妨，由來富貴屬蒼蒼。", "誰能却學癡兒女，深夜潜燒祭竈香。"]'),
('a9a13ed4-0a58-4684-8352-a5fe97d28fb7','歲晚書事十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','歲晚郊居苦寂寥，日高鹽酪去城遥。',32,'全唐诗/poet.song.198000.json','["歲晚郊居苦寂寥，日高鹽酪去城遥。", "深深榕逕苔牆裏，忽有銀釵叫賣樵。"]'),
('d0cd9665-7048-434c-98f8-57a3dccee3ee','歲晚書事十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','主公晚節治家寬，婢慣奴驕號令難。',32,'全唐诗/poet.song.198000.json','["主公晚節治家寬，婢慣奴驕號令難。", "圃在屋邊慵種菜，井臨砌畔怕澆蘭。"]'),
('65e9d320-872d-426a-9166-fe24aaae04ce','歲晚書事十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','丐客鶉衣立戶前，豈知儂自窘殘年。',32,'全唐诗/poet.song.198000.json','["丐客鶉衣立戶前，豈知儂自窘殘年。", "染人酒媼逋猶緩，且送添丁上學錢。"]'),
('9e6db42d-9188-46e4-9772-26bfd1023f62','元日','劉克莊','宋','宋诗','song-poetry','','[]','元日家童催蚤起，起搔冷髮惜殘眠。',64,'全唐诗/poet.song.198000.json','["元日家童催蚤起，起搔冷髮惜殘眠。", "未將柏葉簪新歲，且與梅花敘隔年。", "甥姪拜多身老矣，親朋來少屋蕭然。", "人生智力難求處，惟有稱觴阿母前。"]'),
('dcf28299-5751-4413-8346-bd99fe189a9d','寄題李尚書秀野堂一首','劉克莊','宋','宋诗','song-poetry','','[]','江上歸來兩鬢絲，倒囊惟剩草堂貲。',64,'全唐诗/poet.song.198000.json','["江上歸來兩鬢絲，倒囊惟剩草堂貲。", "雲山有態爭呈獻，天海無邊入指麾。", "怪石遠從商舶至，名花多自別州移。", "寄聲獨樂先生說，世事而今尚可爲。"]'),
('5279e912-7b60-4689-9d5a-44c9efe2fe7a','又真止堂一首','劉克莊','宋','宋诗','song-poetry','','[]','作堂肯以止爲名，出處遥知講已精。',64,'全唐诗/poet.song.198000.json','["作堂肯以止爲名，出處遥知講已精。", "縱使胸中橫綠野，未應度外置蒼生。", "波頹公獨能山立，漏盡人方喜夜行。", "千載英雄須冷笑，孔明回首學淵明。"]'),
('29fc649d-ba4a-42f9-8d9e-3245fe80101d','晚悟','劉克莊','宋','宋诗','song-poetry','','[]','晚悟才爲祟，深居學養生。',48,'全唐诗/poet.song.198000.json','["晚悟才爲祟，深居學養生。", "乃知景升子，差勝少游兄。", "絕澗携瓶汲，空山抱耒耕。", "兒孫聽苦語，世世勿談兵。"]'),
('e18ca2b8-6fb3-4d2b-9def-579c56fab528','書燈','劉克莊','宋','宋诗','song-poetry','','[]','童子糊新就，籠紗碧色深。',48,'全唐诗/poet.song.198000.json','["童子糊新就，籠紗碧色深。", "喚回少年夢，照見古人心。", "每對忘甘寢，頻挑伴苦吟。", "與君交到老，莫慮棄牆陰。"]'),
('0d25025f-ddf6-4ac7-bdff-9c1ec63bf540','書感','劉克莊','宋','宋诗','song-poetry','','[]','髧髦馳逐少年場，晚向深山學老莊。',64,'全唐诗/poet.song.198000.json','["髧髦馳逐少年場，晚向深山學老莊。", "名以馬牛猶不校，嘲爲豚犬極何妨。", "性疎熟客來難記，意懶生書讀易忘。", "却笑癡人誤標榜，賢愚千古共茫茫。"]'),
('85b4a90d-5fe9-4219-b6b9-b5feffed22e3','山茶','劉克莊','宋','宋诗','song-poetry','','[]','青女行霜下曉空，山茶獨殿衆花叢。',64,'全唐诗/poet.song.198000.json','["青女行霜下曉空，山茶獨殿衆花叢。", "不知戶外千林縞，且看盆中一本紅。", "性晚每經寒始拆，色深却愛日微烘。", "人言此樹尤難養，暮溉晨澆自課僮。"]'),
('33ed36e9-b639-4aad-a54b-31aff3d8dc66','落梅  其一','劉克莊','宋','宋诗','song-poetry','','["\u548f\u7269", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u6885\u82b1", "\u5b8b\u8bd7", "\u548f\u7269\u8bd7", "\u6292\u6000"]','一片能教一斷腸，可堪平砌更堆牆。',64,'全唐诗/poet.song.198000.json','["一片能教一斷腸，可堪平砌更堆牆。", "飄如遷客來過嶺，墜似騷人去赴湘。", "亂點莓苔多莫數，偶黏衣袖久猶香。", "東風謬掌花權柄，却忌孤高不主張。"]'),
('d0e1e1e6-011d-4092-aee7-db3c0e5b3c66','落梅  其二','劉克莊','宋','宋诗','song-poetry','','[]','昨夜尖風幾陣寒，心知尤物久留難。',64,'全唐诗/poet.song.198000.json','["昨夜尖風幾陣寒，心知尤物久留難。", "枝疎似被金刀剪，片細疑經玉杵殘。", "痛叱山童持帚去，苛留野客坐苔看。", "月中徙倚憑空樹，也勝吳兒賞牡丹。"]'),
('cc266d35-9433-4289-af9e-d8cd3839cdee','野性','劉克莊','宋','宋诗','song-poetry','','[]','野性無覊束，人間毀譽輕。',48,'全唐诗/poet.song.198000.json','["野性無覊束，人間毀譽輕。", "客言詩惹謗，妻諫酒傷生。", "窗納鄰峯碧，瓢分遠澗清。", "近來尤少睡，打坐到鍾聲。"]'),
('c52df16e-84cc-44e1-b619-7abf4afe45e6','懷保寧聰老','劉克莊','宋','宋诗','song-poetry','','[]','秣陵一見歎魁梧，每恨斯人不業儒。',64,'全唐诗/poet.song.198000.json','["秣陵一見歎魁梧，每恨斯人不業儒。", "幾度劇談俱抵掌，有時大醉勸留鬚。", "探梅尚憶陪山屐，煨芋何因共地爐。", "我已休官師退院，肯來林下卓庵無。"]'),
('773d36fe-6b1b-41df-a7a1-467e363c93d2','哭五一弟先輩二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','未冠辭家出，麻衣不肯迴。',48,'全唐诗/poet.song.198000.json','["未冠辭家出，麻衣不肯迴。", "瘦因身久客，貧爲性疎財。", "精力書中去，科名病裏來。", "空傳場屋義，留與鋪家開。"]'),
('38483e5c-4594-45a2-bae8-56e9c277535c','哭五一弟先輩二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','自小即相依，天涯影伴飛。',48,'全唐诗/poet.song.198000.json','["自小即相依，天涯影伴飛。", "共燈抄細字，分俸贖寒衣。", "已痛身長訣，猶疑客未歸。", "素幃惟幼女，斷續哭聲稀。"]'),
('1ef13a5b-084b-44e6-9fbd-bb07d08ddc18','腰痛','劉克莊','宋','宋诗','song-poetry','','[]','偶得休文病，行遲卧不安。',48,'全唐诗/poet.song.198000.json','["偶得休文病，行遲卧不安。", "益綿身尚怯，加劑脈猶寒。", "扶出看山易，驅教立雪難。", "邊頭方募士，自愧已衰殘。"]'),
('f156a376-d64f-472e-8307-fbd7b5c53da0','上冢','劉克莊','宋','宋诗','song-poetry','','[]','落梅萬點曉泥乾，擘紙携家去上山。',64,'全唐诗/poet.song.198000.json','["落梅萬點曉泥乾，擘紙携家去上山。", "寧與先君遊地下，肯隨諂子乞墦間。", "墼牆漬雨頹偏易，沙土栽松長極艱。", "畢竟有慙廬墓士，林扉夜只付僧關。"]'),
('90b5bc67-eded-4a32-8372-58d1c7009524','平床嶺','劉克莊','宋','宋诗','song-poetry','','[]','一動非容易，三年議始成。',48,'全唐诗/poet.song.198000.json','["一動非容易，三年議始成。", "倩人挑旅橐，買紙劄山程。", "下嶺峯如拜，登崖樹若迎。", "暫無塵事汩，便覺長吟情。"]'),
('3c681751-cc72-4c83-98c8-fa10fb22f9ef','溪西','劉克莊','宋','宋诗','song-poetry','','[]','暮止溪西宿，喧呼聒四鄰。',48,'全唐诗/poet.song.198000.json','["暮止溪西宿，喧呼聒四鄰。", "滿村無別姓，比屋喜生人。", "解榻勤爲黍，烘衣許覓薪。", "客房惟有月，偏照不眠身。"]'),
('0a805c84-086d-4855-b792-a5f0a01faada','夾漈草堂','劉克莊','宋','宋诗','song-poetry','','[]','嶺絕瀑源窮，曾於此築宮。',48,'全唐诗/poet.song.198000.json','["嶺絕瀑源窮，曾於此築宮。", "得知千載上，因住萬山中。", "廢址苔荒盡，遺書電取空。", "高皇南渡始，却議及招弓。"]'),
('5766e4d6-2539-4dbd-8922-96f06ee30487','祺山院','劉克莊','宋','宋诗','song-poetry','','[]','昔日祺山院，今惟認土丘。',48,'全唐诗/poet.song.198000.json','["昔日祺山院，今惟認土丘。", "有僧逃債去，無主施錢修。", "野叟樵難禁，巖僊弈未休。", "何須悲幻境，佛比作浮漚。"]'),
('f979440e-1bd7-4ed4-8f8a-c9fed6ecf6fe','西林寺','劉克莊','宋','宋诗','song-poetry','','[]','將謂如廬阜，因迂數里行。',48,'全唐诗/poet.song.198000.json','["將謂如廬阜，因迂數里行。", "問俱無古迹，來等慕虛名。", "借榻眠難熟，逢碑眼暫明。", "殘僧逃似鼠，難結社中盟。"]'),
('6c42ab10-1e58-40f5-8dac-be223e3422da','興化縣','劉克莊','宋','宋诗','song-poetry','','[]','繞縣百千峯，初疑路不通。',48,'全唐诗/poet.song.198000.json','["繞縣百千峯，初疑路不通。", "居民猶太古，令尹似春風。", "箏遠呼難至，杯寒吸易空。", "却從歸路望，飛榭半天中。"]'),
('4e1f5f3c-99b6-4954-90e5-a853ec7b01bb','麥斜','劉克莊','宋','宋诗','song-poetry','','[]','諺比武夷君，來游稱所聞。',48,'全唐诗/poet.song.198000.json','["諺比武夷君，來游稱所聞。", "巖開花似染，洞出氣如雲。", "屋老殘詩在，崖枯小篆焚。", "只疑龕室內，猶有艾軒文。"]'),
('137231a4-bc34-4cb8-b37d-4c06923d0d30','鯉湖','劉克莊','宋','宋诗','song-poetry','','[]','凡是龍居處，皆難敵此泉。',48,'全唐诗/poet.song.198000.json','["凡是龍居處，皆難敵此泉。", "下窮源至海，上有穴通天。", "小派猶成瀑，低峯亦起煙。", "莫疑乘鯉事，能住即能僊。"]'),
('41e3d4f5-101f-4e57-8c46-e031dc5bf3c7','蔡溪巖','劉克莊','宋','宋诗','song-poetry','','[]','愛瀑戀苔磯，難招出翠微。',48,'全唐诗/poet.song.198000.json','["愛瀑戀苔磯，難招出翠微。", "死因巖作墓，生以石爲扉。", "已歎逃名是，猶嫌學佛非。", "後來無此士，不但鶴書稀。"]'),
('ced13c1a-d32b-44c5-a7fd-8d733d31d045','九座山','劉克莊','宋','宋诗','song-poetry','','[]','化盡開山物，惟存窣堵坡。',48,'全唐诗/poet.song.198000.json','["化盡開山物，惟存窣堵坡。", "俗傳潭出雨，僧說火因魔。", "舊給唐綾暗，新鎸蔡字訛。", "巖前觀蟒石，尤覺可疑多。"]'),
('a8d639a4-1adc-4672-bbe7-a2862893feb1','香山寺','劉克莊','宋','宋诗','song-poetry','','[]','佛廢何關儒者事，要知開創亦辛勤。',64,'全唐诗/poet.song.198000.json','["佛廢何關儒者事，要知開創亦辛勤。", "居人公拆純欏柱，巨室深藏舊記文。", "鍾已毀樓移出寺，石猶鎸字徙爲墳。", "吾詩句句通陰騭，安得檀那子細聞。"]'),
('e0008e8c-41c6-433e-8bac-cfb9f40af26c','仙遊縣','劉克莊','宋','宋诗','song-poetry','','[]','不見層崗與複巖，眼中夷曠似江南。',64,'全唐诗/poet.song.198000.json','["不見層崗與複巖，眼中夷曠似江南。", "煙收綠野連青嶂，樹闕朱橋映碧潭。", "丞相無家曾住寺，聘君有字尚留庵。", "荒山數畝如堪買，徑欲誅茆老一龕。"]'),
('631b07f4-65cf-471e-be9a-4813b88712ae','觀溪西子弟降僊','劉克莊','宋','宋诗','song-poetry','','[]','似有物憑箕，傍觀競卜疑。',48,'全唐诗/poet.song.198000.json','["似有物憑箕，傍觀競卜疑。", "曾從師授易，肯問鬼求詩。", "巖穴雖高枕，乾坤尚弈碁。", "老儒心下事，未必紫姑知。"]'),
('24106d87-e4c2-4ef6-b8cd-eb8283562fac','自昔','劉克莊','宋','宋诗','song-poetry','','[]','自昔英豪忌苟同，此身易盡學難窮。',64,'全唐诗/poet.song.198000.json','["自昔英豪忌苟同，此身易盡學難窮。", "習爲聯絕真唐體，講到玄虛有晉風。", "螘子盡云參妙喜，乞兒自許識荆公。", "安知斯世無顔閔，到死浮沉里巷中。"]'),
('76263f5d-53c0-4805-ae93-30d0ed787954','耕仕一首','劉克莊','宋','宋诗','song-poetry','','[]','耕不逢年仕背時，蕭然井臼掩茅茨。',64,'全唐诗/poet.song.198000.json','["耕不逢年仕背時，蕭然井臼掩茅茨。", "貧求生墓爲謀早，病學還丹見事遲。", "馬上功名成畫餠，林間身世似持棋。", "未應對客呈饑面，尚有荒園可種葵。"]'),
('ddd860af-e5eb-42b5-a528-cc21cef8c8da','真母吳氏挽詞二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','系出自華宗，來嬪隠約中。',48,'全唐诗/poet.song.198000.json','["系出自華宗，來嬪隠約中。", "貧能安苦節，貴愈積陰功。", "立志如歐母，生兒似富公。", "如聞新窆處，神告在溪東。"]'),
('9f6409c6-e3a7-4f7e-ae3c-4bcb4d6050ad','真母吳氏挽詞二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','族昔多名壻，今觀子更奇。',48,'全唐诗/poet.song.198000.json','["族昔多名壻，今觀子更奇。", "他年槐樹讖，早歲柏舟詩。", "割股延姑壽，抽簪活衆饑。", "事皆堪入史，何必墓傍碑。"]'),
('3a9eefdb-0e15-4e79-92f2-9afd49642b20','蘭','劉克莊','宋','宋诗','song-poetry','','[]','深林不語抱幽貞，頼有微風遞遠馨。',64,'全唐诗/poet.song.198000.json','["深林不語抱幽貞，頼有微風遞遠馨。", "開處何妨依蘚砌，折來未肯戀金瓶。", "孤高可挹供詩卷，素淡堪移入卧屏。", "莫笑門無佳子弟，數枝濯濯映階庭。"]'),
('914a10ed-babc-4244-9514-c6a1551dc5fb','感昔二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','談攻說守漫多端，誰把先朝事細看。',64,'全唐诗/poet.song.198000.json','["談攻說守漫多端，誰把先朝事細看。", "棄夏西陲忘險要，失燕北面受風寒。", "傍無公議扶种李，中有流言沮范韓。", "寄語深衣揮麈者，身經目擊始知難。"]'),
('ef7ce7f1-16f2-4e91-8817-9e8b291cbeea','感昔二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','先皇立國用文儒，奇士多爲禮法拘。',64,'全唐诗/poet.song.198000.json','["先皇立國用文儒，奇士多爲禮法拘。", "澶水歸來邊奏少，熙河捷外戰功無。", "生前上亦知强至，死後人方誄尹洙。", "螻蟻小臣孤憤意，夜窗和淚看輿圖。"]'),
('51613d7d-4bcd-49bd-8e6b-e8eb8e2a1b9a','山丹','劉克莊','宋','宋诗','song-poetry','','[]','偶然避雨過民舍，一本山丹恰盛開。',64,'全唐诗/poet.song.198000.json','["偶然避雨過民舍，一本山丹恰盛開。", "種久樹身樛似蓋，澆頻花面大如杯。", "怪疑朱草非時出，驚問紅雲甚處來。", "可惜書生無事力，千金移入畫欄栽。"]'),
('a117ec32-2a26-459e-b776-5c0907e7b453','燕二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','曾客烏衣看落花，春風吹影傍天涯。',32,'全唐诗/poet.song.198000.json','["曾客烏衣看落花，春風吹影傍天涯。", "茅簷亦有安巢地，何必王家與謝家。"]'),
('854214a9-b2aa-41e5-943d-d64963fc92f0','燕二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','野老柴門日日開，且無欄檻礙飛迴。',32,'全唐诗/poet.song.198000.json','["野老柴門日日開，且無欄檻礙飛迴。", "勸君莫入珠簾去，羯鼓如雷打出來。"]'),
('931e3e77-f878-4acb-9d6c-9a7ca12b914e','過永福精舍有懷仲白二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','求福招提小步廊，憶携詩卷共追涼。',32,'全唐诗/poet.song.198000.json','["求福招提小步廊，憶携詩卷共追涼。", "年來行處常迂路，纔近君家即斷腸。"]'),
('e7c6d7ab-5b20-4399-aed3-8b1cc9cf9123','過永福精舍有懷仲白二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','一樹梅花掩舊居，主人僊去客來疎。',32,'全唐诗/poet.song.198000.json','["一樹梅花掩舊居，主人僊去客來疎。", "白頭留得吟詩友，每見郎君勉讀書。"]'),
('4419c056-4cf2-44e0-8547-8610558f0a88','詠史二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','虜入中原力不支，洛陽名勝浪相推。',32,'全唐诗/poet.song.198000.json','["虜入中原力不支，洛陽名勝浪相推。", "可憐揮麈人如璧，半夜排牆尚未知。"]'),
('350818b0-6c47-4b8e-8809-72851838818b','詠史二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','保惜金甌未必非，臺城至竟亦灰飛。',32,'全唐诗/poet.song.198000.json','["保惜金甌未必非，臺城至竟亦灰飛。", "隠侯老任梁朝事，却爲閑情減带圍。"]'),
('07111472-280f-4fce-bf3a-a2fb066699cc','韓曾一首','劉克莊','宋','宋诗','song-poetry','','[]','道散斯文體尚浮，韓曾力與化工侔。',64,'全唐诗/poet.song.198000.json','["道散斯文體尚浮，韓曾力與化工侔。", "山瞻泰華巖巖聳，河出崑崙混混流。", "長慶從官銷不得，熙寧丞相挽難留。", "滄州奏疏潮州表，猶被人拈作話頭。"]'),
('5edbe65d-23bc-4e3b-a845-cffb95f5af9f','春旱四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','一春閔雨動龍顔，曉殿權停賀雪班。',32,'全唐诗/poet.song.198000.json','["一春閔雨動龍顔，曉殿權停賀雪班。", "林下散人看邸報，也疎把酒廢游山。"]'),
('2f3ea244-e565-4068-875b-0ef7c4b82d2e','春旱四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','去冬玉塞靜無埃，春雪雖遲亦壓災。',32,'全唐诗/poet.song.198000.json','["去冬玉塞靜無埃，春雪雖遲亦壓災。", "大士送歸天竺去，相公宣入浙江來。"]'),
('81ad5179-280d-4567-9c08-18fa0aa1af6d','春旱四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','屋山無筍圃無蔬，釜冷樽空客至疎。',32,'全唐诗/poet.song.198000.json','["屋山無筍圃無蔬，釜冷樽空客至疎。", "說與厨人稀作粥，老夫留腹要盛書。"]'),
('84885bf2-213f-4775-8a56-983f536b52a2','春旱四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','清明未雨下秧難，小麥低低似剪殘。',32,'全唐诗/poet.song.198000.json','["清明未雨下秧難，小麥低低似剪殘。", "窮巷蕭然惟飲水，家童忽報井源乾。"]'),
('a6e33fc6-89c4-456c-a980-fe8b66212f73','黄天谷贈詩次韻二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','浪迹徧齊州，曾從劍俠游。',48,'全唐诗/poet.song.198000.json','["浪迹徧齊州，曾從劍俠游。", "尚嫌秦政臭，肯要郅支頭。", "客禮朝三殿，兒嬉弄五侯。", "吾猶看不破，何况道家流。"]'),
('73965cc3-ed70-4600-b32c-c676b4dcbc26','黄天谷贈詩次韻二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','世無仙則已，有必屬斯人。',48,'全唐诗/poet.song.198000.json','["世無仙則已，有必屬斯人。", "丹熟將分友，雲遊每念親。", "小窗時讀易，靜室夜修真。", "符篆皆餘事，題詩亦出塵。"]'),
('b942d5be-d823-47c8-b199-64ff8ec0689a','得曾景建書一首','劉克莊','宋','宋诗','song-poetry','','[]','聞君別後買傾城，酒戒中年亦放行。',64,'全唐诗/poet.song.198000.json','["聞君別後買傾城，酒戒中年亦放行。", "遠使忽來知病起，近書全未說丹成。", "莫嫌身去依劉表，曾有人甘殺禰衡。", "何日斷原荒澗畔，一間茅屋對寒檠。"]'),
('656c215e-5104-4f14-893b-e2722d3385f5','示兒','劉克莊','宋','宋诗','song-poetry','','[]','瓜芋村邊一畝宮，閉門不復問窮通。',64,'全唐诗/poet.song.198000.json','["瓜芋村邊一畝宮，閉門不復問窮通。", "生羞奏技伶人裏，死怕標名狎客中。", "講學有誰明太極，吟詩無路和薰風。", "身今老矣空追悔，但祝吾兒勿似翁。"]'),
('b254d6bd-c2e4-476c-a467-20b587ed0089','擷陽塘','劉克莊','宋','宋诗','song-poetry','','[]','塘水年時似練湖，春來亦已化平蕪。',64,'全唐诗/poet.song.198000.json','["塘水年時似練湖，春來亦已化平蕪。", "農官久廢存遺址，樵子公行作坦途。", "葦折鷺藏身不得，萍乾魚以沫相濡。", "桔槔伊軋聲如泣，借問龍公睡穩無。"]'),
('c9023805-f58b-4359-95b9-6b1775498f1b','春日二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','睡起無人小院空，南華一卷磬聲中。',32,'全唐诗/poet.song.198000.json','["睡起無人小院空，南華一卷磬聲中。", "鼻端老去齊香臭，分別柑花是晚風。"]'),
('7e1fa2c4-837b-4f4f-b299-0083c52513df','春日二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','隙地新鉏一逕通，野中手自植芳叢。',32,'全唐诗/poet.song.198000.json','["隙地新鉏一逕通，野中手自植芳叢。", "生來不慣游金谷，屋角花開也自紅。"]'),
('859777de-9437-4dfe-a4b2-c929c8a0a164','憶毛易甫薛子舒','劉克莊','宋','宋诗','song-poetry','','[]','昔在江東會集時，二君獨許話心期。',64,'全唐诗/poet.song.198000.json','["昔在江東會集時，二君獨許話心期。", "春風蕭寺同登塔，落日荒臺共讀碑。", "百吏染毫供草檄，萬花圍席看題詩。", "那知數尺無情土，別後雙埋玉樹枝。"]'),
('e8631fcb-5426-4c45-8fd7-8b89016dbdc8','有感','劉克莊','宋','宋诗','song-poetry','','[]','殘羯如蜂暫寄窠，十年南北問干戈。',64,'全唐诗/poet.song.198000.json','["殘羯如蜂暫寄窠，十年南北問干戈。", "穹廬昔少曾居汴，莫府今猶未過河。", "越石不生誰可將，奉春再出亦難和。", "憂時元是詩人職，莫怪吟中感慨多。"]'),
('5556e6c5-9393-42d2-9bb4-9b4a850b2dfe','哭趙紫芝','劉克莊','宋','宋诗','song-poetry','','[]','奪到斯人處，詞林亦可悲。',48,'全唐诗/poet.song.198000.json','["奪到斯人處，詞林亦可悲。", "世間空有字，天下便無詩。", "盡出香分妓，惟留硯付兒。", "傷心湖上冢，誰葬復誰碑。"]'),
('ae3212d4-bf15-4825-82c5-2b0c5de7bbca','哭周晉仙','劉克莊','宋','宋诗','song-poetry','','[]','君在詩人裏，功夫用最深。',48,'全唐诗/poet.song.198000.json','["君在詩人裏，功夫用最深。", "古如神禹鑄，清似鬼仙吟。", "死定無高塚，生惟有破衾。", "長安酒樓上，猶記昔相尋。"]'),
('5ece819d-0b88-43e3-9bf6-f4a0527f3ba0','中𡼢先塋','劉克莊','宋','宋诗','song-poetry','','[]','昔遇重華席屢前，因排貴近去翩然。',64,'全唐诗/poet.song.198000.json','["昔遇重華席屢前，因排貴近去翩然。", "叩墀袖有馳毬疏，易簀囊無沐槨錢。", "當日傳家惟諫草，至今贍族頼祠田。", "原頭宰木蒼如此，纔見山庵葺數椽。"]'),
('19cf377b-c2b3-4692-affd-54d99bcef3f1','被酒','劉克莊','宋','宋诗','song-poetry','','[]','酒戶當年頗著聲，可堪病起困飛觥。',64,'全唐诗/poet.song.198000.json','["酒戶當年頗著聲，可堪病起困飛觥。", "醉呼褚令爲傖父，狂喚桓公作老兵。", "舊有崢嶸皆鏟去，新無壘塊可澆平。", "投床懶取騷經看，只嗅梨花解宿酲。"]'),
('cae0b0bf-f9f9-4115-a4b5-06798be76f38','小園即事二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','何處瑶姬款戶來，薔薇花下暫裴徊。',32,'全唐诗/poet.song.198000.json','["何處瑶姬款戶來，薔薇花下暫裴徊。", "分明粉蝶通消息，未有人知一朵開。"]'),
('feb8bcfd-2714-4e13-aa0f-c65c2b328f97','小園即事二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','因聽簫聲一念差，碧雲遮斷阿環家。',32,'全唐诗/poet.song.198000.json','["因聽簫聲一念差，碧雲遮斷阿環家。", "春來無遣閑愁處，玉面紗巾出看花。"]'),
('3dbe4a14-17d4-4997-b13a-12d825a0778e','夢豐宅之二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','一別茫茫隔九京，夢中慷慨語如生。',64,'全唐诗/poet.song.198000.json','["一別茫茫隔九京，夢中慷慨語如生。", "老猶奮筆排和議，病尚登陴募捄兵。", "天奪偉人關氣數，時無好漢共功名。", "殘胡仍在王師老，寶劍雖埋憤未平。"]'),
('67095f81-8a38-4c90-b23c-c8b950d107e2','夢豐宅之二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','斯人古少况於今，每恨諸賢識未深。',64,'全唐诗/poet.song.198000.json','["斯人古少况於今，每恨諸賢識未深。", "朝給賻錢方掩骨，家無餘帛可爲衾。", "向來夫子真知己，近世門生喜負心。", "惟有天涯華髮掾，獨揮衰涕望山陰。"]'),
('4f4d7310-95d0-4488-ab3d-ad8e8f872857','漢儒二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','執㦸浮沉亦未迂，無端著頌美新都。',32,'全唐诗/poet.song.198000.json','["執㦸浮沉亦未迂，無端著頌美新都。", "白頭所得能多少，枉被人書莽大夫。"]'),
('7fb76851-27b0-48d1-88ea-9178ec6190a2','漢儒二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','賣賦長安偶遇知，後車歸載遠山眉。',32,'全唐诗/poet.song.198000.json','["賣賦長安偶遇知，後車歸載遠山眉。", "可憐犬子真窮相，不見劉郎過沛時。"]'),
('025e0c56-98ae-4f0f-ac4f-890c46f8acd2','暮春','劉克莊','宋','宋诗','song-poetry','','[]','燕子來時春事空，杖藜來往綠陰中。',32,'全唐诗/poet.song.198000.json','["燕子來時春事空，杖藜來往綠陰中。", "靜憐朱槿無根蔕，開落惟銷一陣風。"]'),
('cd2fb753-4ddd-4c61-bcff-e0964716387e','哭吳杞','劉克莊','宋','宋诗','song-poetry','','[]','七十未陞舍，目深雙鬢殘。',48,'全唐诗/poet.song.198000.json','["七十未陞舍，目深雙鬢殘。", "病中依佛寺，死處近嚴灘。", "俗薄揮金少，家貧返骨難。", "遺言令火葬，聞者鼻皆酸。"]'),
('72805ff4-ff34-47c4-96b7-8a423398f928','橘花','劉克莊','宋','宋诗','song-poetry','','[]','一種靈根有異芬，初開尤勝結丹蕡。',64,'全唐诗/poet.song.198000.json','["一種靈根有異芬，初開尤勝結丹蕡。", "白於薝蔔林中見，清似旃檀國裏聞。", "淡月珠胎明璀粲，微風玉屑撼繽紛。", "平生荀令熏衣癖，露坐花間至夜分。"]'),
('c3a09f75-2466-42dc-98f9-79c21b446ada','薔薇花','劉克莊','宋','宋诗','song-poetry','','[]','浥露含風匝樹開，呼童浄掃架邊苔。',64,'全唐诗/poet.song.198000.json','["浥露含風匝樹開，呼童浄掃架邊苔。", "湘紅染就高張起，蜀錦機成乍剪來。", "公子但貪桃夾道，貴人自愛藥翻階。", "寧知野老茅茨下，亦有繁英送一盃。"]'),
('31e14fff-eaea-4599-81d6-ac214851eb87','答鄭閩清','劉克莊','宋','宋诗','song-poetry','','[]','多著襦裙少裹巾，形容蒼槁意清真。',32,'全唐诗/poet.song.198000.json','["多著襦裙少裹巾，形容蒼槁意清真。", "舊時論語都忘記，難做深衣社裏人。"]'),
('94173b94-7c10-40a0-9861-34a8ae85eaac','前輩','劉克莊','宋','宋诗','song-poetry','','[]','前輩日以遠，斯文吁可悲。',48,'全唐诗/poet.song.198000.json','["前輩日以遠，斯文吁可悲。", "古人皆尚友，近世例無師。", "晚節初寮集，中年務觀詩。", "雖云南渡體，俗子未容窺。"]'),
('aa04c37d-7cf6-4d58-9e92-154e44784666','鐵塔院','劉克莊','宋','宋诗','song-poetry','','[]','鐵塔荒涼院，年深失主名。',48,'全唐诗/poet.song.198000.json','["鐵塔荒涼院，年深失主名。", "昔遊基已廢，今至屋皆成。", "人出私錢施，僧憑願力營。", "如何榆塞上，却有未包城。"]'),
('cb91d80b-6947-44a4-9184-486f5f11458d','柬方寺丞病足','劉克莊','宋','宋诗','song-poetry','','[]','西北名山未徧經，詎宜倚杖立竛竮。',64,'全唐诗/poet.song.198000.json','["西北名山未徧經，詎宜倚杖立竛竮。", "脈通氣數醫難曉，病在皮膚藥易靈。", "昔走戰場常縱靶，今居內屋更施屏。", "平生受用嵇康論，欲獻公爲座右銘。"]'),
('40706251-ed88-4f72-93c8-779f7c9b81c5','贈徐相師','劉克莊','宋','宋诗','song-poetry','','[]','許負遺書果是非，子憑何處說精微。',64,'全唐诗/poet.song.198000.json','["許負遺書果是非，子憑何處說精微。", "使君豈必如椰大，丞相元來要瓠肥。", "袖闊日常籠短刺，肩寒春未換單衣。", "半頭布袋挑詩卷，也道游方賣術歸。"]'),
('b5398624-1ed3-4637-8816-023100d2226f','送孫夢宮','劉克莊','宋','宋诗','song-poetry','','[]','大帝開江左，無錐與遠孫。',48,'全唐诗/poet.song.198000.json','["大帝開江左，無錐與遠孫。", "自言埋戰地，也勝活侯門。", "短褐邊風緊，孤舟海浪翻。", "知他三尺劍，携去報誰恩。"]'),
('e077721b-3334-4085-ae75-299dedfa4bda','寄何立可提刑','劉克莊','宋','宋诗','song-poetry','','[]','故人握節守齊安，聞說邊頭事愈難。',64,'全唐诗/poet.song.198000.json','["故人握節守齊安，聞說邊頭事愈難。", "赤手募丁修險隘，白頭擐甲禦風寒。", "半腰城甫包圍畢，一把兵皆點摘殘。", "收得去年書在架，憶君燈下展來看。"]'),
('261b0766-2310-4338-aebc-e71e0848a21c','和曾史君喜雨','劉克莊','宋','宋诗','song-poetry','','[]','雄烏忽變作雌霓，太守爲壇水畔祠。',64,'全唐诗/poet.song.198000.json','["雄烏忽變作雌霓，太守爲壇水畔祠。", "多謝龍公來挹彼，寄聲風伯莫吹之。", "麥殘黑穟差傷晚，秧出青鍼未過期。", "想見鈴齋聞點滴，銀鈎滿紙又成詩。"]'),
('e25b4064-6216-47e9-b176-f936a4090122','送饒司理端學','劉克莊','宋','宋诗','song-poetry','','[]','一郡夸饒掾，才名果不虛。',48,'全唐诗/poet.song.198000.json','["一郡夸饒掾，才名果不虛。", "忽聞歸去勇，極恨往還疎。", "囚戴公平德，奴擔性理書。", "京華逢友舊，爲說閉門居。"]'),
('c6bc9b79-4368-40f8-945b-70e2b1525653','贈防江卒六首  其一','劉克莊','宋','宋诗','song-poetry','','[]','陌上行人甲在身，營中少婦淚痕新。',32,'全唐诗/poet.song.198000.json','["陌上行人甲在身，營中少婦淚痕新。", "邊城柳色連天碧，何必家山始有春。"]'),
('ec135cb7-a9e1-4d5f-ae33-9cb6fcac34b2','贈防江卒六首  其二','劉克莊','宋','宋诗','song-poetry','','[]','壯士如駒出渥洼，死眠牖下等蟲沙。',32,'全唐诗/poet.song.198000.json','["壯士如駒出渥洼，死眠牖下等蟲沙。", "老儒細爲兒郎說，名將皆因戰起家。"]'),
('c9e6445b-88c0-4170-962f-f6f3a86a1eda','贈防江卒六首  其三','劉克莊','宋','宋诗','song-poetry','','[]','昨者邳徐表奏通，聖朝除吏遍山東。',32,'全唐诗/poet.song.198000.json','["昨者邳徐表奏通，聖朝除吏遍山東。", "新來調卒防秋浦，又與山東報不同。"]'),
('5066f25b-c17c-4a95-8b1f-77509f507098','贈防江卒六首  其四','劉克莊','宋','宋诗','song-poetry','','[]','身屬嫖姚性命輕，君看一蟻尚貪生。',32,'全唐诗/poet.song.198000.json','["身屬嫖姚性命輕，君看一蟻尚貪生。", "無因喚取談兵者，來向橋邊聽哭聲。"]'),
('0fce82bc-e82d-4c6c-bbbf-56e2e7e87314','贈防江卒六首  其五','劉克莊','宋','宋诗','song-poetry','','[]','戰地春來血尚流，殘烽缺堠滿淮頭。',32,'全唐诗/poet.song.198000.json','["戰地春來血尚流，殘烽缺堠滿淮頭。", "明時頗牧居深禁，若見關山也自愁。"]'),
('869a7cd1-624d-4fc4-bbd3-0dab1e8be325','贈防江卒六首  其六','劉克莊','宋','宋诗','song-poetry','','[]','一炬曹瞞僅脫身，謝郎棋畔走苻秦。',32,'全唐诗/poet.song.198000.json','["一炬曹瞞僅脫身，謝郎棋畔走苻秦。", "年年拈起防江字，地下諸賢會笑人。"]'),
('e429290d-ad18-4e8d-b8d6-f406b51971e0','哭黄直卿寺丞二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','久在文公几杖旁，暮年所得最精詳。',64,'全唐诗/poet.song.198000.json','["久在文公几杖旁，暮年所得最精詳。", "貧甘香火辭符竹，病整衣冠坐簀床。", "壯士軍中悲亮死，先師地下惜回亡。", "法雲破寺三間屋，却有門人遠赴喪。"]'),
('da8dd6fc-e215-4032-819a-cff728e8709a','哭黄直卿寺丞二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','當年出塞共臨戎，箭滿行營戍火紅。',64,'全唐诗/poet.song.198000.json','["當年出塞共臨戎，箭滿行營戍火紅。", "督府凱旋先請去，堅城築就獨無功。", "身謀彼此皆迂闊，國事中間偶異同。", "莫怪些詞含哽噎，在時曾賞小詩工。"]'),
('af4b8639-8a00-427e-9e18-36b5fca324dc','不寐','劉克莊','宋','宋诗','song-poetry','','[]','萬戶千門盡擁衾，據梧展轉看橫參。',64,'全唐诗/poet.song.198000.json','["萬戶千門盡擁衾，據梧展轉看橫參。", "不知身已成衰證，枉被人疑是苦吟。", "周漢前書盲記憶，乾坤外事彊思尋。", "華山老子差堪語，安得呼來論此心。"]'),
('6eb75110-a701-4888-a245-16cf944324e1','寄夔漕王中甫','劉克莊','宋','宋诗','song-poetry','','[]','舊歲書猶至漢陽，新年夢已隔瞿唐。',64,'全唐诗/poet.song.198000.json','["舊歲書猶至漢陽，新年夢已隔瞿唐。", "西人久苦供軍費，南士專營出峽裝。", "塵暗三邊途尚梗，身遊萬里鬢應蒼。", "蜀山聞說多僊者，試爲余求辟穀方。"]'),
('4d814922-92c1-4e29-8d3c-c336841c0626','送章通判','劉克莊','宋','宋诗','song-poetry','','[]','半刺已官尊，常時讀魯論。',48,'全唐诗/poet.song.198000.json','["半刺已官尊，常時讀魯論。", "身居恭叔里，心在晦翁門。", "貧士來遮路，詩人送出村。", "君能齊得喪，何必戀華軒。"]'),
('3b079ab3-2c00-4302-a237-ab2eaf88ffeb','旱蓮','劉克莊','宋','宋诗','song-poetry','','[]','晴久方池可跣行，萍枯惟有草縱橫。',64,'全唐诗/poet.song.198000.json','["晴久方池可跣行，萍枯惟有草縱橫。", "朱葩未見叢叢拆，綠柄纔看寸寸生。", "悴若放臣臨楚澤，厄於學士蹈秦坑。", "輸他杭越花如錦，畫舫名姝夜按笙。"]'),
('5e7e2bad-a2bf-45a3-abd5-df54c23c0405','辭桂帥辟書作','劉克莊','宋','宋诗','song-poetry','','[]','一昨聞公莫府開，夢魂頻繞嶺頭梅。',64,'全唐诗/poet.song.198000.json','["一昨聞公莫府開，夢魂頻繞嶺頭梅。", "久拋鞾袴辭軍去，忽有弓旌扣戶來。", "茅舍相過爭借問，荷衣欲出却徘徊。", "舊時檄筆今焚棄，孤負黄金百尺臺。"]'),
('4fd60487-f31e-49fa-a7ae-c14e3a671787','聞何立可李茂欽訃二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','初聞邊報暗吞聲，想見登譙與虜爭。',64,'全唐诗/poet.song.198000.json','["初聞邊報暗吞聲，想見登譙與虜爭。", "世俗今猶疑許遠，君王元未識真卿。", "傷心百口同臨穴，極目孤城絕捄兵。", "多少虎臣提將印，誰知戰死是書生。"]'),
('d5abd9b3-b8f9-4152-ac95-81f5091efaf5','聞何立可李茂欽訃二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','何老長身李白鬚，傳聞死尚握州符。',64,'全唐诗/poet.song.198000.json','["何老長身李白鬚，傳聞死尚握州符。", "戰場便合營雙廟，太學今方出二儒。", "史館何人徵逸事，羽林無日訪遺孤。", "病夫疇昔曾同幕，西望關山涕自濡。"]'),
('330143fd-0135-425f-ae20-40a3fa02ec93','夏旱','劉克莊','宋','宋诗','song-poetry','','[]','滿望梅天雨，誰知日轉驕。',48,'全唐诗/poet.song.198000.json','["滿望梅天雨，誰知日轉驕。", "畦蔬新住摘，盆樹久停澆。", "米貴糧囷盡，泉乾汲路遥。", "未遑憂世事，災已到顔瓢。"]'),
('9c41d910-f2dc-4319-9ce7-f0c289e24154','憶藕','劉克莊','宋','宋诗','song-poetry','','[]','昔過臨平召伯時，小舟就買藕尤奇。',64,'全唐诗/poet.song.198000.json','["昔過臨平召伯時，小舟就買藕尤奇。", "如拈玉麈涼雙手，似瀉金莖嚥上池。", "好事染紅無意緒，癡人蒸熟減風姿。", "炎州地狹陂塘少，渴死相如欠藥醫。"]'),
('a548dbe9-1fce-4f8d-b74a-396062c02900','夜飲方湖','劉克莊','宋','宋诗','song-poetry','','[]','貪聽月下小叢歌，擲去金蕉吸碧荷。',64,'全唐诗/poet.song.198000.json','["貪聽月下小叢歌，擲去金蕉吸碧荷。", "四面凉如浮震澤，五更渴欲挽斜河。", "古稱賢達誰存者，今不懽娛柰老何。", "長笑峴山空感慨，羊公湛輩兩消磨。"]'),
('f3c512f9-9f67-44d6-b55d-be2542292367','哀江帥張常二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','關破壘猶堅，傷心援不前。',48,'全唐诗/poet.song.198000.json','["關破壘猶堅，傷心援不前。", "生居諸將下，死在衆人先。", "憤極拳雙握，創多體少全。", "豈無人策應，擁纛坐江邊。"]'),
('5cdcbb32-bc44-4610-8dc3-b7f76a404537','哀江帥張常二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','昔我居戎幕，爲侯論戰勳。',48,'全唐诗/poet.song.198000.json','["昔我居戎幕，爲侯論戰勳。", "齋旄俄烜赫，書札尚殷勤。", "國難忠方見，天高事未聞。", "九江殘部曲，暗哭故將軍。"]'),
('ce8d065c-aeaa-4456-919c-3a88e5b1971d','瀑上值雨','劉克莊','宋','宋诗','song-poetry','','[]','絕頂嵐煙合，危亭略見簷。',48,'全唐诗/poet.song.198000.json','["絕頂嵐煙合，危亭略見簷。", "不知山雨過，但覺瀑流添。", "悲壯張瑶瑟，迷濛展畫縑。", "野人雙草屨，來往任泥霑。"]'),
('4aca0586-7514-4fb9-a60d-de5a25cf0300','懶','劉克莊','宋','宋诗','song-poetry','','[]','病入中年百事闌，頹然一榻倦衣冠。',64,'全唐诗/poet.song.198000.json','["病入中年百事闌，頹然一榻倦衣冠。", "客方接話俄辭起，書未終編已輟看。", "架壞儘教花卧蘚，砌荒亦任草侵蘭。", "力求香火非無意，疎散明知涉事難。"]'),
('40250330-c4c8-4094-b15d-8bfa199051b2','送沈僴','劉克莊','宋','宋诗','song-poetry','','[]','建學多通顯，何爲尚布衣。',48,'全唐诗/poet.song.198000.json','["建學多通顯，何爲尚布衣。", "不聞行聘久，始悟設科非。", "落日君尋店，深山我掩扉。", "幾時殘燭下，重聽講精微。"]'),
('17637730-7287-4c05-9ba5-81ea6855fd19','紫薇花','劉克莊','宋','宋诗','song-poetry','','[]','風標雅合對詞臣，映硯窺窗伴演綸。',32,'全唐诗/poet.song.198000.json','["風標雅合對詞臣，映硯窺窗伴演綸。", "忽發一枝深谷裏，似知茅屋有詩人。"]'),
('3d096344-d802-4dbb-b6c5-51109624cb87','書第二考','劉克莊','宋','宋诗','song-poetry','','[]','遥領叢祠又一年，何功月請水衡錢。',64,'全唐诗/poet.song.198000.json','["遥領叢祠又一年，何功月請水衡錢。", "江南塞北雖無分，林下山間尚有緣。", "兵去未妨行酒令，印收不礙掌詩權。", "祇嫌海嶠登臨少，夢繞朱陵紫蓋邊。"]'),
('f58bc523-1066-46e3-9cf3-52eadfe92791','送鄭君瑞知閩清','劉克莊','宋','宋诗','song-poetry','','[]','茲邑猶淳古，君行作長官。',48,'全唐诗/poet.song.198000.json','["茲邑猶淳古，君行作長官。", "假令三尺密，終有一分寬。", "栗里歸差易，桐鄉愛極難。", "千峯青繞郭，暇日想凭欄。"]'),
('6d4e2f6b-1182-49ba-92ff-14f26e2bb1d8','貓捕燕','劉克莊','宋','宋诗','song-poetry','','[]','文采如彪膽智非，畫堂巧伺燕雛微。',64,'全唐诗/poet.song.198000.json','["文采如彪膽智非，畫堂巧伺燕雛微。", "梁空賓客來俱訝，巢破雌雄去不歸。", "鶑閉深籠防鷙性，蝶飛高樹遠危機。", "主人寘在花墩上，飽卧徐行自養威。"]'),
('96425843-2b2c-4328-84da-29e794778071','次方寺丞方湖韻','劉克莊','宋','宋诗','song-poetry','','[]','晚來吉語到茅椽，太華詩翁約泛蓮。',64,'全唐诗/poet.song.198000.json','["晚來吉語到茅椽，太華詩翁約泛蓮。", "况有鄒枚同預讌，可能李郭獨如仙。", "帝猶給我還山俸，天不需人買月錢。", "揮手闖門冠蓋客，急歸勿攪甕間眠。"]'),
('a1ee2ecd-17b3-4d39-a6ec-b66f6f223675','鄰家孔雀','劉克莊','宋','宋诗','song-poetry','','[]','初來毛羽錦青葱，今與家雞飲啄同。',64,'全唐诗/poet.song.198000.json','["初來毛羽錦青葱，今與家雞飲啄同。", "童子有時偷剪翅，主人常日少開籠。", "嶠南歲月幽囚裏，隴右山川夢寐中。", "因笑世間真贋錯，繡身翻得上屏風。"]'),
('8013ad00-9f28-4085-8a59-2e6b9904618e','答傅監倉','劉克莊','宋','宋诗','song-poetry','','[]','少豪頗似括談兵，老去方慙理未明。',64,'全唐诗/poet.song.198000.json','["少豪頗似括談兵，老去方慙理未明。", "窗下殘書千遍讀，卷中一字幾回更。", "撚髭人盡嗤吾拙，歃血誰當豫此盟。", "肯啖菜根抄脫粟，許君十載共經營。"]'),
('1832d15a-2248-47ef-8765-e1a5a35f8134','蟾蜍硯滴','劉克莊','宋','宋诗','song-poetry','','[]','鑄出爬沙狀，兒童競撫摩。',48,'全唐诗/poet.song.198000.json','["鑄出爬沙狀，兒童競撫摩。", "背如千歲者，腹柰一輪何。", "器較瓶罌小，功於几硯多。", "所盛涓滴水，後世頼餘波。"]'),
('80b49f86-114d-4adf-a9fe-99551bd94149','讀崇寧後長編二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','自入崇寧政已荒，由來治忽繫毫芒。',64,'全唐诗/poet.song.198000.json','["自入崇寧政已荒，由來治忽繫毫芒。", "初爲御筆行中旨，漸取兵權付左璫。", "玉带解來攽貴倖，珠袍脫下賜降羌。", "諸公日侍鈞天讌，不道流人死瘴鄉。"]'),
('8b0cca6e-47ed-44af-b01f-8a237434db52','讀崇寧後長編二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','陳迹分明斷簡中，纔看卷首可占終。',64,'全唐诗/poet.song.198000.json','["陳迹分明斷簡中，纔看卷首可占終。", "兵來尚恐妨恭謝，事去徒知悔夾攻。", "丞相自言芝産第，太師頻奏鶴翔空。", "如何直到宣和季，始憶元城與了翁。"]'),
('035e0872-6385-4967-ac85-ef094d5281e1','午窗','劉克莊','宋','宋诗','song-poetry','','[]','恩賦支離粟一囊，午窗卧看世人忙。',32,'全唐诗/poet.song.198000.json','["恩賦支離粟一囊，午窗卧看世人忙。", "東家學究窮於我，六月褒衣上講堂。"]'),
('bd23505b-3031-4f20-87f0-e7268614a124','書感','劉克莊','宋','宋诗','song-poetry','','[]','仲尼已沒世無師，新學專門各自私。',64,'全唐诗/poet.song.198000.json','["仲尼已沒世無師，新學專門各自私。", "死守不爲它說勝，祕藏似恐外人窺。", "欲招程子看通典，兼起歐公講繫辭。", "浩歎邇來耆舊盡，緒言分付與羣兒。"]'),
('e94e20a6-5696-4994-bfb8-20e005859645','答客','劉克莊','宋','宋诗','song-poetry','','[]','誰謂貧難忍，三年閉戶居。',48,'全唐诗/poet.song.198000.json','["誰謂貧難忍，三年閉戶居。", "老兵能合藥，小僕會抄書。", "白髮羞彈鋏，青山去荷鉏。", "既於吟得趣，功業合乘除。"]'),
('eae964e6-69cb-4b2e-87f4-b6bef9d60bd8','邛杖','劉克莊','宋','宋诗','song-poetry','','[]','珍重邛山鶴膝枝，十年南北慣携持。',64,'全唐诗/poet.song.198000.json','["珍重邛山鶴膝枝，十年南北慣携持。", "扶登石壁寧嫌峻，拄過溪橋肯避危。", "昔涉畏途麾不去，今行平地棄如遺。", "主人尚要防衰老，會有重拈入手時。"]'),
('a4a7ac0d-99c4-45c9-ba41-487508ee648d','寄泉僧真濟','劉克莊','宋','宋诗','song-poetry','','[]','師邃於醫者，聞諸諫議然。',48,'全唐诗/poet.song.198000.json','["師邃於醫者，聞諸諫議然。", "若非禪性悟，必有脈書傳。", "藥貴逢人施，方靈尅日痊。", "西風瓶錫冷，儻肯訪沉綿。"]'),
('e54ed533-78f5-48aa-9a64-b87c41c56388','羊毫筆','劉克莊','宋','宋诗','song-poetry','','[]','拔到髯生族，多因兔穎稀。',48,'全唐诗/poet.song.198000.json','["拔到髯生族，多因兔穎稀。", "只宜茅舍用，難向玉堂揮。", "弄翰虛名似，吹毛本質非。", "兒曹貪價賤，鴉蚓掃如飛。"]'),
('ffb1dfa1-97ed-4835-9910-a7ebda1648b0','空村','劉克莊','宋','宋诗','song-poetry','','[]','棄置在空村，浮名豈復論。',48,'全唐诗/poet.song.198000.json','["棄置在空村，浮名豈復論。", "因思戎服窄，方悟縕袍尊。", "城遠雞司曉，家貧犬守閽。", "常憐劉越石，辛苦戍并門。"]'),
('2c6f42aa-a656-44c1-a2ed-d1046ba0b775','題齋壁','劉克莊','宋','宋诗','song-poetry','','[]','浩如煙海積如山，紙上陳人叫不還。',32,'全唐诗/poet.song.198000.json','["浩如煙海積如山，紙上陳人叫不還。", "白首書生無事業，一生精力費窗間。"]'),
('bfdda2b6-f452-43d0-ac57-c6aa4b53ae59','題繫年錄','劉克莊','宋','宋诗','song-poetry','','[]','炎紹諸賢慮未精，今追遺恨尚難平。',64,'全唐诗/poet.song.198000.json','["炎紹諸賢慮未精，今追遺恨尚難平。", "區區王謝營南渡，草草江徐議北征。", "往日中丞甘結好，暮年都督始知兵。", "可憐白髮宗留守，力請鑾輿幸舊京。"]'),
('d12a6aa9-2f52-40fa-9a34-3b6f1aff97d6','晚出','劉克莊','宋','宋诗','song-poetry','','[]','晚出別村幹，夜深徒步歸。',48,'全唐诗/poet.song.198000.json','["晚出別村幹，夜深徒步歸。", "飯猶懸早稼，衣尚在鄰機。", "關塞秋防急，田園歲入微。", "喟然投耒歎，事事與心違。"]'),
('877136fe-4a06-4578-8853-c95b04e7cb50','伏日','劉克莊','宋','宋诗','song-poetry','','[]','屋山竹樹带疎蟬，浄掃風軒散髮眠。',32,'全唐诗/poet.song.198000.json','["屋山竹樹带疎蟬，浄掃風軒散髮眠。", "老子平生無長物，陶詩一卷枕屏邊。"]'),
('8e95f317-a2db-4391-a171-11a9362bf2e6','自警','劉克莊','宋','宋诗','song-poetry','','[]','筆枯硯燥自傷悲，文體全關氣盛衰。',64,'全唐诗/poet.song.198000.json','["筆枯硯燥自傷悲，文體全關氣盛衰。", "倚馬縱難揮萬字，騎馿尚足課千詩。", "奉盤誰可推盟主，撼樹人方謗老師。", "疑有更深於此者，入山十載試精思。"]'),
('42e6fa61-fbed-40d8-8938-eaeae3009f93','詠鄰人蘭花','劉克莊','宋','宋诗','song-poetry','','[]','兩盆去歲共移來，一置雕闌一委苔。',64,'全唐诗/poet.song.198000.json','["兩盆去歲共移來，一置雕闌一委苔。", "我拙事持令葉瘦，君能調護遣花開。", "隸人挑蠹巡千匝，稚子澆泉走幾迴。", "亦欲效顰耘小圃，地荒終恐費栽培。"]'),
('c8d0597a-5d54-450d-90dd-5db424693125','夏夜','劉克莊','宋','宋诗','song-poetry','','[]','熱極不可度，起行林影中。',48,'全唐诗/poet.song.198000.json','["熱極不可度，起行林影中。", "開窗需過月，移簟就來風。", "豪鼠喧深夜，高蟬響半空。", "永言時物變，露已濕莎叢。"]'),
('7151fd67-5985-4b02-bd6a-74de25dbfebc','書田舍所見','劉克莊','宋','宋诗','song-poetry','','[]','漠漠晴埃起遠疇，占相雲日幾家愁。',64,'全唐诗/poet.song.198000.json','["漠漠晴埃起遠疇，占相雲日幾家愁。", "細民方慮填中壑，巨室何心堰上流。", "斬木由來基小釁，澆瓜誰爲解私仇。", "寧知送老茅簷下，猶抱書生畎畝憂。"]'),
('5863b83d-d211-49f2-a868-1dacf33c6cdb','郊坰','劉克莊','宋','宋诗','song-poetry','','[]','所住在郊坰，田園事遍經。',48,'全唐诗/poet.song.198000.json','["所住在郊坰，田園事遍經。", "淺溝晴後塞，高壠雨餘青。", "屋潤鄰翁富，祠新社鬼靈。", "南州無酒禁，十戶九旗亭。"]'),
('c194066f-94bb-4167-aecf-dcf7d3eb21ac','客過','劉克莊','宋','宋诗','song-poetry','','[]','客過柴門歎寂寥，旋挑野菜拾風樵。',64,'全唐诗/poet.song.198000.json','["客過柴門歎寂寥，旋挑野菜拾風樵。", "無錢輟贈開衣笈，有病來求探藥瓢。", "偶憇荒郊思種樹，每逢斷澗欲營橋。", "書生一念終迂闊，猶閔蒼黔與肖翹。"]'),
('83846052-069c-4e08-a350-425212fe3b96','孟浩然騎馿圖','劉克莊','宋','宋诗','song-poetry','','[]','壞墨殘縑閲幾春，灞橋風味尚如真。',64,'全唐诗/poet.song.198000.json','["壞墨殘縑閲幾春，灞橋風味尚如真。", "摩挲只可誇同社，裝飾應難奉貴人。", "舊向集中窺一面，今於畫裏識前身。", "世間老手惟工部，曾伏先生句句新。"]'),
('d0b36c59-1187-487f-a533-20a31c19e4ee','有興','劉克莊','宋','宋诗','song-poetry','','[]','有興駕柴車，無心起草廬。',48,'全唐诗/poet.song.198000.json','["有興駕柴車，無心起草廬。", "淺傾家釀酒，細讀手抄書。", "門巷慵耘草，園籬課種蔬。", "雖非黄叔度，未易得親疎。"]'),
('b17a8510-2ae1-4263-8698-f6da4247c763','聞笛二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','少年毬馬逐秋風，笛起連營響裂空。',32,'全唐诗/poet.song.198000.json','["少年毬馬逐秋風，笛起連營響裂空。", "今夕夢回村墅冷，一枝孤奏月明中。"]'),
('1625aeef-a2e4-4930-8a9d-bd4ba34066c0','聞笛二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','初如廢將哭窮邊，又似孤臣訴左遷。',32,'全唐诗/poet.song.198000.json','["初如廢將哭窮邊，又似孤臣訴左遷。", "何必謝公雙淚落，野人聽罷亦凄然。"]'),
('99f1d6e6-7f2b-4dde-a22c-944302f46dc4','健忘一首','劉克莊','宋','宋诗','song-poetry','','[]','昏昏健忘廢專精，默坐空齋忽自驚。',64,'全唐诗/poet.song.198000.json','["昏昏健忘廢專精，默坐空齋忽自驚。", "少作回看如兩手，舊書重讀似前生。", "却疑安世知三篋，不曉睢陽記一城。", "莫怪詩成呼燭寫，曉窗追憶欠分明。"]'),
('d9ea5347-b048-427e-a27e-d6146af84cee','宿莊家二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','初秋風露變，偶出憇莊家。',48,'全唐诗/poet.song.198000.json','["初秋風露變，偶出憇莊家。", "原稼無全穗，陂荷有晚花。", "疎鍾踰澗響，微月轉林斜。", "鄰媼頭如雪，燈前自績麻。"]'),
('89d50daf-6ebd-46ba-9eca-2787d6a0e2ea','宿莊家二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','茅茨迷詰曲，度谷復踰陂。',48,'全唐诗/poet.song.198000.json','["茅茨迷詰曲，度谷復踰陂。", "世上事如許，山中人不知。", "牛羊晴卧野，鵝鶩晚歸池。", "粗識爲農意，秋輸每及時。"]'),
('57f61461-b349-4aba-b8ad-ca0a1f643483','妄想','劉克莊','宋','宋诗','song-poetry','','[]','妄想如冰已盡消，朱顔日向鏡中凋。',64,'全唐诗/poet.song.198000.json','["妄想如冰已盡消，朱顔日向鏡中凋。", "玉關萬里曾投筆，草市三家却負樵。", "弱水古來無路到，小山歲晚有人招。", "吾廬寂寂何須笑，君看閑僧住退寮。"]'),
('1b2ab292-5eb2-41a8-89e5-3919a571913b','白杜迓客一首','劉克莊','宋','宋诗','song-poetry','','[]','貧食官倉不自由，强扶衰病坐荒郵。',32,'全唐诗/poet.song.198000.json','["貧食官倉不自由，强扶衰病坐荒郵。", "送迎不是祠官事，偶見青山急下頭。"]'),
('6f3b80d1-3d0c-4762-b1f4-fa8615e4b3ab','七月九日二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','海激天翻電雹嗔，蒼松十丈劈爲薪。',32,'全唐诗/poet.song.198000.json','["海激天翻電雹嗔，蒼松十丈劈爲薪。", "須臾龍卷它山去，誤殺田頭望雨人。"]'),
('b9763294-8992-4b05-ac7e-6758d53cfeb3','七月九日二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','樵子俄從間路迴，因言溪谷響如雷。',32,'全唐诗/poet.song.198000.json','["樵子俄從間路迴，因言溪谷響如雷。", "分明雨怕城中去，只隔前峯不過來。"]'),
('37cc0416-99ff-492b-a155-be7972e63aac','夢賞心亭','劉克莊','宋','宋诗','song-poetry','','[]','夢與諸賢會賞心，恍然佳日共登臨。',64,'全唐诗/poet.song.198000.json','["夢與諸賢會賞心，恍然佳日共登臨。", "酒邊多說烏衣事，曲裏猶殘玉樹音。", "江水淮山明歷歷，孫陵晉廟冷沉沉。", "曉鍾呼覺俱忘却，獨記千門柳色深。"]'),
('caeb9c51-ce2a-4bf0-86c1-9085419faf97','郊行','劉克莊','宋','宋诗','song-poetry','','[]','一雨餞殘熱，忻然思杖藜。',48,'全唐诗/poet.song.198000.json','["一雨餞殘熱，忻然思杖藜。", "野田沙鸛立，古木廟鴉啼。", "失僕行迷路，逢樵負過溪。", "獨遊吾有趣，何必問栖栖。"]'),
('96bf0a71-0038-4df4-9310-fbda2030b41d','懷友','劉克莊','宋','宋诗','song-poetry','','[]','老鶴孤飛久失羣，天涯懷友寸心勤。',64,'全唐诗/poet.song.198000.json','["老鶴孤飛久失羣，天涯懷友寸心勤。", "狂生似膩寧堪近，佳士如香故可熏。", "無復拏舟乘大雪，有時倚杖送停雲。", "秋來逕草深三尺，誰伴青燈緝舊聞。"]'),
('2e0e67e8-efdf-412c-8736-f2eee3786b2f','牢落','劉克莊','宋','宋诗','song-poetry','','[]','牢落吾何恨，先賢未免窮。',48,'全唐诗/poet.song.198000.json','["牢落吾何恨，先賢未免窮。", "寧爲田舍子，不作國師公。", "螢影穿窗隙，蛩聲出壁中。", "殘書殊有味，讀到角吹終。"]'),
('d2578e27-f7e5-4bcd-8cb9-3895bb9f2fbd','跋方雲臺文藁二十韻','劉克莊','宋','宋诗','song-poetry','','[]','文人何瑣碎，夫子獨雄尊。',240,'全唐诗/poet.song.198000.json','["文人何瑣碎，夫子獨雄尊。", "擊水移南海，追風出大宛。", "黑潭龍怒起，碧宇鶻孤鶱。", "翕曶波濤湧，須臾電雹奔。", "筆鋒山突兀，墨瀋雨傾翻。", "軒豁青天露，淒迷白晝昏。", "至微該草樹，極大括乾坤。", "金鼓條侯壁，旌旗渭上屯。", "聚如羣玉圃，散似建章門。", "覽岱親臨頂，窮河直至源。", "檄書傳絕漠，詩句落中原。", "猛虎堪鬚捋，脩鯨可氣吞。", "寂寥時數語，浩蕩或千言。", "神與經營力，誰窺斧鑿痕。", "流行通象桂，模刻遍湘沅。", "欲揀皆逢寶，將芟不見繁。", "居然開穾奧，詎肯闖籬籓。", "坎井疑天大，溪流笑海渾。", "不妨兒輩撼，姑付後人論。", "拙詠雖卑弱，因公儻並存。"]'),
('a40f8564-7ed8-44da-849b-8e9d69629f62','雲','劉克莊','宋','宋诗','song-poetry','','[]','農家望汝卜年豐，似絮如峯𨺗不同。',64,'全唐诗/poet.song.198000.json','["農家望汝卜年豐，似絮如峯𨺗不同。", "縱有濃陰工閣雨，略無定態喜隨風。", "往來與月爲仇敵，舒卷和天盡蔽蒙。", "安得竦身騰汗漫，叫開閶闔掃長空。"]'),
('e6d94863-cf11-445b-bfd4-c1844bf09736','椶冠','劉克莊','宋','宋诗','song-poetry','','[]','羽士過門賣，新翻樣愈奇。',48,'全唐诗/poet.song.198000.json','["羽士過門賣，新翻樣愈奇。", "堅如龜屋製，精似鹿胎爲。", "邛杖扶相稱，唐衣戴最宜。", "笑他蟬冕客，憂畏白鬚眉。"]'),
('7f7f3a18-d9a2-4aa3-86d6-538e87518dc6','方寺丞招宿瀑上不果','劉克莊','宋','宋诗','song-poetry','','[]','久與瀑泉疎，勞公下檄書。',48,'全唐诗/poet.song.198000.json','["久與瀑泉疎，勞公下檄書。", "極知居陋巷，不似宿精廬。", "奴客辭看犢，鄰人畏借馿。", "何時兒子壯，聊爲舉籃輿。"]'),
('8a174c65-aa94-4c26-9ff3-9a7768495a2b','詩境樓觀月','劉克莊','宋','宋诗','song-poetry','','[]','人世應無第二樓，暮雲飛不到簾鈎。',64,'全唐诗/poet.song.198000.json','["人世應無第二樓，暮雲飛不到簾鈎。", "未開寶鑑青冥裏，先湧冰輪碧海頭。", "白似雪濤翻赤壁，壯如夜日出羅浮。", "酒醒何處吹橫玉，徑欲乘風萬里遊。"]'),
('ecedbc53-f0b6-4928-9c46-355796cee420','野望','劉克莊','宋','宋诗','song-poetry','','[]','稍有西風起，孤筇挾自隨。',48,'全唐诗/poet.song.198000.json','["稍有西風起，孤筇挾自隨。", "名山多著寺，古木必爲祠。", "鳥過投林急，樵歸度嶂遲。", "相尋惟有月，搔首待移時。"]'),
('096cd750-452d-40c0-ac7a-c83cdcaebad8','西淙山觀雨','劉克莊','宋','宋诗','song-poetry','','[]','與客同登萬仞崖，蔽天風雨驀然來。',64,'全唐诗/poet.song.198000.json','["與客同登萬仞崖，蔽天風雨驀然來。", "六丁白晝誅炎魃，百怪蒼淵起蟄雷。", "毒蟒噴時林盡黑，怒龍裂處石中開。", "吾生不及觀河決，得賦斯遊亦壯哉。"]'),
('e2e18aed-4b06-424a-9742-91592d7fe61b','宿山中十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','城中人怪我，清旦買芒鞋。',24,'全唐诗/poet.song.198000.json','["城中人怪我，清旦買芒鞋。", "君若知其趣，還應日日來。"]'),
('2ba1ecbd-ae9b-486f-a851-8a03c62f09c6','宿山中十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','玉轡上沙堤，金鞍戍磧西。',24,'全唐诗/poet.song.198000.json','["玉轡上沙堤，金鞍戍磧西。", "何如寒澗底，落日蹇馿嘶。"]'),
('c8725019-0364-4a43-9fac-a0096e3d4af8','宿山中十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','就泉爲碓屋，纍石作書龕。',24,'全唐诗/poet.song.198000.json','["就泉爲碓屋，纍石作書龕。", "有意耕汾曲，無心起水南。"]'),
('9aa8845b-8fde-4222-9354-a23a8df30c0d','宿山中十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','市脯店猶遠，刈芻人未歸。',24,'全唐诗/poet.song.198000.json','["市脯店猶遠，刈芻人未歸。", "夜深語童子，且掩半邊扉。"]'),
('292848e0-efa0-45e0-9e8c-db6705a97d7e','宿山中十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','路危防陟遠，溪黑阻窮深。',24,'全唐诗/poet.song.198000.json','["路危防陟遠，溪黑阻窮深。", "涼月如高士，頻招未出林。"]'),
('f4f7bd61-6c66-4cda-8cbd-1a5ae2451d38','宿山中十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','巖僧殊好事，絕頂廟龍君。',24,'全唐诗/poet.song.198000.json','["巖僧殊好事，絕頂廟龍君。", "勿笑一泓水，能生六合雲。"]'),
('639ef72e-1d8a-45ed-a8a5-23a77a0b7673','宿山中十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','崖居供給少，不用犬防籬。',24,'全唐诗/poet.song.198000.json','["崖居供給少，不用犬防籬。", "只恐偷兒黠，來窺壁上詩。"]'),
('26e9d602-15eb-4c08-b43e-88b49496100d','宿山中十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','山中無價寶，月色與泉聲。',24,'全唐诗/poet.song.198000.json','["山中無價寶，月色與泉聲。", "莫向貴人說，將爲有力爭。"]'),
('31eb8c69-99c6-438b-9a63-65910fe2fa46','宿山中十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','玉筯篆文古，銀鈎楷法精。',24,'全唐诗/poet.song.198000.json','["玉筯篆文古，銀鈎楷法精。", "得知千載下，時有打碑聲。"]'),
('00c8db83-2b54-4a4d-8014-a0c48d377659','宿山中十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','淒風轉林杪，露坐感衣單。',24,'全唐诗/poet.song.198000.json','["淒風轉林杪，露坐感衣單。", "不道山中冷，翻憂世上寒。"]'),
('8b088ed4-eb9d-4c4f-be9b-0c417158a9d5','七月二十日自瀑上先歸方寺丞遣詩夸雷雨之壯次韻一首','劉克莊','宋','宋诗','song-poetry','','[]','城裏遥看雨出時，想公筆墨發雄奇。',64,'全唐诗/poet.song.198000.json','["城裏遥看雨出時，想公筆墨發雄奇。", "山深龍虎飛騰變，海運鯤鵬瞬息移。", "凜凜前鋒如赴敵，堂堂迴勢似歸師。", "驅還始悟山靈意，怕向蒼崖寫惡詩。"]'),
('70de2268-ea1a-4852-b809-a881146a37a5','秋望二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','暮色蒼然上野臺，廢塘尚有數荷開。',32,'全唐诗/poet.song.198000.json','["暮色蒼然上野臺，廢塘尚有數荷開。", "望中愛殺城南柳，只怕霜風一夜來。"]'),
('c368bd31-9b6e-4df1-9b6d-35d284b9072b','秋望二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','舍南舍北種芙蓉，及到秋來次第紅。',32,'全唐诗/poet.song.198000.json','["舍南舍北種芙蓉，及到秋來次第紅。", "自是詩人才思窘，清風明月有何窮。"]'),
('163d4f08-ae05-4809-91cd-b7275dac352d','村校書','劉克莊','宋','宋诗','song-poetry','','[]','短衣穿結半瓢空，所住茅簷僅蔽風。',64,'全唐诗/poet.song.198000.json','["短衣穿結半瓢空，所住茅簷僅蔽風。", "久誦經書皆默記，試挑史傳亦旁通。", "青燈窗下研孤學，白首山中聚小童。", "却羨安昌師弟子，只談論語至三公。"]'),
('0b6504ca-79cc-4276-ae43-a4003c305f49','聖賢','劉克莊','宋','宋诗','song-poetry','','[]','聖賢自牧極卑謙，後學才高膽力兼。',64,'全唐诗/poet.song.198000.json','["聖賢自牧極卑謙，後學才高膽力兼。", "悔賦不妨排賈誼，謗詩遂至劾陶潜。", "取人最忌規模狹，絕物常因議論嚴。", "君看國風三百首，小夫賤隸採何嫌。"]'),
('5f51778e-4813-45e3-8669-6b7eb7cdc249','懷李敬子','劉克莊','宋','宋诗','song-poetry','','[]','此士今徐孺，柴扉肯妄開。',48,'全唐诗/poet.song.198000.json','["此士今徐孺，柴扉肯妄開。", "空聞羔鴈去，不見鳳麟來。", "廬阜尋僧出，東湖赴講迴。", "何由操杖屨，林下再相陪。"]'),
('5a8ac6a1-ff61-49e6-a056-9e9092bdc905','華嚴知客寮','劉克莊','宋','宋诗','song-poetry','','[]','簷外蒼榕六月秋，小年來此愛深幽。',64,'全唐诗/poet.song.198000.json','["簷外蒼榕六月秋，小年來此愛深幽。", "壞牆螢出如漁火，古壁蜂穿似射侯。", "涉世昏昏忘舊話，入山歷歷記前遊。", "故人埋玉僧歸塔，獨聽疎鐘起暮愁。"]'),
('4d1a3c21-1a07-479d-95cb-5a8ba47ad0ce','聞黄德常除德安倅','劉克莊','宋','宋诗','song-poetry','','[]','幕下相從若弟兄，當年曾悔誤談兵。',64,'全唐诗/poet.song.198000.json','["幕下相從若弟兄，當年曾悔誤談兵。", "足行江北生重趼，髮爲山東白幾莖。", "病擁琴書專一壑，老携檄筆赴孤城。", "暮雲不見關山路，空有天涯故舊情。"]'),
('3cd220ac-d9a0-43e9-99ee-500a34fca0ee','閑居即事','劉克莊','宋','宋诗','song-poetry','','[]','性偶安林藪，元非慕獨清。',48,'全唐诗/poet.song.198000.json','["性偶安林藪，元非慕獨清。", "米從仁祖乞，粟是伯夷耕。", "廢井通鄰汲，深牆隔市聲。", "却因虛澹極，亦自覺身輕。"]'),
('45c6ee8c-dcc3-424c-8e22-cb2af726d73a','自勉','劉克莊','宋','宋诗','song-poetry','','[]','海濱荒淺幼無師，前哲藩籬尚未窺。',64,'全唐诗/poet.song.198000.json','["海濱荒淺幼無師，前哲藩籬尚未窺。", "玄詠易流西晉學，苦吟不脫晚唐詩。", "遠僧庵就勤求記，亡友墳成纍索碑。", "天若假余金石壽，所爲詎肯止於斯。"]'),
('528e1775-bf9e-4c59-97b9-0361dec88952','少日','劉克莊','宋','宋诗','song-poetry','','[]','少日關河要指呼，晚歸田里似囚拘。',64,'全唐诗/poet.song.198000.json','["少日關河要指呼，晚歸田里似囚拘。", "氣衰不敢高聲語，腕弱纔能小楷書。", "座有老兵持共飲，路逢醉尉避前驅。", "子元兄弟何爲者，自是嵇康處世疎。"]'),
('a26a1dda-677f-4d73-b731-95c057508fec','貧病','劉克莊','宋','宋诗','song-poetry','','[]','默默守柴荆，人間事頗更。',48,'全唐诗/poet.song.198000.json','["默默守柴荆，人間事頗更。", "病方知養性，貧始欲謀生。", "尚有狂奴態，元無老婢聲。", "邇來塵慮盡，勿怪小詩清。"]'),
('ab8b2d61-2319-4847-b7c3-5a0d21e183a3','示同志一首','劉克莊','宋','宋诗','song-poetry','','[]','滿身秋月滿襟風，敢歎栖遲一壑中。',64,'全唐诗/poet.song.198000.json','["滿身秋月滿襟風，敢歎栖遲一壑中。", "除目解令丹竈壞，詔書能使草堂空。", "豈無高士招難出，曾有先賢隠不終。", "說與同袍二三子，下山未可太匆匆。"]'),
('8843bbdb-52c1-4fe5-aacc-d8f1cb92e270','和方孚若瀑上種梅五首  其一','劉克莊','宋','宋诗','song-poetry','','[]','仙翁小試春風手，高拂茅簷矮映窗。',64,'全唐诗/poet.song.198000.json','["仙翁小試春風手，高拂茅簷矮映窗。", "選勝多依巖罅種，愛奇或併樹身扛。", "海山大士寒蒙衲，月殿仙姝夜擁幢。", "商略此花宜茗飲，不銷銀燭綵纏缸。"]'),
('c00e7ad0-df75-4276-a8c6-9bb201a623e0','和方孚若瀑上種梅五首  其二','劉克莊','宋','宋诗','song-poetry','','[]','天賜梅花爲受用，繽紛玉雪被層矼。',64,'全唐诗/poet.song.198000.json','["天賜梅花爲受用，繽紛玉雪被層矼。", "素芳林下超羣匹，繁蘂枝頭巧疊雙。", "隴月照時霜剪剪，澗風吹處水淙淙。", "主人筆力迴元化，催發何須杖鼓腔。"]'),
('2cf1034f-0a0b-4fa2-8ab4-656fb09def46','和方孚若瀑上種梅五首  其三','劉克莊','宋','宋诗','song-poetry','','["\u897f\u6e56"]','瀑映梅華何所似，蚌胎蟾彩浴寒江。',64,'全唐诗/poet.song.198000.json','["瀑映梅華何所似，蚌胎蟾彩浴寒江。", "夢回東閣頻牽興，吟到西湖始樹降。", "雪屋戀香開紙帳，月窗憐影掩書釭。", "若將漢晉間人比，不是淵明即老龐。"]'),
('9ac23711-e808-439f-847a-11cae0dc60f5','和方孚若瀑上種梅五首  其四','劉克莊','宋','宋诗','song-poetry','','[]','百匝千迴看不足，管他急雪濺奔瀧。',64,'全唐诗/poet.song.198000.json','["百匝千迴看不足，管他急雪濺奔瀧。", "瑶林錯立明梁苑，寶璐橫陳照楚邦。", "愛殺嚼芳仍嗅蘂，吟狂哆口更疎厖。", "曉來翠羽驚飛去，應爲煙鐘樹杪撞。"]'),
('1210fe72-7a94-4517-a04a-15c9834ad83e','和方孚若瀑上種梅五首  其五','劉克莊','宋','宋诗','song-poetry','','[]','欲賦梅花材藻盡，公分生意到枯樁。',64,'全唐诗/poet.song.198000.json','["欲賦梅花材藻盡，公分生意到枯樁。", "鉅題昔只韓聯孟，妙手今惟羿愈逄。", "守穀尚煩看杏虎，護花難少吠籬尨。", "丹崖翠壁宜揮掃，止要游人筆似杠。"]'),
('668196c8-32f0-495c-b0af-0170f08e5404','再和五首  其一','劉克莊','宋','宋诗','song-poetry','','[]','先生多在山中宿，爲愛橫斜影上窗。',64,'全唐诗/poet.song.198000.json','["先生多在山中宿，爲愛橫斜影上窗。", "茁髮僧從深澗徙，赬肩奴過別峯扛。", "和羹宰相調金鼎，止渴將軍擁碧幢。", "空谷不知如許事，沽來村酒且開缸。"]'),
('2ead88a0-c4c7-439e-b99a-83bd577cfb39','再和五首  其二','劉克莊','宋','宋诗','song-poetry','','[]','厭看花開平地上，故攀絕磴履危矼。',64,'全唐诗/poet.song.198000.json','["厭看花開平地上，故攀絕磴履危矼。", "節方靜女尤專一，韻比高人更少雙。", "堪伴愚公居北谷，宜偕漫叟隠南淙。", "素標尚恐詩輕媟，敢犯人間曲子腔。"]'),
('0931e654-b7f8-457d-ad59-3d108070f7d3','再和五首  其三','劉克莊','宋','宋诗','song-poetry','','[]','手選千株高下種，似行庾嶺泛湘江。',64,'全唐诗/poet.song.198000.json','["手選千株高下種，似行庾嶺泛湘江。", "只銷一朵南枝拆，盡受羣花北面降。", "自愛空山吹縞袂，絕羞華屋照銀釭。", "主林神禁人殘毀，深夜應無斫樹龐。"]'),
('b2a66c36-806e-4699-a581-54d028e4a42d','再和五首  其四','劉克莊','宋','宋诗','song-poetry','','[]','絕巔歲晚無人到，但見山風激嶺瀧。',64,'全唐诗/poet.song.198000.json','["絕巔歲晚無人到，但見山風激嶺瀧。", "高蘤恍如珠照乘，深葩還似寶迷邦。", "巢居公未甘枯槁，鼎實朝方起碩厖。", "詩在簡齋和靖裏，追攀真以寸筳撞。"]'),
('8f298148-1b63-4c6b-ba5f-ff1807199dfc','再和五首  其五','劉克莊','宋','宋诗','song-poetry','','[]','杖屨暇時常檢點，細分枝幹數株樁。',64,'全唐诗/poet.song.198000.json','["杖屨暇時常檢點，細分枝幹數株樁。", "試呼童子調霜弄，絕勝奴兵擂曉逄。", "色映巖松寒引鶴，根連園杞夜聞尨。", "社中作者銛鋒穎，甘樹降旛束短杠。"]'),
('1eba1458-64d0-4c45-adcf-53943350ba54','賦西淙瀑布得斷字','劉克莊','宋','宋诗','song-poetry','','[]','蒼山七百畝，主人新買斷。',144,'全唐诗/poet.song.198000.json','["蒼山七百畝，主人新買斷。", "于時積霧開，素瀑掛青漢。", "泠泠瑟初鏗，璀璀珠乍貫。", "久晴雨瓢翻，忽暖冰柱泮。", "恍如白浪湧，翔舞下鳧鴈。", "又疑黄河决，禜祭沉玉瓚。", "不然蟒出穴，或是虹吸澗。", "客言下有潭，龍伏不可玩。", "攫拏起雲氣，噴薄蘇歲旱。", "平生愛奇心，欲此築飛觀。", "沿流踏淺清，陟巘騰汗漫。", "低頭拜主人，分我華山半。"]'),
('8410855c-590d-44de-adf3-c2a767b97864','送陳寺丞守延平','劉克莊','宋','宋诗','song-poetry','','[]','詔免延英對，輕裝見吏民。',48,'全唐诗/poet.song.198000.json','["詔免延英對，輕裝見吏民。", "極知忙捄旱，豈是急頒春。", "邑爲搜空壞，州因獻羨貧。", "此行休戚繫，未敢賀朱輪。"]'),
('7a312adf-4de9-4267-80fc-38843c9266fc','送丁元暉知南海','劉克莊','宋','宋诗','song-poetry','','[]','不用急符催，先行要看梅。',48,'全唐诗/poet.song.198000.json','["不用急符催，先行要看梅。", "歲時親祭海，休沐必登臺。", "鮑井聊供飲，韓碑待拭苔。", "遥知蠻俗喜，令尹带琴來。"]'),
('b34b105a-473e-4079-b030-c4e8c38fb261','黄檗道中崖居者','劉克莊','宋','宋诗','song-poetry','','[]','種竹成林橘滿園，牛歸童子掩籬門。',32,'全唐诗/poet.song.198000.json','["種竹成林橘滿園，牛歸童子掩籬門。", "主人雖不知名氏，想見孤高可與言。"]'),
('7c57735b-5055-402b-b63f-a08ed6cb8892','橫塘','劉克莊','宋','宋诗','song-poetry','','[]','水松百本映門栽，池上荷花似錦開。',32,'全唐诗/poet.song.198000.json','["水松百本映門栽，池上荷花似錦開。", "記取橫塘風景好，歸程摹入小詩來。"]'),
('1c59f0fa-17b8-4f69-a3c4-755054042f22','蒜溪','劉克莊','宋','宋诗','song-poetry','','[]','日爍千山草樹然，海鄉極目少炊煙。',32,'全唐诗/poet.song.198000.json','["日爍千山草樹然，海鄉極目少炊煙。", "蒜溪一脈涓涓水，只綠庵西數丈田。"]'),
('2d8d7c98-bc82-47e5-9d06-c6462190aa84','哭囊山覺初長老  其一','劉克莊','宋','宋诗','song-poetry','','[]','豈謂茶毗速，龕前一愴情。',48,'全唐诗/poet.song.198000.json','["豈謂茶毗速，龕前一愴情。", "空留尊宿貌，難問小師名。", "骨已迎歸塔，衣多唱入城。", "百年如此過，何異不曾生。"]'),
('b87e44bd-f97b-44e8-b8d9-3bf33a42f5e1','哭囊山覺初長老  其二','劉克莊','宋','宋诗','song-poetry','','[]','雪峯寺裏曾相識，面皺顴高五十餘。',64,'全唐诗/poet.song.198000.json','["雪峯寺裏曾相識，面皺顴高五十餘。", "削髮入山參最久，白頭出世瘦如初。", "覺心不共真身壞，遺偈猶能戰手書。", "何必塔銘并語錄，吾詩自可表幽墟。"]'),
('ea1cc969-7980-4e94-8b41-433cf0d776c2','贈蕭高士','劉克莊','宋','宋诗','song-poetry','','[]','玉笥蕭高士，超然物外姿。',48,'全唐诗/poet.song.198000.json','["玉笥蕭高士，超然物外姿。", "能彈廣陵操，會作豫章詩。", "紫府非無分，丹房未有基。", "西山多隠者，何必遠求師。"]'),
('e21ce946-bfc8-466a-b79e-f6dee17ea3fd','挽李端','劉克莊','宋','宋诗','song-poetry','','[]','要識君操履，全如字畫真。',48,'全唐诗/poet.song.198000.json','["要識君操履，全如字畫真。", "病能妨獻賦，窮不廢修身。", "月旦推先輩，春官失此人。", "如聞埋玉速，里巷共酸辛。"]'),
('f66346fe-13f2-490a-a0fa-c603677b3603','海口三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','暫游不得久婆娑，柰此龍江景物何。',64,'全唐诗/poet.song.198000.json','["暫游不得久婆娑，柰此龍江景物何。", "天勢去隨帆際盡，海聲來傍枕邊多。", "昏窗微見燈明嶼，霽閣遥看日浴波。", "定有後人尋舊迹，已留小篆識山阿。"]'),
('cfa7dd50-f860-4f0e-b14b-78ca8c0a083b','海口三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','島煙常至晏方開，沙際參差辨遠桅。',64,'全唐诗/poet.song.198000.json','["島煙常至晏方開，沙際參差辨遠桅。", "風挾寒聲從樹起，潮分末勢過橋來。", "吏人不禁山排闥，客子思傾海入杯。", "歸憶斯游非冷淡，如嘗橄欖味初迴。"]'),
('84783427-468c-44c9-acf3-0b4e871e4a44','海口三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','人煙窮處屋三間，目斷寒雲接淺山。',64,'全唐诗/poet.song.198000.json','["人煙窮處屋三間，目斷寒雲接淺山。", "石塔有風鈴自語，水亭無稅印常閑。", "沙晴火伏如棋布，浪急漁舟似洗還。", "自古詩從登覽得，莫辭絕境共追攀。"]'),
('ad78ebd5-436d-4b0e-90a4-5e10a045728f','黄檗寺一首','劉克莊','宋','宋诗','song-poetry','','[]','猶記垂髫到此山，重游客鬢已彫殘。',64,'全唐诗/poet.song.198000.json','["猶記垂髫到此山，重游客鬢已彫殘。", "寺經水後增輪奐，僧比年時減鉢單。", "絕壑雲興潭影黑，疎林霜下葉聲乾。", "平生酷嗜朱翁字，細看荒碑倚石欄。"]'),
('ce80ea8e-3ac5-4596-9094-26a3cb9f984e','和西外趙知宗','劉克莊','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','斤妙斲如神，源深汲愈新。',48,'全唐诗/poet.song.198000.json','["斤妙斲如神，源深汲愈新。", "岱宗疑有趾，海若忽無津。", "傳遠須公等，鑽堅盡此身。", "平生師友意，非爲雨中巾。"]'),
('5659b89d-528e-49ce-b6ea-98095e9e44a9','悼秦醫','劉克莊','宋','宋诗','song-poetry','','[]','最曉陰陽證，於身獨不靈。',48,'全唐诗/poet.song.198000.json','["最曉陰陽證，於身獨不靈。", "有妻持舊肆，無子學遺經。", "蟲蝕抄方篋，莎生曬藥庭。", "城中醫絕少，堪惜爾彫零。"]'),
('14313c29-578e-476f-bcb6-1eb8c5edf6a4','十月二十二夜同方寺丞宿瀑庵讀劉賓客集','劉克莊','宋','宋诗','song-poetry','','[]','瀑山木落霜寒夜，共讀吾家夢得詩。',64,'全唐诗/poet.song.198000.json','["瀑山木落霜寒夜，共讀吾家夢得詩。", "坐對遺篇忘漏盡，手遮殘燭怕風吹。", "森嚴似聽元戎令，機警如看國手棋。", "千載愚溪相對壘，未應地下友微之。"]'),
('7ab44a69-1da3-49c6-8858-4fc847903c61','戍婦詞三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','織錦爲書寄鴈飛，功名從古恨無機。',32,'全唐诗/poet.song.198000.json','["織錦爲書寄鴈飛，功名從古恨無機。", "良人白首沙場裏，何日封侯建節歸。"]'),
('5b571845-30bf-4f83-bb3b-de32cd0c0425','戍婦詞三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','昨日人迴問塞垣，陣前多有未招魂。',32,'全唐诗/poet.song.198000.json','["昨日人迴問塞垣，陣前多有未招魂。", "營司不許分明哭，寒月家家照淚痕。"]'),
('1995b1d8-68ec-4fa9-95d9-ea2ba16eb066','戍婦詞三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','九月嚴霜塞下飛，連營回首望寒衣。',32,'全唐诗/poet.song.198000.json','["九月嚴霜塞下飛，連營回首望寒衣。", "將軍縱上移屯奏，無柰公卿半是非。"]'),
('28e6b8dd-4863-4c49-8379-368b9495378e','游水南一首','劉克莊','宋','宋诗','song-poetry','','[]','九馬如飛不用鞭，微塵一道起晴川。',64,'全唐诗/poet.song.198000.json','["九馬如飛不用鞭，微塵一道起晴川。", "有司誤謗爲山賊，好事俄傳是地仙。", "何處名樓風月爽，誰家脩竹主人賢。", "橐詩三百高無價，難向旗亭當酒錢。"]'),
('232b4c60-12f1-4571-99fc-d4de87035f7a','哭陳鑰主簿','劉克莊','宋','宋诗','song-poetry','','[]','不但心孤介，生形亦怪奇。',48,'全唐诗/poet.song.198000.json','["不但心孤介，生形亦怪奇。", "在爲官長駡，沒使邑人思。", "魂遠鄉猶隔，名微世未知。", "空存朋友誼，到此力何施。"]'),
('726753d9-b003-441d-a4d1-9adf6ef8fcfc','傅諫議和予所贈傅監倉詩復用前韻一首','劉克莊','宋','宋诗','song-poetry','','[]','諫草如山不論兵，當年出處最分明。',64,'全唐诗/poet.song.198000.json','["諫草如山不論兵，當年出處最分明。", "中朝安可無耆舊，故事猶應問老更。", "敢與鳳毛評句法，素知牛耳執文盟。", "詩壇亦合先生築，遥望偏師已拔營。"]'),
('4face2d8-09ce-494a-9903-7bd8c2a0da4b','宿別瀑上二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','十里荒荆手共開，屐痕歷歷在青苔。',32,'全唐诗/poet.song.198000.json','["十里荒荆手共開，屐痕歷歷在青苔。", "山中猿鳥愁予去，爭問先生幾日迴。"]'),
('60e31916-ba63-4487-b882-d42ffdf9cb87','宿別瀑上二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','兩日相疎鄙吝生，今當遠別若爲情。',32,'全唐诗/poet.song.198000.json','["兩日相疎鄙吝生，今當遠別若爲情。", "夜窗看到千峰黑，枕上猶貪落澗聲。"]'),
('2c932a42-1954-48fc-8323-e29e68a45fe7','初宿囊山和方雲臺韻一首','劉克莊','宋','宋诗','song-poetry','','[]','客游萬里踐霜冰，旦旦披衣坐待明。',64,'全唐诗/poet.song.198000.json','["客游萬里踐霜冰，旦旦披衣坐待明。", "絫黍功名成未易，跳丸歲月去堪驚。", "即今紙被携尋宿，當日油幢聽報更。", "頼有雲臺公好事，追程來送老門生。"]'),
('1c0a8936-6b06-4890-8ea3-4a08da2aaa1c','白鹿寺','劉克莊','宋','宋诗','song-poetry','','[]','歲晚霜林落葉稠，携家來作鹿門遊。',64,'全唐诗/poet.song.198000.json','["歲晚霜林落葉稠，携家來作鹿門遊。", "偈言恍似前生說，詩稾猶煩侍者收。", "身上征衫拋未得，山中靈藥採無由。", "十年不獨行人老，入定高僧白盡頭。"]'),
('7b7bf7a6-57b5-4e31-ac34-0aeafe116a3d','答婦兄林公遇四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','霜下石橋滑，蛩吟茅店清。',24,'全唐诗/poet.song.198000.json','["霜下石橋滑，蛩吟茅店清。", "夢廻殘月在，錯認是天明。"]'),
('d670c869-aa69-4cdc-8ddf-c10ac75297dd','答婦兄林公遇四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','恨余行李速，愧子酒杯長。',24,'全唐诗/poet.song.198000.json','["恨余行李速，愧子酒杯長。", "日暮于誰屋，天寒陟彼岡。"]'),
('bbb0bb3e-ffaa-406c-ae9b-7736e649495f','答婦兄林公遇四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','自笑如窮鬼，相從不記年。',24,'全唐诗/poet.song.198000.json','["自笑如窮鬼，相從不記年。", "每煩詩餞送，不止辦車船。"]'),
('48c56ea0-3049-43b9-b427-e8609cfef2a2','答婦兄林公遇四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','挹君如玉雪，未易得親疎。',24,'全唐诗/poet.song.198000.json','["挹君如玉雪，未易得親疎。", "何日深山裏，同燈共讀書。"]'),
('e9847a09-7cd2-4227-8e8a-3f76c2976f82','發枕峰','劉克莊','宋','宋诗','song-poetry','','[]','蒼頭奉辟書，嚴裝犯蕭辰。',120,'全唐诗/poet.song.198000.json','["蒼頭奉辟書，嚴裝犯蕭辰。", "豈不謀出處，歲儉水菽貧。", "曛黑投山中，明發趨江濱。", "漁父隠者歟，葉舟方垂緡。", "相逢飄然逝，似笑來往頻。", "白鷗我同盟，青山吾故人。", "即之欲與言，邈若不可親。", "昔迎歸軒喜，今見行橐嗔。", "素願悵未諧，抱慙終此身。", "先賢遠志喻，千載猶如新。"]'),
('bf6eb2fa-011c-44e6-8935-b8e20236e107','嵩溪驛','劉克莊','宋','宋诗','song-poetry','','[]','舟子初辭去，風吹薄酒醒。',48,'全唐诗/poet.song.198000.json','["舟子初辭去，風吹薄酒醒。", "一莖新鬢白，數點晚山青。", "潦倒彈長鋏，荒凉宿短亭。", "鄰雞空喔喔，不似昔年聽。"]'),
('4bd4886f-ec25-4a27-a4ba-64a82e6e458e','環翠閣','劉克莊','宋','宋诗','song-poetry','','[]','大陸題詩小陸和，寶鞍畫戟傳呼過。',32,'全唐诗/poet.song.198000.json','["大陸題詩小陸和，寶鞍畫戟傳呼過。", "兩片頑碑未百年，已有牧兒來打破。"]'),
('fcdfb720-c83a-412b-814c-333c10f1f2b7','崇化麻沙道中','劉克莊','宋','宋诗','song-poetry','','[]','經行愛此人煙好，面俯清溪背負山。',64,'全唐诗/poet.song.198000.json','["經行愛此人煙好，面俯清溪背負山。", "半𦩘何妨呼渡去，小橋不礙負薪還。", "遠聞清磬來林杪，忽有朱欄出竹間。", "深處安知無隠者，卜鄰容我設柴關。"]'),
('f690e642-550b-4214-abc8-865c4ecf0e0b','過劉尚書墓','劉克莊','宋','宋诗','song-poetry','','[]','士林方卜道窮通，一旦騎鯨萬事空。',64,'全唐诗/poet.song.198000.json','["士林方卜道窮通，一旦騎鯨萬事空。", "帷下有人師董相，墓傍無客哭喬公。", "白頭稍得談經力，青簡尤高絕幣功。", "尚記長衣橫麈柄，今看華表立西風。"]'),
('7b522b4c-059a-483a-a21b-ee984179c086','謝墳','劉克莊','宋','宋诗','song-poetry','','[]','一月山行未有梅，曉來戲著小詩催。',32,'全唐诗/poet.song.198000.json','["一月山行未有梅，曉來戲著小詩催。", "謝家墳寺更衣處，初見牆西半樹開。"]'),
('b48b2ceb-dff8-4a34-98da-8614b0b29928','大乾記夢','劉克莊','宋','宋诗','song-poetry','','[]','昔夢游湘水，琴書寄葉舟。',24,'全唐诗/poet.song.198000.json','["昔夢游湘水，琴書寄葉舟。", "安知三十載，真作夢中游。"]'),
('0a016ce7-b94f-4447-8ff6-034405ead8b4','館頭','劉克莊','宋','宋诗','song-poetry','','[]','雨雪蕭蕭驛堠長，不堪流潦入車箱。',32,'全唐诗/poet.song.198000.json','["雨雪蕭蕭驛堠長，不堪流潦入車箱。", "撫州城外黄泥路，即是人間小太行。"]'),
('5cf65185-a12c-4ff9-b1ae-29b73d511652','發臨川','劉克莊','宋','宋诗','song-poetry','','[]','始予丱角來，家君綰銅墨。',240,'全唐诗/poet.song.198000.json','["始予丱角來，家君綰銅墨。", "縣齋多休暇，縣圃足戲劇。", "雖云嗜梨栗，亦頗窺簡冊。", "弟妹俱孩幼，親髮方如漆。", "後予捧檄至，軒蓋候廣陌。", "於時志氣銳，門戶况烜赫。", "郡花照席紅，湖柳拂鞍碧。", "耆老互問訊，酒餼紛狼籍。", "今予挑包過，城郭宛如昔。", "高年凋落盡，滿眼少朋識。", "管子仕瘴烟，屈叟掩泉穸。", "蓽門訪舊師，目闇面黧黑。", "買醪與之酌，往事話歷歷。", "既生異縣感，遂起故鄉憶。", "吾翁墓草深，高堂已斑白。", "貧居滫髓空，遠遊溫凊隔。", "二季官海濱，女子各有適。", "曾不如阿奴，碌碌在母側。", "回思盛壯時，去矣復難得。", "因成臨川吟，吟罷淚橫臆。"]'),
('514be988-6d7d-4dca-965f-5b6761f20f32','曾景建自臨川送予至豐城示詩爲別次韻一首','劉克莊','宋','宋诗','song-poetry','','[]','追程送我劍池邊，亹亹清談晉宋前。',64,'全唐诗/poet.song.198000.json','["追程送我劍池邊，亹亹清談晉宋前。", "豈意白頭趨幕日，廼逢紫氣出關年。", "夜深續炬俱忘寢，地冷吹薪久未然。", "臨別祝君加帽絮，高峯雪後尚童顛。"]'),
('d2c46729-0584-4223-be63-4c9eb206257c','自撫至袁連日雨霰風雪一首','劉克莊','宋','宋诗','song-poetry','','[]','窮臘天地閉，雲氣匝野垂。',120,'全唐诗/poet.song.198000.json','["窮臘天地閉，雲氣匝野垂。", "何况袁撫間，積潦盈路歧。", "寸晷拔寸步，一堠費一時。", "忽跌落深淖，有似鳥著𥻿。", "寒日已西匿，游子方南馳。", "孤店渺煙際，僮馬饑以羸。", "霏霏雪沒骭，憯憯風裂肌。", "古人貴遺體，不肯臨深危。", "兒行風雪中，慈母安得知。", "終當投紱去，重補南陔詩。"]'),
('44f43e02-9831-4c46-9dd5-d933c7eb5504','安仁驛','劉克莊','宋','宋诗','song-poetry','','[]','偶向溪邊洗客塵，數株如玉照青蘋。',32,'全唐诗/poet.song.198000.json','["偶向溪邊洗客塵，數株如玉照青蘋。", "凄風冷雨分宜縣，頼有梅花管領人。"]'),
('98420f0d-14b1-4c91-8b8f-cc56fdcc6b21','萍鄉','劉克莊','宋','宋诗','song-poetry','','[]','聞說萍鄉縣，家家有絹機。',24,'全唐诗/poet.song.198000.json','["聞說萍鄉縣，家家有絹機。", "荒年絲價貴，未敢議寒衣。"]'),
('77bf4e0a-219c-4828-a4d1-e47ef00b6463','牛田鋪大雪','劉克莊','宋','宋诗','song-poetry','','[]','暝色蟠空起，獰飈激地吹。',288,'全唐诗/poet.song.198000.json','["暝色蟠空起，獰飈激地吹。", "漸看雲布濩，稍有霰紛披。", "蔌蔌初飄瓦，輕輕已點墀。", "居人朝未覺，客子夜先知。", "巧似莊嚴就，勻如剪刻爲。", "充庭冰氏喜，縞戶染人疑。", "灑密苔緘遍，擎多樹壓垂。", "高峰迷頂踵，遠渡失津涯。", "窘兔低蹲草，僵禽默墮枝。", "馬難分牝牡，烏不辨雄雌。", "倏忽斜還整，冥濛合又離。", "半埋官路堠，亂打寺廊碑。", "猛勢欺袍絮，寒光照鬢絲。", "店荒敲盡閉，橋滑步尤危。", "破釜羹霜菜，殘爐燎濕萁。", "廢粧憐婦怯，露骭笑兒癡。", "乍起毛皆蝟，深藏手亦龜。", "犬驚鄰吠急，雞噤野鳴遲。", "偏滯南轅路，翻思北戍時。", "旌旗鳴鴈塞，刁斗亂鵝池。", "呵筆堪飛檄，收燈可覆棋。", "暮營蒙虎卧，曉獵臂鷹隨。", "浴鐵成何事，披簑自一奇。", "空山吟忍凍，窮巷齧充饑。"]'),
('5a5caa8d-9bd0-43f7-8c72-438813e3b628','醴陵客店','劉克莊','宋','宋诗','song-poetry','','[]','縣郭依稀隔渡頭，解鞍來倚店家樓。',64,'全唐诗/poet.song.198000.json','["縣郭依稀隔渡頭，解鞍來倚店家樓。", "已攀桂樹吟招隠，因看梅花賦遠遊。", "市上俚音多楚語，橋邊碧色是湘流。", "直南鄉國三千里，目送覊鴻起暮愁。"]'),
('a7d517bc-8a24-4512-beaf-bcdc73e839dd','湘潭道中即事二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','敗絮龍鍾擁病身，十分寒事在湘濱。',32,'全唐诗/poet.song.198000.json','["敗絮龍鍾擁病身，十分寒事在湘濱。", "若非野店黏官曆，不記今朝是立春。"]'),
('ff164e40-6798-47cc-919b-246d89fb0551','湘潭道中即事二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','儺鼓鼕鼕匝廟門，可憐楚俗至今存。',32,'全唐诗/poet.song.198000.json','["儺鼓鼕鼕匝廟門，可憐楚俗至今存。", "屈原章句無人誦，別有山歌侑桂尊。"]'),
('a8f6a32b-7edc-4ff8-a153-a43dd67ab767','謁南嶽','劉克莊','宋','宋诗','song-poetry','','["\u8861\u5c71"]','中原昔分裂，五嶽僅存一。',288,'全唐诗/poet.song.198000.json','["中原昔分裂，五嶽僅存一。", "嗟余生東南，有眼乃未覿。", "清晨犯寒慄，馬上青歷歷。", "怪雲何處來，對面失崷崒。", "午投勝業寺，僧訝余不懌。", "茗餘因獻嘲，君定非韓匹。", "彼來既軒露，君至若封鐍。", "余謂僧無躁，茲可以理詰。", "止僧坐悅亭，霾翳忽冰釋。", "石廩先呈身，岣嶁俄見脊。", "須臾天柱開，最後祝融出。", "高峰七十二，固已得彷彿。", "鄴侯何嘗死，懶殘元非寂。", "恍疑在山中，明當往尋覓。", "咄哉三尺雪，孤此一雙屐。", "駕言款靈瑣，樓堞晃丹赤。", "柏深不見人，畫妙如新筆。", "珠瓏千娉婷，彈棋拊瑶瑟。", "茫茫鬼神事，荒幻難究悉。", "吾師太史公，江淮徧浪迹。", "茲焉又浮湘，汗漫恣遊陟。", "雖然乏毫端，亦頗增目力。", "規模五字體，蟠屈萬丈碧。", "詩成投褚中，何必題廟壁。"]'),
('4f577c70-0846-47c2-a404-025a4e511912','勝業寺','劉克莊','宋','宋诗','song-poetry','','[]','寺創於何代，問僧皆不知。',48,'全唐诗/poet.song.198000.json','["寺創於何代，問僧皆不知。", "槎牙夏后柏，殘缺柳侯碑。", "雪過禪堂冷，冰餘嶽路危。", "上封猶未到，太息負心期。"]'),
('2a626a47-0f40-4872-9302-e8508774541f','發嶽市三首  其一','劉克莊','宋','宋诗','song-poetry','','[]','嶽下無耆老，何從訪舊聞。',24,'全唐诗/poet.song.198000.json','["嶽下無耆老，何從訪舊聞。", "不知紫巖墓，更隔幾重雲。"]'),
('b97285c3-f1b6-40db-8cb0-01f0d2d46849','發嶽市三首  其二','劉克莊','宋','宋诗','song-poetry','','[]','明仲竄蠻煙，欽夫棄盛年。',24,'全唐诗/poet.song.198000.json','["明仲竄蠻煙，欽夫棄盛年。", "空令後死者，有淚滴遺編。"]'),
('b26616fc-6ff6-4317-a42e-b2d054db0f46','發嶽市三首  其三','劉克莊','宋','宋诗','song-poetry','','[]','昔者監香火，今焉裂芰荷。',24,'全唐诗/poet.song.198000.json','["昔者監香火，今焉裂芰荷。", "祝融應冷笑，還肯再來麽。"]'),
('bc72f702-b2b6-4c38-a32e-1e9e04971bf6','湘江一首','劉克莊','宋','宋诗','song-poetry','','[]','屈賈死將千載，劉君來泛湘江。',28,'全唐诗/poet.song.198000.json','["屈賈死將千載，劉君來泛湘江。", "沽酒偶留村店，看山不掩船窗。"]'),
('02dddc78-96f0-43d9-b834-efeaa1314776','煙竹鋪','劉克莊','宋','宋诗','song-poetry','','[]','野迥村疎起暮寒，偶逢廢驛卸征鞍。',64,'全唐诗/poet.song.198000.json','["野迥村疎起暮寒，偶逢廢驛卸征鞍。", "主人家比漁舟小，客子房如鶴柵寬。", "燈與鄰通眠未易，風從壁入避尤難。", "似聞南去加蕭索，一夜披衣坐不安。"]'),
('f6ca4cf5-e3cb-4d36-9efd-c3efa99ac504','衡永道中二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','一舍常分作兩程，雪鞭兩袖少逢晴。',32,'全唐诗/poet.song.198000.json','["一舍常分作兩程，雪鞭兩袖少逢晴。", "平生不識終南逕，來傍湖南堠子行。"]'),
('dd879fcc-be6a-4300-9a13-3165ff671171','衡永道中二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','過了衡陽鴈北迴，鄉書迢遞託誰哉。',32,'全唐诗/poet.song.198000.json','["過了衡陽鴈北迴，鄉書迢遞託誰哉。", "嶽山石鼓皆辭去，惟有湘江作伴來。"]'),
('26305a3c-858b-412e-b5cf-e722945de141','黄羆嶺','劉克莊','宋','宋诗','song-poetry','','[]','黄茅迷遠近，不見一人行。',48,'全唐诗/poet.song.198000.json','["黄茅迷遠近，不見一人行。", "信步未知險，迴頭方可驚。", "路由高頂過，雲在半腰生。", "落日無栖止，飄飄自問程。"]'),
('14ea6bea-8ab2-480d-aa5f-a5355da5006d','祁陽縣','劉克莊','宋','宋诗','song-poetry','','[]','入境少人煙，寒江碧際天。',48,'全唐诗/poet.song.198000.json','["入境少人煙，寒江碧際天。", "小留因買石，久立待呼船。", "笛起漁汀上，鷗飛縣郭前。", "若無州帖至，令尹即神仙。"]'),
('7d34e2df-1077-4e93-8d86-f9a6e9d2dcb9','零陵','劉克莊','宋','宋诗','song-poetry','','["\u548f\u7269\u8bd7", "\u5c71\u6c34", "\u548f\u7269"]','畫圖曾識零陵郡，今日方知畫未如。',64,'全唐诗/poet.song.198000.json','["畫圖曾識零陵郡，今日方知畫未如。", "城郭恰臨瀟水上，山川猶是柳侯餘。", "驛亭幽絕堪垂釣，巖室虛明可讀書。", "欲買冉溪三畝地，手苫茅棟徑移居。"]'),
('8fee9e40-b63d-4e33-99c0-f1436a825e0b','深溪驛','劉克莊','宋','宋诗','song-poetry','','[]','苔滿朱扉半闔開，更無人跡獨徘徊。',32,'全唐诗/poet.song.198000.json','["苔滿朱扉半闔開，更無人跡獨徘徊。", "湘江臨別如相語，早買扁舟出嶺來。"]'),
('86d148bb-669e-46c3-827b-642d7194ba23','全州','劉克莊','宋','宋诗','song-poetry','','[]','寂寞全州路，家家荻竹扉。',48,'全唐诗/poet.song.198000.json','["寂寞全州路，家家荻竹扉。", "異僧留塔在，過客入城稀。", "傳舍臨清泚，官亭占翠微。", "沙頭泊船者，多自嶺南歸。"]'),
('469ca186-11c9-4ebb-979a-af476f9ee534','炎關','劉克莊','宋','宋诗','song-poetry','','[]','關北關南氣候分，雪飛不過古來云。',32,'全唐诗/poet.song.198000.json','["關北關南氣候分，雪飛不過古來云。", "若非曾發看山願，老大何因入瘴雲。"]'),
('0195eae1-48b2-4995-898e-9627b7c7623b','秦城','劉克莊','宋','宋诗','song-poetry','','[]','缺甓殘磚無處尋，當年築此慮尤深。',32,'全唐诗/poet.song.198000.json','["缺甓殘磚無處尋，當年築此慮尤深。", "君王自向沙丘死，何必區區戍桂林。"]'),
('074b900e-144b-4943-a5aa-8181472b08f5','來至桂州葉潜仲以詩相迎次韻一首','劉克莊','宋','宋诗','song-poetry','','[]','柘岡西路別君時，幾見天涯柳弄絲。',64,'全唐诗/poet.song.198000.json','["柘岡西路別君時，幾見天涯柳弄絲。", "橫草壯心空忼慨，覆蕉殘夢懶尋思。", "羞將白髮趨新府，却憶青山領舊祠。", "猶有南來奇特事，馬頭先得故人詩。"]'),
('51898033-7077-4fc3-9b0d-be81e4262be6','游水東諸洞次同游韻二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','桂山前未到，今日是初遊。',48,'全唐诗/poet.song.198000.json','["桂山前未到，今日是初遊。", "招鶴登青巘，呼龍俯碧湫。", "深蹊通秉炬，小竇劣容舟。", "豈敢輕題詠，同官盡柳劉。"]'),
('1dde1c7d-1caf-46ff-952d-609c06c9f0ba','游水東諸洞次同游韻二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','舊聞巖洞勝，欲往自髫年。',48,'全唐诗/poet.song.198000.json','["舊聞巖洞勝，欲往自髫年。", "聳秀過靈隠，幽深似善權。", "遠環州堞外，近獻屋簷邊。", "儻有登臨約，甘爲子執鞭。"]'),
('d0b9066b-1a8c-4cd3-a068-7b9501fc6cbc','春日五首  其一','劉克莊','宋','宋诗','song-poetry','','[]','眼邊桃李過匆匆，鏡裏衰顔豈再紅。',32,'全唐诗/poet.song.198000.json','["眼邊桃李過匆匆，鏡裏衰顔豈再紅。", "久覺胃寒疎建焙，新因血熱戒郫筒。"]'),
('fc1b36c8-dd6e-4de1-ad3c-5df6a77bef43','春日五首  其二','劉克莊','宋','宋诗','song-poetry','','[]','步入西峰不見人，數聲澗鳥自啼春。',32,'全唐诗/poet.song.198000.json','["步入西峰不見人，數聲澗鳥自啼春。", "下山欲與唐碑語，先遣奴兵細拂塵。"]'),
('c9dffa16-f099-4273-a322-0cd1b9958128','春日五首  其三','劉克莊','宋','宋诗','song-poetry','','[]','歸到城門欲發更，馬頭惟有暮鴉迎。',32,'全唐诗/poet.song.198000.json','["歸到城門欲發更，馬頭惟有暮鴉迎。", "小窗了却觀書課，幾首殘詩旋補成。"]'),
('aeb0c4b5-e859-4f4b-b5fc-21a6925eb32c','春日五首  其四','劉克莊','宋','宋诗','song-poetry','','[]','老嬾何心更出嬉，閉門終日讀陶詩。',32,'全唐诗/poet.song.198000.json','["老嬾何心更出嬉，閉門終日讀陶詩。", "湘南二月花如掃，恰似扶疎遶屋時。"]'),
('4712210f-b3fe-4c4b-878f-7c94d5baa339','春日五首  其五','劉克莊','宋','宋诗','song-poetry','','[]','曉風細細雨斜斜，僝僽書生屋角花。',32,'全唐诗/poet.song.198000.json','["曉風細細雨斜斜，僝僽書生屋角花。", "想見水南僧寺裏，一株落盡病山茶。"]'),
('e037a3db-710b-4fa1-9894-0205bd088865','訾家洲二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','來訪唐時事，荒洲暮靄青。',48,'全唐诗/poet.song.198000.json','["來訪唐時事，荒洲暮靄青。", "遍生新草棘，難認舊池亭。", "毀記欺無主，存祠怕有靈。", "今人輕古迹，此地少曾經。"]'),
('782c9602-d881-40c7-ad29-02b3fc0872f3','訾家洲二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','裴柳英靈渺莽中，鶴歸應不記遼東。',64,'全唐诗/poet.song.198000.json','["裴柳英靈渺莽中，鶴歸應不記遼東。", "遺基只有蛬鳴雨，往事全如鳥印空。", "谿水無情流㶁㶁，海山依舊碧叢叢。", "斷碑莫怪千迴讀，今代何人筆力同。"]'),
('1203e124-b254-4387-be8d-4d0dcd954472','舜廟','劉克莊','宋','宋诗','song-poetry','','[]','粵俗安知帝，遺祠亦至今。',48,'全唐诗/poet.song.198000.json','["粵俗安知帝，遺祠亦至今。", "青山人寂寂，朱戶柏森森。", "雨打荒碑缺，苔封古洞深。", "曾聞張侍講，來此想韶音。"]'),
('0541c0e1-83f3-405c-ac2e-d028f566ba67','得家訊一首','劉克莊','宋','宋诗','song-poetry','','[]','不覺離鄉久，南來驛使疎。',48,'全唐诗/poet.song.198000.json','["不覺離鄉久，南來驛使疎。", "羈臣一掬淚，慈母兩行書。", "租稅聞輸畢，田園說歉餘。", "何時真宦達，處處奉潘輿。"]'),
('5a61f117-6d01-4902-9b7f-accc5da052b9','湘南樓','劉克莊','宋','宋诗','song-poetry','','[]','偶陪羣彥賦登樓，一笑聊寬故國愁。',64,'全唐诗/poet.song.198000.json','["偶陪羣彥賦登樓，一笑聊寬故國愁。", "近郭山來晴檻裏，待船人立晚沙頭。", "春天晴雨常多變，晦日文書得小休。", "尚有殘錢沽老酒，落花時節約重遊。"]'),
('2066300b-fdcd-42bd-9fcf-51525e4a61ba','上巳與二客游水月洞分韻得事字','劉克莊','宋','宋诗','song-poetry','','[]','勝踐造物慳，貧交世情棄。',144,'全唐诗/poet.song.198000.json','["勝踐造物慳，貧交世情棄。", "昔戒十客來，旦無一人至。", "惟余暨兩君，鼎足坐水次。", "歡言天氣佳，誰謂風土異。", "高吟雜騷選，序酌逮髫穉。", "滌崖去惡詩，捫石認缺字。", "古來幾禊飲，傳者纔一二。", "蘭亭感慨多，未了生死事。", "杜陵更酸辛，窮眼眩珠翠。", "旨哉茲日遊，超然遺塵累。", "消摇千載後，尚有浴沂意。", "巖扉滑如玉，歲月可鎸識。"]'),
('3b6234a0-e8fc-4079-abb1-8cf0ee98130e','出城二絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','日日銅瓶插數枝，瓶空頗訝折來稀。',32,'全唐诗/poet.song.198000.json','["日日銅瓶插數枝，瓶空頗訝折來稀。", "出城忽見櫻桃熟，始信無花可買歸。"]'),
('5a09926e-a11b-418c-bb05-00d17b4d9ee0','出城二絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','小憇城西賣酒家，綠陰深處有啼鴉。',32,'全唐诗/poet.song.198000.json','["小憇城西賣酒家，綠陰深處有啼鴉。", "主人歎息官來晚，謝了酴醾一架花。"]'),
('1d3d101f-261f-4c6e-8efe-7f1efcd12249','三月十四日陪帥卿出遊一首','劉克莊','宋','宋诗','song-poetry','','[]','未出堯山雲，既出雲徐開。',240,'全唐诗/poet.song.198000.json','["未出堯山雲，既出雲徐開。", "君侯與天通，造化力可回。", "駕言訪巖扉，羣彥森然陪。", "旗鉞映川原，笳吹喧蒿萊。", "掃石坐夷曠，捫葛窺崔嵬。", "訾洲久蕪沒，草樹皆新培。", "范張數君子，遺刻蒼蘚埋。", "方羊不忍去，返照明千崖。", "沙禽就栖宿，綵鷁猶泝洄。", "眷焉宇宙間，此樂何常哉。", "鄴都會應劉，梁園命鄒枚。", "主公富貴人，襟抱尤雄猜。", "當年篇翰存，往往鄰俳諧。", "英英大都督，羔鴈招遺才。", "雲煙生妙筆，冰雪懸靈臺。", "况復是夕霽，素魄海上來。", "一碧九萬里，空洞無纖埃。", "臨風惜飲量，孤負黄金罍。", "座中盡文豪，授簡奚徘徊。", "吾詩固拙速，聊爲石生媒。"]'),
('155e71ea-3abe-4a22-a930-7138c5da156d','武岡葉使君寄詩次韻二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','詞客紛紛載後車，誰能遠寄病相如。',64,'全唐诗/poet.song.198000.json','["詞客紛紛載後車，誰能遠寄病相如。", "雙旌已拜湖南牧，尺素猶題嶺外書。", "詩句騎馿游蜀後，情懷賦鵩吊湘餘。", "似聞闔郡春風暖，便擬移家占籍居。"]'),
('f4bb21ec-fc0b-41a1-bbdb-ee1a30196111','武岡葉使君寄詩次韻二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','北戍逢君歲建寅，豈知今作落南人。',64,'全唐诗/poet.song.198000.json','["北戍逢君歲建寅，豈知今作落南人。", "瘴來客病鄰山鬼，舶去鄉書託海神。", "目送飛鳶偏戀土，夢隨畫隼共行春。", "謝家兄弟如雙璧，交契寧非有宿因。"]'),
('159f88e8-006e-4d41-bde3-61ad36cdb192','移居二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','庭下薔薇樹，花開玉雪毬。',24,'全唐诗/poet.song.198000.json','["庭下薔薇樹，花開玉雪毬。", "主人明日去，相對似含愁。"]'),
('b6bf90fe-cc8d-4b3d-83ed-675026b55981','移居二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','鄰曲無還往，何由有別情。',24,'全唐诗/poet.song.198000.json','["鄰曲無還往，何由有別情。", "惟應小窗月，長記讀書聲。"]'),
('bd80617c-6937-4b90-a5dd-3dd99536a98e','弔錦雞一首呈葉任道','劉克莊','宋','宋诗','song-poetry','','[]','炎州産文雞，毛羽固天稟。',192,'全唐诗/poet.song.198000.json','["炎州産文雞，毛羽固天稟。", "朱丹飾尾距，綵繡錯衿衽。", "主人極珍憐，龠合分俸廩。", "置諸後園中，小奴司啄飲。", "地荒籠柵疎，客見輒危懔。", "點狸出沒精，豪鼠窺伺稔。", "諒垂彼饞涎，或瞯君高枕。", "駭機中夕發，果以斃來諗。", "裂冠首立碎，齧嗉聲已噤。", "酷哉三尺喙，殘此一段錦。", "長嗟命瘞埋，詎忍付烹飪。", "始爲文采累，終欠智慮審。", "老瞞戕孔公，千載憤凜凜。", "黄祖殺處士，麤暴犯流品。", "况茲毒鷙物，尤索防閑甚。", "善視雙翠衣，夜凉勿嗜寢。"]'),
('35a7d84b-8449-432d-a32f-9bcf6921be6d','哭孫行之二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','已了燈窗債，心知舉業非。',48,'全唐诗/poet.song.198000.json','["已了燈窗債，心知舉業非。", "立朝多諫草，取友必深衣。", "虀甕貧時共，書筒貴後稀。", "病身偏惜淚，一爲故人揮。"]'),
('aa4ed9ab-d2cf-4b85-a2cf-5db281e3bf9f','哭孫行之二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','世上高科衆，君尤自貴珍。',48,'全唐诗/poet.song.198000.json','["世上高科衆，君尤自貴珍。", "如何一夕裏，忽盡百年身。", "雙旐齊眉友，孤燈擁髻人。", "傷心惟孟母，頭白送歸閩。"]'),
('d71ecca1-28fa-45d0-b915-040c845c1fd3','即事','劉克莊','宋','宋诗','song-poetry','','[]','嶠南氣候異中州，多病誰令作遠遊。',64,'全唐诗/poet.song.198000.json','["嶠南氣候異中州，多病誰令作遠遊。", "瘴土不因梅亦濕，颶風能變夏爲秋。", "方眠壞絮俄敷簟，已著輕絺又索裘。", "自歎幻身非鐵石，天涯豈得久淹留。"]'),
('6b219522-ae91-4737-8729-2791439e48df','楮樹','劉克莊','宋','宋诗','song-poetry','','[]','楮樹婆娑覆小齋，更無日影午窗開。',32,'全唐诗/poet.song.198000.json','["楮樹婆娑覆小齋，更無日影午窗開。", "一端能敗幽人意，夜夜牆西礙月來。"]'),
('e1c49b7e-8101-4ba3-85e0-2a9bb097321e','象弈一首呈葉潜仲','劉克莊','宋','宋诗','song-poetry','','[]','小藝無難精，上智有未解。',288,'全唐诗/poet.song.198000.json','["小藝無難精，上智有未解。", "君看橘中戲，妙不出局外。", "屹然兩國立，限以大河界。", "連營稟中權，四壁設堅械。", "三十二子者，一一具變態。", "先登如挑敵，分布如備塞。", "盡銳賈吾勇，持重伺彼怠。", "或遲如圍莒，或速如入蔡。", "遠砲勿虛發，冗卒要精汰。", "負非繇寡少，勝豈繫彊大。", "昆陽以象奔，陳濤以車敗。", "匹馬郭令來，一士汲黯在。", "獻俘將策勛，得雋衆稱快。", "我欲築壇場，孰可建旗蓋。", "葉侯天機深，臨陳識向背。", "縱未及國手，其高亦可對。", "狃捷敢饒先，諱輸每索再。", "寧爲握節死，安肯屈膝拜。", "有時橫槊吟，句法尤雄邁。", "愚慮僅一得，君才廼十倍。", "霸圖務并弱，兵志貴攻昧。", "雖然屢剋獲，詎可自侈忲。", "呂蒙能馘羽，衛瓘足縛艾。", "南師未宜輕，夜半防斫寨。"]'),
('9ff0f632-379e-4d80-a07e-f122cfd61c2a','送陶仁父','劉克莊','宋','宋诗','song-poetry','','["\u897f\u6e56"]','自古送行情味惡，君行快似泛仙槎。',64,'全唐诗/poet.song.198000.json','["自古送行情味惡，君行快似泛仙槎。", "新班人少先投卷，下水船輕易到家。", "南浦不堪看草色，西湖尚可及荷花。", "諸公若問栖栖者，爲說吟詩兩鬢華。"]'),
('719a7362-b0c1-4b32-ad45-2d3822fc2248','書壁','劉克莊','宋','宋诗','song-poetry','','[]','綀衣蒲屨小綸巾，四壁清風一榻塵。',32,'全唐诗/poet.song.198000.json','["綀衣蒲屨小綸巾，四壁清風一榻塵。", "誰謂先生貧到骨，百金新聘竹夫人。"]'),
('a87a5d2d-e429-4f4f-be81-913b7c10c8c9','栽竹','劉克莊','宋','宋诗','song-poetry','','[]','借居未定先栽竹，爲愛疎聲與薄陰。',64,'全唐诗/poet.song.198000.json','["借居未定先栽竹，爲愛疎聲與薄陰。", "一日暫無能鄙吝，數竿雖少亦蕭森。", "窗間對了添詩料，郭外移來費俸金。", "自笑明年何處在，虛簷風至且披襟。"]'),
('0fc9065f-a740-413b-a890-d73d5d97b10c','癸水亭觀荷花一首','劉克莊','宋','宋诗','song-poetry','','[]','執熱屏人事，偃卧慵巾裳。',168,'全唐诗/poet.song.198000.json','["執熱屏人事，偃卧慵巾裳。", "過門二三友，失喜跣下床。", "鳴騶出華陌，聯轡遵野塘。", "崇軒俯萬荷，濯濯涵波光。", "都忘瘴海中，疑墮玉井傍。", "遠無膏粉氣，近有冰雪凉。", "製葉可以衣，采菂可以嘗。", "離騷譜靈草，品爾列衆芳。", "似曾識三閭，安肯肖六郎。", "詞人更儇薄，比詠猶妃嬙。", "曷不觀茲華，意色和而莊。", "風吹月露洗，豈若冶與倡。", "衆方慕絕艷，誰能參微香。", "余詩縱枯淡，一掃時世粧。"]'),
('587bfd9d-a3e0-493a-bc7b-4b737d7f2fa8','棲霞洞','劉克莊','宋','宋诗','song-poetry','','[]','往聞耆老言，茲洞深無際。',120,'全唐诗/poet.song.198000.json','["往聞耆老言，茲洞深無際。", "闇中或識路，塵外別有世。", "幾思絕人事，齎糧窮所詣。", "棋終出易迷，炬絕入難繼。", "孤亭渺雲端，於焉小休憇。", "憑高眺城闕，擾擾如聚蚋。", "盡捐滓穢念，遂有飛舉勢。", "山靈媢清遊，雨意來極銳。", "濛濛濕莎草，浥浥凉松桂。", "暝色不可留，悵望崖扉閉。"]'),
('5b60b9cf-58cc-481c-8500-fe7bd2e98413','堯廟','劉克莊','宋','宋诗','song-poetry','','[]','帝與天同大，天存帝亦存。',48,'全唐诗/poet.song.198000.json','["帝與天同大，天存帝亦存。", "桑麻通絕徼，簫鼓出深村。", "水至孤亭合，山居列岫尊。", "尚餘土階意，樵牧踐籬藩。"]'),
('92d7d022-d1a2-46ae-a900-efddbacdd3ec','五月二十七日游諸洞','劉克莊','宋','宋诗','song-poetry','','[]','來南百慮拙，所得惟幽尋。',144,'全唐诗/poet.song.198000.json','["來南百慮拙，所得惟幽尋。", "矧余玉雪友，共此丘壑心。", "江亭俯虛曠，穴室窮邃深。", "是時薄雨收，白靄籠青岑。", "棄筇追野步，却扇開風襟。", "炎方豈必好，差遠鼙鼓音。", "且願海道清，莫問神州沉。", "徘徊惜景短，留滯畏老侵。", "昨遊感鶑哢，今至聞蟬吟。", "常恐官事縶，佳日妨登臨。", "譬如逃學兒，汲汲貪寸陰。", "何因釋膠擾，把臂偕入林。"]'),
('a9f966b0-c69d-46ab-8c8d-b25805ce9e5e','泛西湖','劉克莊','宋','宋诗','song-poetry','','["\u897f\u6e56"]','桂湖亦在西，豈減潁與杭。',168,'全唐诗/poet.song.198000.json','["桂湖亦在西，豈減潁與杭。", "丹橋抗崇榭，淥波浮輕航。", "休沐陪勝餞，軒蓋何煒煌。", "停橈藕華中，一目千紅裳。", "詎知白晝永，但覺朱夏凉。", "古洞半蕪廢，仙人今在亡。", "踞石散醉髮，吸澗澆吟腸。", "延緣繚溪步，詰曲經禪房。", "野鳥啼密竹，高蟬嘒疎楊。", "雖無絲管樂，談論諧宮商。", "諸君敏於詩，援筆如蜚翔。", "顧予乏華藻，山鷄追鸞皇。", "頗能讀古碑，所恨侵夕陽。", "明發復擾擾，前游未可忘。"]'),
('0cb5d860-25d5-4ca4-a9a2-7a4ef894acf4','題許介之詩草','劉克莊','宋','宋诗','song-poetry','','[]','我留鳶跕外，君住鴈迴邊。',48,'全唐诗/poet.song.198000.json','["我留鳶跕外，君住鴈迴邊。", "走僕行千里，敲門授一編。", "真妍非粉黛，至巧謝雕鎸。", "何必周丞相，男兒要自傳。"]'),
('f9fd2389-cfed-41e4-a4af-4fa2b4e4bce7','慈氏閣','劉克莊','宋','宋诗','song-poetry','','[]','閣建五季時，丹碧晃層纍。',120,'全唐诗/poet.song.198000.json','["閣建五季時，丹碧晃層纍。", "吾行半區中，鉅麗莫與比。", "想方營綜時，霸心極雄侈。", "但思窮耳目，寧論竭膏髓。", "一朝陵谷變，飛電掃僣壘。", "湘波日夜流，不洗爭篡耻。", "惟存浮屠居，願力久未毀。", "夕陽吊陳迹，危檻聊徙倚。", "遥憐下界熱，高處凉如水。", "若非逼嚴鑰，坐待鐘聲起。"]'),
('b2052404-3849-44ab-86d8-050e569c89f6','翛然亭','劉克莊','宋','宋诗','song-poetry','','[]','每到闌干畔，徘徊暮始還。',48,'全唐诗/poet.song.198000.json','["每到闌干畔，徘徊暮始還。", "爲憐臨水寺，盡見隔城山。", "牆繚青苔裏，舟藏綠樹間。", "松扉宜步月，只是限重關。"]'),
('bae360de-2046-4d7d-aece-f54414112ea2','辰山','劉克莊','宋','宋诗','song-poetry','','[]','一峯疊三洞，迺似弘景樓。',168,'全唐诗/poet.song.198000.json','["一峯疊三洞，迺似弘景樓。", "下洞初俯入，蘚室寒颼颼。", "中洞忽躍出，有逕通玄幽。", "豁然崖谷判，萬態誰鑴鎪。", "或如植寶幢，或如綴珠旒。", "或如鯤鯨飛，或如龍麟游。", "石橋狀天台，木棧疑蜀州。", "稍憇大士巖，遂經羽人丘。", "力窮至上洞，身載雲氣浮。", "未畢山水緣，勉爲塵世留。", "平生避地心，茲焉宜菟裘。", "長斧樵青壁，短簑耘綠疇。", "獨恨汲路遠，溪澗皆背流。", "會當逢異人，卓錫成靈湫。"]'),
('98082513-9e3c-4240-9842-aa8e1566fab4','千山觀','劉克莊','宋','宋诗','song-poetry','','[]','西巘林巒擅一城，渺然飛觀入青冥。',64,'全唐诗/poet.song.198000.json','["西巘林巒擅一城，渺然飛觀入青冥。", "于湖數字題華棟，陽朔千山獻畫屏。", "境勝小詩難寫盡，天寒薄酒易吹醒。", "獨遊不恨無人語，滿壑松聲可細聽。"]'),
('246ff028-2398-4aca-886f-5e7250905b68','曾公巖','劉克莊','宋','宋诗','song-poetry','','[]','廣室內嵌空，層峰外巍嵬。',120,'全唐诗/poet.song.198000.json','["廣室內嵌空，層峰外巍嵬。", "仰視駭懸石，俯踐愁滑苔。", "古竇風肅肅，陰澗泉洄洄。", "飛梁跨其間，上可陳尊罍。", "愛凉復畏濕，當暑重裘來。", "名巖者誰歟，兄固弟子開。", "憶昔建中初，國論幾一迴。", "惜也祖荆舒，卒爲清議排。", "至今出牧地，姓字留蒼崖。", "躊躇增歎慨，日入禽聲哀。"]'),
('3a42ec5a-a9f7-48e9-855e-a21a152be318','郊行','劉克莊','宋','宋诗','song-poetry','','[]','薄有西風意，郊行得自娛。',48,'全唐诗/poet.song.198000.json','["薄有西風意，郊行得自娛。", "山晴全體出，樹老半身枯。", "林轉亭方見，江侵路欲無。", "何妨橋纜斷，小𦩘故堪呼。"]'),
('67c12fd9-22b8-45a6-b749-a7579b0eb98f','秋日會遠華館呈胡仲威','劉克莊','宋','宋诗','song-poetry','','[]','嶺表豈必熱，庚伏頻滂沱。',120,'全唐诗/poet.song.198000.json','["嶺表豈必熱，庚伏頻滂沱。", "薄暮辱招要，盆李參瓶荷。", "君侯如長松，折節交藤蘿。", "奇字識夏鼎，古音彈雲和。", "今日素商至，高屋凉意多。", "夜清群籟息，已有蛩鳴莎。", "人生不飲酒，賢愚同銷磨。", "拍手問湘纍，獨醒欲如何。", "謬承青眼顧，詎惜蒼顔酡。", "客散我亦歸，耿耿看斜河。"]'),
('52abe228-94a4-4cdf-b730-b45784b7df16','老大','劉克莊','宋','宋诗','song-poetry','','[]','老大重登聘士臺，客懷牢落可曾開。',64,'全唐诗/poet.song.198000.json','["老大重登聘士臺，客懷牢落可曾開。", "臨流往往看鳶墮，入署時時見馬來。", "有約青山何日去，無根白髮是誰栽。", "自嫌不带功名骨，只合眠莎與坐苔。"]'),
('7e2d9934-7fa6-46cf-9f6e-c894c4e6ccd7','伏波巖','劉克莊','宋','宋诗','song-poetry','','[]','懸壁萬仞餘，江流繞其趾。',120,'全唐诗/poet.song.198000.json','["懸壁萬仞餘，江流繞其趾。", "仰視不見天，森秀拔地起。", "中洞既深豁，旁竇皆奇詭。", "惜哉題識多，蒼玉半鑱毀。", "安得巨靈鑿，永削崖谷恥。", "緬懷兩伏波，往事可追紀。", "銅柱戍浪泊，樓船下湟水。", "時異非一朝，地去亦萬里。", "山頭博德廟，今爲文淵矣。", "謂予詩弗信，君請訂諸史。"]'),
('9fbe4e54-1f6c-4678-b6a0-aea51d79c79d','詰貓','劉克莊','宋','宋诗','song-poetry','','[]','古人養客乏車魚，今汝何功客不如。',32,'全唐诗/poet.song.198000.json','["古人養客乏車魚，今汝何功客不如。", "飯有溪鱗眠有毯，忍教鼠齧案頭書。"]'),
('9693ad26-1b4f-40a0-9c1f-f4e135a54e74','八桂堂呈葉潜仲','劉克莊','宋','宋诗','song-poetry','','[]','之子初度日，畏客如避仇。',120,'全唐诗/poet.song.198000.json','["之子初度日，畏客如避仇。", "朱門禁入謁，青山招出遊。", "置醴泉石間，凉意生觥籌。", "風檻絳華馥，冰盆丹實浮。", "起誦眉壽篇，酌君介千秋。", "煌煌丞相孫，少也宜襲侯。", "黑頭去云遠，白髮來何稠。", "君言權位盛，孰若志意修。", "靜觀鐘鼎族，起滅猶輕漚。", "祝君象韓呂，不羨熺與攸。"]'),
('1b5b59d8-8be2-48ab-8edf-d6d8e79c6241','挽聶孺人','劉克莊','宋','宋诗','song-poetry','','[]','已病猶蔬素，西歸不復疑。',48,'全唐诗/poet.song.198000.json','["已病猶蔬素，西歸不復疑。", "飛鳬踰嶺遠，別鶴返鄉遲。", "箴史傳賢女，巾褠付侍姬。", "白頭潘令在，應有悼亡詩。"]'),
('f6dfad89-10ea-4b41-b8b5-fbd6b73fffe0','題胡仲威文藁','劉克莊','宋','宋诗','song-poetry','','[]','熟讀執事文，恍如入寶山。',120,'全唐诗/poet.song.198000.json','["熟讀執事文，恍如入寶山。", "瑰異千萬種，一一無可刪。", "瑶草既俯拾，珠樹亦仰攀。", "美玉不知數，照映穹壤間。", "大者中圭瓚，小者堪佩環。", "居然郊廟器，胡爲委荆菅。", "嗟余頗識寶，對之清涕潸。", "携寘蔀屋內，虹氣驚市闤。", "常恐陽虎輩，竊去亡繇還。", "何當變姓名，袖出函谷關。"]'),
('b1c24e47-e2f1-4246-999a-4a6ab8af2d80','戴秀巖','劉克莊','宋','宋诗','song-poetry','','[]','茲巖視諸峰，厥狀尤崢嶸。',144,'全唐诗/poet.song.198000.json','["茲巖視諸峰，厥狀尤崢嶸。", "舊爲碧蘚封，新有朱棧橫。", "縻腰尚恐墜，束炬劣可行。", "外狹中乃寬，始闇俄忽明。", "仰視神魄悸，俯顧形殻輕。", "遂覽丹爐基，微聞玉鼓聲。", "源深足力盡，路黑雲氣生。", "不辨晝夜分，恍疑世代更。", "嘗聞學神仙，所得由專精。", "豈吾諸名士，羨彼一老兵。", "欣然約同志，嗣此將尋盟。", "安知無白鹿，絕頂來相迎。"]'),
('0cc0d0e1-af98-436d-ab9c-0e94760044e5','寄左次魏二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','多謝齊安牧，交情未闊疎。',48,'全唐诗/poet.song.198000.json','["多謝齊安牧，交情未闊疎。", "方籌江北事，肯寄海南書。", "開幙交鋒處，修城劫火餘。", "別來各添歲，筋力近何如。"]'),
('39a7ffab-77d2-4fe5-9a5a-91e073e3767a','寄左次魏二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','同事征西府，聞君已繡衣。',48,'全唐诗/poet.song.198000.json','["同事征西府，聞君已繡衣。", "小侵今視昔，大捷是耶非。", "酋長輿尸返，偏裨奏凱歸。", "六關天樣險，莫遣賊能飛。"]'),
('19c676e3-e961-4fb1-a768-5e886c3157e0','中秋湘南樓餞張昭州','劉克莊','宋','宋诗','song-poetry','','[]','臺使選良牧，詔下帝曰俞。',132,'全唐诗/poet.song.198000.json','["臺使選良牧，詔下帝曰俞。", "高牙植華艦，餞者來傾郛。", "明月滿麗譙，寒光映尊壺。", "桂人願少留，昭人望疾驅。", "一室可爲政，况迺有國都。", "嶺民日以耗，丁口彊半無。", "洋洋紫雲詔，侯其勒座隅。", "道鄉游息處，暇日披榛蕪。", "鄙拙忝投分，臨風獨躊躇。", "頗念友離索，寧論鬼揶揄。", "何繇扣鈴閣，百榼傾兵厨。"]'),
('bf798bcc-dbb9-4613-9f20-4240b5cda99c','榕溪閣','劉克莊','宋','宋诗','song-poetry','','[]','榕聲竹影一溪風，遷客曾來繫短篷。',32,'全唐诗/poet.song.198000.json','["榕聲竹影一溪風，遷客曾來繫短篷。", "我與竹君俱晚出，兩榕猶及識涪翁。"]'),
('f291875e-255d-4be8-8173-c22454277f90','哭譚戶錄二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','讀過書皆記，非惟善屬文。',48,'全唐诗/poet.song.198000.json','["讀過書皆記，非惟善屬文。", "有名登進士，無命作參軍。", "白髮行秋暑，青衫殮瘴雲。", "可憐膏火下，虛費一生勤。"]'),
('f7d6d5f2-afcc-4d44-913a-17990b9d0f25','哭譚戶錄二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','胸次有千年，囊中乏一錢。',48,'全唐诗/poet.song.198000.json','["胸次有千年，囊中乏一錢。", "客來臨旅殯，官爲雇歸船。", "通德梳新髻，童烏拾舊編。", "傷心鄰巷裏，廢宅鎖寒煙。"]'),
('529d5555-b837-4ddb-9c20-e29d5cf17773','風','劉克莊','宋','宋诗','song-poetry','','[]','風於天地間，惟桂尤其雄。',120,'全唐诗/poet.song.198000.json','["風於天地間，惟桂尤其雄。", "將由巖竅多，或是地形穹。", "不知起何處，但覺來無窮。", "浮埃晦白晝，奇響激半空。", "一怒動旬浹，小亦數日中。", "城堞凜欲壓，况此半畝宮。", "嘗聞古至人，御氣猶輕鴻。", "劉季晚可憐，擊筑悲沛豐。", "我老斷恐怖，眡身等枯蓬。", "飄擲付大塊，奚必分西東。"]'),
('123fa2dd-887a-4fae-ba18-df7e2d540909','觀射','劉克莊','宋','宋诗','song-poetry','','[]','浪箭束如林，傍觀笑不禁。',53,'全唐诗/poet.song.198000.json','["浪箭束如林，傍觀笑不禁。", "蠻平無事久，卒惰可憂深。", "各自分牛{炙火=肉}，何曾貫虱心。", "种侯青澗法，能費幾黄金。"]'),
('f63e801b-3742-4e1a-82f3-969f97ab6c2c','荔支巖','劉克莊','宋','宋诗','song-poetry','','[]','異境閟神奇，一罅通深阻。',144,'全唐诗/poet.song.198000.json','["異境閟神奇，一罅通深阻。", "呀然張蟾吻，光怪腹中貯。", "始來尚覿面，稍進但聆語。", "迴頭失塵世，束縕行里所。", "石房容十客，石柱徑丈許。", "眠獒若將吠，墜果疑可咀。", "平生聞化城，今見玉樓櫓。", "陟高既趫捷，循狹或傴僂。", "忽逢路窮處，淺浪隔洲渚。", "心知仙聖居，欲到無飛羽。", "向非薪燭力，往返何異瞽。", "重游儻未卜，聊向詩中覩。"]'),
('8d15c8ed-c50b-4b83-a4a4-2ec2ad203885','再游栖霞洞','劉克莊','宋','宋诗','song-poetry','','[]','直路幽陰側路明，玉爲牆壁雪爲城。',32,'全唐诗/poet.song.198000.json','["直路幽陰側路明，玉爲牆壁雪爲城。", "殷勤報有詩翁到，萬一仙人肯出迎。"]'),
('8979d7a1-8128-4004-aa5e-067956f9c56c','佛子巖','劉克莊','宋','宋诗','song-poetry','','[]','環郭洞府多，所患在卑濕。',120,'全唐诗/poet.song.198000.json','["環郭洞府多，所患在卑濕。", "斯巖獨虛敞，他境未易及。", "穹如層屋構，廣可百客集。", "開竇送雲出，掃壑延月入。", "穴居倘堪謀，徑欲老樵汲。", "絕顛尤玲瓏，苔磴不計級。", "惜爲僧所涴，飛棟緣嶪岌。", "佞佛墮癡想，明鬼趨陋習。", "遂令登眺者，欲往足若縶。", "何當一燎空，盡見萬仞立。"]'),
('167bf5ee-bd68-4be7-a26d-15cc443a0105','劉仙巖','劉克莊','宋','宋诗','song-poetry','','[]','絕頂來尋鍊藥蹤，老仙端的是吾宗。',32,'全唐诗/poet.song.198000.json','["絕頂來尋鍊藥蹤，老仙端的是吾宗。", "寄聲月白風清夜，定許相期第幾峯。"]'),
('844e5707-54d0-46c4-944d-09185d7b7c99','龍隠洞','劉克莊','宋','宋诗','song-poetry','','[]','先賢評桂山，推爾居第一。',144,'全唐诗/poet.song.198000.json','["先賢評桂山，推爾居第一。", "豁然碧瑶戶，夾以蒼玉壁。", "中有無底淵，黑浪常蕩潏。", "諒當剖判初，倍費造化力。", "雷嗔斧山開，龍怒裂石出。", "至今絕頂上，千丈留尾脊。", "寧論兒女子，壯夫股爲慄。", "我來欲題名，腕弱墨不食。", "摩挲狄李碑，文字尚簡質。", "今人未知貴，後代始寶惜。", "洑流工駭舟，久游覺蕭瑟。", "巖屋寬如家，迴櫂聊愒息。"]'),
('42b7ebab-058a-4f04-a759-89f68f75f39a','哭梁運管','劉克莊','宋','宋诗','song-poetry','','[]','憶共游山猶昨日，奄歸白晝隔存亡。',64,'全唐诗/poet.song.198000.json','["憶共游山猶昨日，奄歸白晝隔存亡。", "宅深外不知何病，醫雜人爭試一方。", "弔客傷心同瀝酒，愛姬收淚各分香。", "淳熙丞相潭潭府，今日門庭冷似霜。"]'),
('13070821-154c-4896-b30f-d1942076a86b','琴潭','劉克莊','宋','宋诗','song-poetry','','[]','山形若覆奩，潭面如拭鏡。',96,'全唐诗/poet.song.198000.json','["山形若覆奩，潭面如拭鏡。", "奇哉几案物，千古棄荒敻。", "了無扳躋勞，坐愜幽野性。", "泉源黑難窮，崖色碧相映。", "闖深畏龍蟄，窺淺見魚泳。", "可憐風水聲，空山誰來聽。", "我欲買茲丘，掃迹逃囂競。", "未言葺茅齋，先可理漁𦩘。"]'),
('f3e36653-2d82-484b-8e4c-38c56724b393','清惠廟','劉克莊','宋','宋诗','song-poetry','','[]','來訪古祠宮，迢迢過水東。',48,'全唐诗/poet.song.198000.json','["來訪古祠宮，迢迢過水東。", "一條溪不斷，數里竹方通。", "巫拜分餘胙，商行禱順風。", "粧樓空百尺，半仆夕陽中。"]'),
('da945fbb-423b-4dd5-87de-c83098cbc136','辰山道人','劉克莊','宋','宋诗','song-poetry','','[]','道人何爲者，寒暑一破衫。',120,'全唐诗/poet.song.198000.json','["道人何爲者，寒暑一破衫。", "髮白具老態，口訥稀冗談。", "我陪小隊來，猿鳥窺層嵐。", "道人方掩戶，燕坐彌陁龕。", "迎客不下山，送客不出庵。", "即之疑槁木，面目寒巉巖。", "贈錢漠然謝，有若投諸潭。", "微言歲計熟，收芋已滿籃。", "斯人未識字，豈必曾遍參。", "所立偶自高，可儆佞與貪。"]'),
('d505e8ae-9f7b-4bc7-b37b-9b4def8ec429','玄山觀','劉克莊','宋','宋诗','song-poetry','','[]','來瞻石像看唐碑，一徑蒼松映碧漪。',32,'全唐诗/poet.song.198000.json','["來瞻石像看唐碑，一徑蒼松映碧漪。", "聞說宋公曾住此，寄聲過客細吟詩。"]'),
('74656615-c71c-40b2-8a33-378fde39acfa','榕溪隠者','劉克莊','宋','宋诗','song-poetry','','[]','榕溪有隠者，幽事在溪曲。',120,'全唐诗/poet.song.198000.json','["榕溪有隠者，幽事在溪曲。", "治地可十畝，方整如弈局。", "始行入荆扉，漸進至茅屋。", "樹之百盆蘭，繚以萬竿竹。", "解衣憇繁陰，擁鼻參微馥。", "主人聞客來，引避若駭鹿。", "却詢守舍兒，云已出賣墨。", "壁間見其像，絛褐巾一幅。", "安知非回仙，寄跡混塵俗。", "矢詩慕高風，君歸儻肯讀。"]'),
('6ef264b4-162e-43e8-a671-896132af1b16','禊亭','劉克莊','宋','宋诗','song-poetry','','[]','年年春草上亭基，父老猶能說左司。',32,'全唐诗/poet.song.198000.json','["年年春草上亭基，父老猶能說左司。", "寂寞當時修禊處，一間老屋兩殘碑。"]'),
('fd897413-249b-405d-9b04-0c8bc5d2aae5','自用臺字韻一首','劉克莊','宋','宋诗','song-poetry','','[]','脫了荷衣事將臺，羈留又見嶺梅開。',64,'全唐诗/poet.song.198000.json','["脫了荷衣事將臺，羈留又見嶺梅開。", "詩因癸水辰山作，訟自雷州電縣來。", "架上書從人借讀，牆邊竹是俸移栽。", "小窗睡起無情味，閑聽饑禽啄砌苔。"]'),
('137d5dba-d1f5-4983-86bf-3162382cc2d7','簪带亭','劉克莊','宋','宋诗','song-poetry','','[]','上到青林杪，凭欄盡桂州。',48,'全唐诗/poet.song.198000.json','["上到青林杪，凭欄盡桂州。", "千峯環野立，一水抱城流。", "沙際分漁𦩘，煙中見寺樓。", "不知垂去客，更得幾迴遊。"]'),
('740f3765-d165-4b22-ae74-5c45554cf832','程公巖','劉克莊','宋','宋诗','song-poetry','','[]','石室外甚狹，中廣如毬場。',96,'全唐诗/poet.song.198000.json','["石室外甚狹，中廣如毬場。", "偉哉鉅麗居，天造無棟梁。", "嚴冬既深燠，盛夏尤虛凉。", "偶至不忍去，杖屨聊方羊。", "人能專此壑，何必政事堂。", "先須置禪龕，次第營丹房。", "煙霞入几席，塵土麾門牆。", "學道縱未得，著書亦可藏。"]'),
('904ec37d-d709-4ac6-9304-9551700734be','哭林晉之判官晋','劉克莊','宋','宋诗','song-poetry','','[]','去歲衝寒赴辟時，感君騎馬遠追隨。',64,'全唐诗/poet.song.198000.json','["去歲衝寒赴辟時，感君騎馬遠追隨。", "一春不得梅花信，萬里空題薤露詩。", "小簡佩壺邀士友，大鐺煮粥活流移。", "平生二事尤堪記，應有名公與撰碑。"]'),
('467a3db8-4c33-4cc2-b54b-abcedf576526','鵲','劉克莊','宋','宋诗','song-poetry','','[]','久不聞烏鵲，朝來噪不休。',24,'全唐诗/poet.song.198000.json','["久不聞烏鵲，朝來噪不休。", "殊鄉無喜事，應爲買歸舟。"]'),
('6f1b56c9-9db5-474a-9214-fbf5fa2d15f3','榕臺二絕  其一','劉克莊','宋','宋诗','song-poetry','','[]','拔地高崖如鐵色，拂天老樹作寒聲。',32,'全唐诗/poet.song.198000.json','["拔地高崖如鐵色，拂天老樹作寒聲。", "他年記宿榕臺夜，便是南歸第一程。"]'),
('a796fae3-ac2a-4a73-80d6-45c58526dc0b','榕臺二絕  其二','劉克莊','宋','宋诗','song-poetry','','[]','囊無金累貧如故，鏡有絲生老柰何。',32,'全唐诗/poet.song.198000.json','["囊無金累貧如故，鏡有絲生老柰何。", "一事尚堪誇北客，來時詩少去時多。"]'),
('c98c3d86-7733-4dcb-b2d5-6b1080d428c7','嚴關新洞','劉克莊','宋','宋诗','song-poetry','','[]','羽客初尋見，因於此葺廬。',48,'全唐诗/poet.song.198000.json','["羽客初尋見，因於此葺廬。", "未能平險峻，先擬架空虛。", "磴路樵相引，山名尉自書。", "看來臨驛道，未必有仙居。"]'),
('6ccd2994-d652-4969-9560-df3a8e3c845c','乳洞','劉克莊','宋','宋诗','song-poetry','','[]','千峰夢裏尚崔嵬，不記青鞋走幾迴。',32,'全唐诗/poet.song.198000.json','["千峰夢裏尚崔嵬，不記青鞋走幾迴。", "天恐錦囊猶欠闕，又添乳洞入詩來。"]'),
('8b1fb6ca-e564-464c-bf90-d932614b5d04','發湘潭驛寄府公','劉克莊','宋','宋诗','song-poetry','','[]','走本山中人，感激趨燕臺。',240,'全唐诗/poet.song.198000.json','["走本山中人，感激趨燕臺。", "謬辱弓旌招，愧乏謀議陪。", "先生如春風，盎然噓陳荄。", "曉入開玉帳，夕話扃鈴齋。", "下榻驚一府，撰杖窮千崖。", "豈曰君畜伋，實惟子視回。", "歲晚謀北轅，凄其難爲懷。", "欲言先菀結，既决猶徘徊。", "是日戒行李，送者皆鄒枚。", "兵厨遺珍餉，祖席羅寶釵。", "下令許卜夜，寧畏街鼓催。", "詰旦枉牙纛，山亭陳金罍。", "都人如堵牆，謂我何榮哉。", "未聞從事去，親致元戎來。", "繾綣談至夜，霜月照露苔。", "長跪抱馬足，離緒焉能裁。", "麗譙落天杪，悵望空倚桅。", "昔人死知己，骨朽名不埋。", "公有管樂姿，愚非溫石才。", "他時倘後凋，安敢忘栽培。"]'),
('2ec536c5-46e6-4ef5-b00b-6572055bffff','鏵觜','劉克莊','宋','宋诗','song-poetry','','[]','世傳靈渠自秦始，南引灕江會湘水。',80,'全唐诗/poet.song.198000.json','["世傳靈渠自秦始，南引灕江會湘水。", "楚山憂赭石畏鞭，鑿崖通塹三百里。", "篙師安知有史祿，割牲沈幣祀瀆鬼。", "我舟閣淺懷若人，要是天下奇男子。", "只今渠廢無人修，嗟乎秦吏未易訾。"]'),
('e6d9c8c8-2b38-4536-b454-6ec5771feeee','書堂山','劉克莊','宋','宋诗','song-poetry','','[]','子厚文章宗，仲塗豈後身。',132,'全唐诗/poet.song.198000.json','["子厚文章宗，仲塗豈後身。", "不肯作崑體，寧來牧湘濱。", "誅茅翠麓顛，日與書卷親。", "剗去五季衰，挽回六籍醇。", "歐尹相繼出，孤唱繇伊人。", "風流喟已遠，尚喜棟宇新。", "千峯高叢叢，一江碧粼粼。", "禽魚暨草樹，纖悉几案陳。", "澗泉既可汲，山木亦可薪。", "熟讀壁間藏，痛掃毫端塵。", "勗哉山中友，勿厭泉石貧。"]'),
('6710a0bf-65ee-429f-8968-c632ca005c4c','湘中口占四首  其一','劉克莊','宋','宋诗','song-poetry','','[]','少年裘馬事清狂，晚看梅花到瘴鄉。',32,'全唐诗/poet.song.198000.json','["少年裘馬事清狂，晚看梅花到瘴鄉。", "一任海風吹面黑，免教人謗作何郎。"]'),
('d2a8eac1-0bca-450d-a5bd-a9ebcc3ebd86','湘中口占四首  其二','劉克莊','宋','宋诗','song-poetry','','[]','船頭吹火盧仝婢，馬後肩書穎士奴。',32,'全唐诗/poet.song.198000.json','["船頭吹火盧仝婢，馬後肩書穎士奴。", "安得世間名畫手，寫予出嶺泛湘圖。"]'),
('98a9f102-8932-4f28-9149-406657c147cc','湘中口占四首  其三','劉克莊','宋','宋诗','song-poetry','','[]','江邊金碧謾層層，戶口稀疎塔廟增。',32,'全唐诗/poet.song.198000.json','["江邊金碧謾層層，戶口稀疎塔廟增。", "楚俗不知黄面老，家家香火事湘僧。"]'),
('7005b80b-8cf3-4e4e-95b0-bdfa38422ea0','湘中口占四首  其四','劉克莊','宋','宋诗','song-poetry','','[]','津吏沙邊立指呼，放船出鎖要州符。',32,'全唐诗/poet.song.198000.json','["津吏沙邊立指呼，放船出鎖要州符。", "書生行李堪抽點，薏苡明珠一例無。"]'),
('009d1dc3-f7e3-444e-9c32-707ec215281b','見方雲臺題壁','劉克莊','宋','宋诗','song-poetry','','[]','寄書迢遞夢參差，每見留題尉所思。',32,'全唐诗/poet.song.198000.json','["寄書迢遞夢參差，每見留題尉所思。", "不論驛亭僧寺裏，有山水處有君詩。"]'),
('ba27c5b1-817b-480c-8d11-982e655dd7fa','土馬村','劉克莊','宋','宋诗','song-poetry','','[]','村墟薪濕米如金，猶記來時臘雪深。',32,'全唐诗/poet.song.198000.json','["村墟薪濕米如金，猶記來時臘雪深。", "曾有小詩題歲月，店荒無壁可追尋。"]'),
('50fb1e5a-796e-40f5-8d57-84dd1947d643','祁陽道中','劉克莊','宋','宋诗','song-poetry','','[]','昨過知岑寂，重來况雪天。',48,'全唐诗/poet.song.198000.json','["昨過知岑寂，重來况雪天。", "人居雞柵裏，路在鳥巢邊。", "草市開還閉，茅山斷復連。", "瀟江清似鏡，悔不問歸船。"]'),
('c1e193b4-be15-42e8-8e78-be65d82b14bc','愚溪二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','草聖木奴安在哉，荒榛無處認池臺。',32,'全唐诗/poet.song.198000.json','["草聖木奴安在哉，荒榛無處認池臺。", "傷心惟有溪頭月，曾識儀曹半面來。"]'),
('d1770bfb-0001-40f6-bf30-95bd533c9448','愚溪二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','青雲失脚謫零陵，十載溪邊意未平。',32,'全唐诗/poet.song.198000.json','["青雲失脚謫零陵，十載溪邊意未平。", "溪不預人家國事，可能一例受愚名。"]'),
('e467e0a1-ba9b-474e-a64f-65ffa647fcba','浯溪二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','上置書堂下釣磯，漫郎陳迹尚依稀。',32,'全唐诗/poet.song.198000.json','["上置書堂下釣磯，漫郎陳迹尚依稀。", "無端一首黄詩在，長與江山起是非。"]'),
('197e8f84-1f85-4f95-8c49-acefa0b2beab','浯溪二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','形容唐事片言中，元子文猶有古風。',32,'全唐诗/poet.song.198000.json','["形容唐事片言中，元子文猶有古風。", "莫管看碑人指點，寫碑人是太師公。"]'),
('1d583476-3177-4f16-9099-6278714f04d7','石鼓','劉克莊','宋','宋诗','song-poetry','','[]','石鼓名天下，州庠畫不如。',48,'全唐诗/poet.song.198000.json','["石鼓名天下，州庠畫不如。", "古祠猶漢舊，石刻半唐餘。", "翠巘供憑几，寒江照讀書。", "恨余非楚産，來借一房居。"]'),
('d179b3f4-7212-4dfb-b3c5-dfab74a13fff','湖南江西道中十首  其一','劉克莊','宋','宋诗','song-poetry','','[]','獨醒公子去沉湘，未識人間有醉鄉。',32,'全唐诗/poet.song.198000.json','["獨醒公子去沉湘，未識人間有醉鄉。", "酒與離騷難捏合，不如痛飲是單方。"]'),
('c728becd-89b6-4df0-b411-0a2a9e8d7785','湖南江西道中十首  其二','劉克莊','宋','宋诗','song-poetry','','[]','賈生廢宅草芊芊，路出長沙一悵然。',32,'全唐诗/poet.song.198000.json','["賈生廢宅草芊芊，路出長沙一悵然。", "今日洛陽歸不得，招魂合在楚江邊。"]'),
('9aad3e5a-6574-46e2-9630-3f2860863195','湖南江西道中十首  其三','劉克莊','宋','宋诗','song-poetry','','[]','少陵阻水詩難繼，子厚遊山記絕工。',32,'全唐诗/poet.song.198000.json','["少陵阻水詩難繼，子厚遊山記絕工。", "斷璧殘圭零落盡，新碑無數滿湘中。"]'),
('4a4c8e3c-0df2-4c67-9cca-a3aaa57cdc8b','湖南江西道中十首  其四','劉克莊','宋','宋诗','song-poetry','','[]','去年冬至投僧寺，今歲陽生宿店家。',32,'全唐诗/poet.song.198000.json','["去年冬至投僧寺，今歲陽生宿店家。", "獨夜無人堪晤語，青燈相對結寒花。"]'),
('e9e65aa7-cdb0-488b-aeca-044994b826d0','湖南江西道中十首  其五','劉克莊','宋','宋诗','song-poetry','','[]','蠻府參軍鬢髮蒼，自調欵乃答漁郎。',32,'全唐诗/poet.song.198000.json','["蠻府參軍鬢髮蒼，自調欵乃答漁郎。", "從今詩律應超脫，新吸瀟湘入肺腸。"]'),
('19e4b5d1-158f-4de6-8e6f-99d222636d48','湖南江西道中十首  其六','劉克莊','宋','宋诗','song-poetry','','[]','丁男放犢草間嬉，少婦看蠶不畫眉。',32,'全唐诗/poet.song.198000.json','["丁男放犢草間嬉，少婦看蠶不畫眉。", "歲暮家家禾絹熟，萍鄉風物似豳詩。"]'),
('dcd98134-2536-4a57-987f-18697c63bdfa','湖南江西道中十首  其七','劉克莊','宋','宋诗','song-poetry','','[]','每嘲介甫行新法，常恨歐公不讀書。',32,'全唐诗/poet.song.198000.json','["每嘲介甫行新法，常恨歐公不讀書。", "浩歎諸劉今已矣，路傍喬木日凋疎。"]'),
('31a6ac0a-bdab-4f5f-85cf-cab033c3f600','湖南江西道中十首  其八','劉克莊','宋','宋诗','song-poetry','','[]','茫茫衰草與雲平，斗氣千年不復明。',32,'全唐诗/poet.song.198000.json','["茫茫衰草與雲平，斗氣千年不復明。", "惟有多情篷上月，相隨客子過豐城。"]'),
('4084e374-6974-4eb1-a476-666e5845cd54','湖南江西道中十首  其九','劉克莊','宋','宋诗','song-poetry','','[]','派裏人人有集開，競師山谷友誠齋。',32,'全唐诗/poet.song.198000.json','["派裏人人有集開，競師山谷友誠齋。", "只饒白下騎馿叟，不敢勾牽入社來。"]'),
('73ff3c15-971a-44d1-95c5-76c6792d5dac','湖南江西道中十首  其一○','劉克莊','宋','宋诗','song-poetry','','[]','上封已失嶽僧期，客問丹霞謝不知。',32,'全唐诗/poet.song.198000.json','["上封已失嶽僧期，客問丹霞謝不知。", "懶到登山臨水處，始驚筋力減來時。"]'),
('5487dce2-c9f5-4723-9e45-48496549ae12','曉雞','劉克莊','宋','宋诗','song-poetry','','[]','絳幘昂然韻節清，不因風雪廢長鳴。',64,'全唐诗/poet.song.198000.json','["絳幘昂然韻節清，不因風雪廢長鳴。", "初聞煙岫猶銜月，久聽山城漸殺更。", "驚起征夫茅店夢，喚回老將玉關情。", "年來無復中宵舞，自笑功名一念輕。"]'),
('7b19bf23-3fdb-489f-a434-797f98b59d5f','哭裘司直','劉克莊','宋','宋诗','song-poetry','','[]','築室西山下，孤標未易親。',48,'全唐诗/poet.song.198000.json','["築室西山下，孤標未易親。", "長閑如野鶴，偶出似祥麟。", "屬者陪髦士，嗟呼瘞玉人。", "北風吹老淚，空滴暮江濱。"]'),
('df997b4e-b25a-43a8-a8b7-0eb14abdbc92','豫章二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','湖光如鏡了無塵，照見先生白髮新。',32,'全唐诗/poet.song.198000.json','["湖光如鏡了無塵，照見先生白髮新。", "歲晚騎馿行萬里，始知孺子是高人。"]'),
('e2676115-5230-42e9-ae40-1a00f40b726b','豫章二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','交遊回首散如煙，重過洪州隔世然。',32,'全唐诗/poet.song.198000.json','["交遊回首散如煙，重過洪州隔世然。", "手種垂楊皆合抱，朱顔安得似當年。"]'),
('0ef9b451-a9e7-4151-afbd-61be613baa4e','還杜子野詩卷','劉克莊','宋','宋诗','song-poetry','','[]','老眼昏花廢課程，小窗久矣斷書聲。',32,'全唐诗/poet.song.198000.json','["老眼昏花廢課程，小窗久矣斷書聲。", "夜來忽得君詩卷，自起挑燈讀到明。"]'),
('0edaa413-d7cf-4889-befe-0ff4e71bc6c5','訪李公晦山居','劉克莊','宋','宋诗','song-poetry','','[]','烏洲在橋北，我僕云路迂。',156,'全唐诗/poet.song.198000.json','["烏洲在橋北，我僕云路迂。", "語僕爾何知，彼有高士廬。", "問樵得處所，林樾尤扶疎。", "脩竹僅萬箇，古梅非一株。", "小畦植蔬果，復有沼可漁。", "下馬式籬藩，攝袂循庭除。", "不聞雞犬聲，茶烟起庖厨。", "伊人道義富，豈比山澤臞。", "蕭然蓬蒿中，尚友泗與洙。", "古來連雲第，翕赫衆競趨。", "漸臺暨郿塢，變滅纔須臾。", "聖門不朽事，廼屬陋巷儒。", "願君長保此，是亦顔之徒。"]'),
('3d48c771-ccf6-451f-8085-05918f008512','道傍梅花','劉克莊','宋','宋诗','song-poetry','','[]','風吹千片點征裘，猶記相逢在嶺頭。',32,'全唐诗/poet.song.198000.json','["風吹千片點征裘，猶記相逢在嶺頭。", "歲晚建州城外見，向人似欲訴離愁。"]'),
('cf51412d-898e-4408-84c7-dc1692437d54','戲書客舍','劉克莊','宋','宋诗','song-poetry','','[]','已去光陰挽不迴，漸驚老態逼人來。',64,'全唐诗/poet.song.198000.json','["已去光陰挽不迴，漸驚老態逼人來。", "决河猶有方堪塞，脫髮應無術可栽。", "圯戍寶藏惟檄草，南游稇載是詩材。", "客愁何物禁當得，聊向旗亭買一杯。"]'),
('250f3d5f-dca5-4b20-878f-544b68bba3aa','懷安道中','劉克莊','宋','宋诗','song-poetry','','[]','閩溪瘴嶺客程賒，曉泊懷安喜近家。',64,'全唐诗/poet.song.198000.json','["閩溪瘴嶺客程賒，曉泊懷安喜近家。", "大屋書旗夸酒米，小舟鳴艣競魚蝦。", "溪移驛已臨高岸，潮退帆多聚淺沙。", "快著征衫鞭瘦馬，要看二十里梅花。"]'),
('b71337f1-d830-4e57-8884-2475cf4853ae','哭澤孺方先生二首  其一','劉克莊','宋','宋诗','song-poetry','','[]','弟子成名衆，先生獨命窮。',48,'全唐诗/poet.song.198000.json','["弟子成名衆，先生獨命窮。", "廣場雙鬢禿，陋巷一瓢空。", "鷄饌爲親設，牛衣與婦同。", "嗟乎猶嗇壽，神理竟難通。"]'),
('9b71729b-86de-4923-b91b-26f32aad1b38','哭澤孺方先生二首  其二','劉克莊','宋','宋诗','song-poetry','','[]','方訝書來少，殊鄉訃忽聞。',48,'全唐诗/poet.song.198000.json','["方訝書來少，殊鄉訃忽聞。", "素幃無祭主，破笥散遺文。", "已閉三間屋，誰封四尺墳。", "舊曾傳業者，南北各離群。"]'),
('aa5f1ca1-cd23-41e5-a804-8364aa870717','真隠寺','劉克莊','宋','宋诗','song-poetry','','[]','出郭斜陽已在山，夜深乘月到江干。',64,'全唐诗/poet.song.198000.json','["出郭斜陽已在山，夜深乘月到江干。", "奴敲小店牢扃戶，僧借虛堂徑掛單。", "駭浪急回因膽薄，逆風小住爲心寬。", "投床一枕瀟湘夢，無柰霜鐘苦喚殘。"]');
